                                ) : (
                                    <>
                                        Continue — Verify Email
                                        <ArrowRight className="w-5 h-5 transition-transform group-hover:translate-x-1" />
                                    </>
                                )}
                            </button>
                        )}

                        <p className="text-center text-sm text-gray-600 mt-4">
