import { NextResponse } from 'next/server';
import { connectDB, UserModel, SuperAdminModel, ClientModel, SystemSettingsModel } from '@/lib/mongodb';
import { validateEmail, validatePassword, validateStrongPassword, validateCsrfOrigin } from '@/lib/validation';
import { verifyOtp } from '@/app/api/signup/send-otp/route';
import bcrypt from 'bcryptjs';

export async function POST(request: Request) {
    try {
        const csrf = validateCsrfOrigin(request);
        if (!csrf.valid) return csrf.response;

        const body = await request.json();
        const { email, otp, newPassword } = body;

        // --- Validate required inputs ---
        if (!email || !otp || !newPassword) {
            return NextResponse.json(
                { error: 'Email, verification code, and new password are required' },
                { status: 400 }
            );
        }

        // --- Validate email format ---
        let validatedEmail: string;
        try {
            validatedEmail = validateEmail(email);
        } catch (e: any) {
            return NextResponse.json({ error: e.message }, { status: 400 });
        }

        // --- Verify OTP ---
        try {
            await verifyOtp(validatedEmail, otp.toString().trim(), 'password-reset');
        } catch (e: any) {
            return NextResponse.json({ error: e.message }, { status: 400 });
        }

        await connectDB();

        // --- Validate new password against system policy ---
        try {
            const sys = await SystemSettingsModel.findOne(
                { key: 'global' },
                { 'security.enforceStrongPasswords': 1 }
            ).lean() as any;
            const enforceStrong = sys?.security?.enforceStrongPasswords ?? true;
            if (enforceStrong) {
                validateStrongPassword(newPassword);
            } else {
                validatePassword(newPassword);
            }
        } catch (e: any) {
            return NextResponse.json({ error: e.message }, { status: 400 });
        }

        // --- Find user and update password ---
        const hashedPassword = await bcrypt.hash(newPassword, 12);

        // Check SuperAdmin first
        const superAdmin = await SuperAdminModel.findOne({ email: validatedEmail }).lean();
        if (superAdmin) {
            await SuperAdminModel.updateOne(
                { email: validatedEmail },
                { $set: { password: hashedPassword } }
            );
            return NextResponse.json({
                success: true,
                message: 'Password reset successful. You can now log in with your new password.',
            });
        }

        // Check User
        const user = await UserModel.findOne({ email: validatedEmail }).lean();
        if (user) {
            if ((user as any).archived) {
                return NextResponse.json(
                    { error: 'This account has been deactivated. Please contact your agency.' },
                    { status: 403 }
                );
            }
            await UserModel.updateOne(
                { email: validatedEmail },
                { $set: { password: hashedPassword } }
            );
            return NextResponse.json({
                success: true,
                message: 'Password reset successful. You can now log in with your new password.',
            });
        }

        // Check Client
        const client = await ClientModel.findOne({ email: validatedEmail }).lean();
        if (client) {
            if ((client as any).archived) {
                return NextResponse.json(
                    { error: 'This account has been deactivated. Please contact your agency.' },
                    { status: 403 }
                );
            }
            await ClientModel.updateOne(
                { email: validatedEmail },
                { $set: { password: hashedPassword } }
            );
            return NextResponse.json({
                success: true,
                message: 'Password reset successful. You can now log in with your new password.',
            });
        }

        // Email not found (shouldn't reach here if OTP was valid, but just in case)
        return NextResponse.json(
            { error: 'No account found with this email address.' },
            { status: 404 }
        );

    } catch (error: any) {
        console.error('Password reset error:', error);
        return NextResponse.json(
            { error: error.message || 'Something went wrong. Please try again.' },
            { status: 500 }
        );
    }
}

import { NextResponse } from 'next/server';
import { connectDB, UserModel, SuperAdminModel, ClientModel, OtpModel, RateLimitModel } from '@/lib/mongodb';
import { validateEmail, validateCsrfOrigin } from '@/lib/validation';
import { sendPasswordResetOtpEmail } from '@/lib/brevo';
import { randomInt } from 'crypto';

const MAX_OTP_REQUESTS = 5;
const OTP_RATE_WINDOW = 60 * 60 * 1000; // 1 hour
const MAX_IP_REQUESTS = 10;

function generateOtp(): string {
    return randomInt(100000, 999999).toString();
}

export async function POST(request: Request) {
    try {
        const csrf = validateCsrfOrigin(request);
        if (!csrf.valid) return csrf.response;

        const body = await request.json();
        const { email } = body;

        if (!email) {
            return NextResponse.json({ error: 'Email is required' }, { status: 400 });
        }

        // Validate email format
        let validatedEmail: string;
        try {
            validatedEmail = validateEmail(email);
        } catch (e: any) {
            return NextResponse.json({ error: e.message }, { status: 400 });
        }

        await connectDB();
        const now = new Date();

        // -- Rate limit by email (MongoDB-backed) --
        const emailRateKey = `pwd-reset-otp:email:${validatedEmail}`;
        const emailRecord = await RateLimitModel.findOne({ key: emailRateKey, expiresAt: { $gt: now } }).lean();
        if (emailRecord) {
            if ((emailRecord as any).count >= MAX_OTP_REQUESTS) {
                return NextResponse.json(
                    { error: 'Too many OTP requests. Please try again later.' },
                    { status: 429 }
                );
            }
            await RateLimitModel.updateOne({ key: emailRateKey }, { $inc: { count: 1 } });
        } else {
            await RateLimitModel.findOneAndUpdate(
                { key: emailRateKey },
                { count: 1, expiresAt: new Date(now.getTime() + OTP_RATE_WINDOW) },
                { upsert: true }
            );
        }

        // -- Rate limit by IP (MongoDB-backed) --
        const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim()
            || request.headers.get('x-real-ip')
            || 'unknown';
        const ipRateKey = `pwd-reset-otp:ip:${ip}`;
        const ipRecord = await RateLimitModel.findOne({ key: ipRateKey, expiresAt: { $gt: now } }).lean();
        if (ipRecord) {
            if ((ipRecord as any).count >= MAX_IP_REQUESTS) {
                return NextResponse.json(
                    { error: 'Too many requests from this device. Please try again later.' },
                    { status: 429 }
                );
            }
            await RateLimitModel.updateOne({ key: ipRateKey }, { $inc: { count: 1 } });
        } else {
            await RateLimitModel.findOneAndUpdate(
                { key: ipRateKey },
                { count: 1, expiresAt: new Date(now.getTime() + OTP_RATE_WINDOW) },
                { upsert: true }
            );
        }

        // -- Check if email exists in any collection --
        const [existingUser, existingSuperAdmin, existingClient] = await Promise.all([
            UserModel.findOne({ email: validatedEmail }).lean(),
            SuperAdminModel.findOne({ email: validatedEmail }).lean(),
            ClientModel.findOne({ email: validatedEmail }).lean(),
        ]);

        if (!existingUser && !existingSuperAdmin && !existingClient) {
            // Return same success-like response to prevent email enumeration
            return NextResponse.json({
                success: true,
                message: 'If an account with this email exists, you will receive a reset code shortly.',
            });
        }

        // Check if account is archived/deactivated
        if ((existingUser && (existingUser as any).archived) || (existingClient && (existingClient as any).archived)) {
            return NextResponse.json({
                success: true,
                message: 'If an account with this email exists, you will receive a reset code shortly.',
            });
        }

        // -- Generate OTP and store in MongoDB with TTL --
        const otp = generateOtp();
        await OtpModel.findOneAndUpdate(
            { email: validatedEmail, purpose: 'password-reset' },
            { otp, attempts: 0, expiresAt: new Date(now.getTime() + 5 * 60 * 1000), purpose: 'password-reset' },
            { upsert: true }
        );

        // -- Send OTP via Brevo --
        const result = await sendPasswordResetOtpEmail(validatedEmail, otp);
        if (!result.success) {
            return NextResponse.json(
                { error: 'Failed to send verification email. Please try again.' },
                { status: 500 }
            );
        }

        return NextResponse.json({
            success: true,
            message: 'If an account with this email exists, you will receive a reset code shortly.',
        });

    } catch (error: any) {
        console.error('Forgot password send OTP error:', error);
        return NextResponse.json(
            { error: 'Something went wrong. Please try again.' },
            { status: 500 }
        );
    }
}

import { NextResponse } from 'next/server';
import { connectDB, AgencyModel, UserModel, SettingsModel, SuperAdminModel, ClientModel, RateLimitModel } from '@/lib/mongodb';
import { AGENCY_PLANS } from '@/lib/types';
import { generateId } from '@/lib/utils-server';
import { validateEmail, validatePassword, validateStrongPassword, sanitizeName, sanitizePhone, validateCsrfOrigin } from '@/lib/validation';
import bcrypt from 'bcryptjs';
import { cookies } from 'next/headers';
import { signToken, verifyToken } from '@/lib/auth-utils';
import { verifyOtp } from './send-otp/route';
import { getPublicSecuritySettings } from '@/lib/actions/super-admin';

// Safe image MIME types — SVG is intentionally excluded (can contain embedded scripts)
const ALLOWED_LOGO_MIME_TYPES = ['image/png', 'image/jpeg', 'image/jpg', 'image/gif', 'image/webp'];

// -- Rate limiting for signup: max 5 accounts per IP per hour --
const MAX_SIGNUPS = 5;
const SIGNUP_WINDOW = 60 * 60 * 1000; // 1 hour

export async function POST(request: Request) {
    try {
        const csrf = validateCsrfOrigin(request);
        if (!csrf.valid) return csrf.response;

        // -- Block signup if user is already authenticated --
        const cookieStore = await cookies();
        const existingToken = cookieStore.get('auth_token')?.value;
        if (existingToken) {
            const existingSession = await verifyToken(existingToken);
            if (existingSession) {
                return NextResponse.json(
                    { error: 'You are already logged in. Please log out first to register a new agency.' },
                    { status: 403 }
                );
            }
        }

        // -- Rate limit by IP (MongoDB-backed) --
        const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim()
            || request.headers.get('x-real-ip')
            || 'unknown';
        await connectDB();
        const now = new Date();
        const rateKey = `signup:ip:${ip}`;
        const ipRecord = await RateLimitModel.findOne({ key: rateKey, expiresAt: { $gt: now } }).lean();
        if (ipRecord) {
            if ((ipRecord as any).count >= MAX_SIGNUPS) {
                return NextResponse.json(
                    { error: 'Too many signup attempts. Please try again later.' },
                    { status: 429 }
                );
            }
            await RateLimitModel.updateOne({ key: rateKey }, { $inc: { count: 1 } });
        } else {
            await RateLimitModel.findOneAndUpdate(
                { key: rateKey },
                { count: 1, expiresAt: new Date(now.getTime() + SIGNUP_WINDOW) },
                { upsert: true }
            );
        }

        const body = await request.json();
        const { agencyName, ownerName, email, password, phone, otp, logo, gender } = body;

        // --- Check if self-registration is allowed ---
        const securitySettings = await getPublicSecuritySettings();
        if (!securitySettings.allowSelfRegistration) {
            return NextResponse.json(
                { error: 'Agency registration is currently disabled. Please contact the platform administrator.' },
                { status: 403 }
            );
        }

        // --- Validate required inputs ---
        if (!agencyName || !ownerName || !email || !password) {
            return NextResponse.json(
                { error: 'Agency name, owner name, email, and password are required' },
                { status: 400 }
            );
        }

        if (!otp) {
            return NextResponse.json(
                { error: 'Email verification code is required' },
                { status: 400 }
            );
        }

        // --- Sanitize & validate ---
        const sanitizedAgencyName = sanitizeName(agencyName, 200);
        if (!sanitizedAgencyName) {
            return NextResponse.json({ error: 'Invalid agency name' }, { status: 400 });
        }

        const sanitizedOwnerName = sanitizeName(ownerName, 200);
        if (!sanitizedOwnerName) {
            return NextResponse.json({ error: 'Invalid owner name' }, { status: 400 });
        }

        const validGenders = ['Male', 'Female', 'Other'];
        const sanitizedGender = validGenders.includes(gender) ? gender : 'Male';

        let validatedEmail: string;
        try {
            validatedEmail = validateEmail(email);
        } catch (e: any) {
            return NextResponse.json({ error: e.message }, { status: 400 });
        }

        try {
            if (securitySettings.enforceStrongPasswords) {
                validateStrongPassword(password);
            } else {
                validatePassword(password);
            }
        } catch (e: any) {
            return NextResponse.json({ error: e.message }, { status: 400 });
        }

        // Sanitize phone
        const sanitizedPhone = phone ? sanitizePhone(phone) : '';

        // Validate logo (if provided, must be a data URI with safe image MIME type)
        let sanitizedLogo = '';
        if (logo && typeof logo === 'string') {
            // Max 2MB base64 (~2.7M chars)
            if (logo.length > 3_000_000) {
                return NextResponse.json({ error: 'Logo file is too large. Max 2MB.' }, { status: 400 });
            }
            // Extract MIME type from data URI and validate against allowlist
            const mimeMatch = logo.match(/^data:(image\/[a-zA-Z+]+);base64,/);
            if (mimeMatch) {
                const mimeType = mimeMatch[1].toLowerCase();
                if (!ALLOWED_LOGO_MIME_TYPES.includes(mimeType)) {
                    return NextResponse.json(
                        { error: 'Unsupported logo format. Please use PNG, JPG, GIF, or WebP.' },
                        { status: 400 }
                    );
                }
                sanitizedLogo = logo;
            } else if (logo.startsWith('data:')) {
                // data: URI but not a valid base64 image — reject
                return NextResponse.json(
                    { error: 'Invalid logo format. Please upload a valid image file.' },
                    { status: 400 }
                );
            }
            // If it doesn't match any data: pattern, sanitizedLogo stays empty (ignored)
        }

        // --- Verify OTP ---
        try {
            await verifyOtp(validatedEmail, otp.toString().trim());
        } catch (e: any) {
            return NextResponse.json({ error: e.message }, { status: 400 });
        }

        // --- Connect to DB ---
        await connectDB();

        // --- Check if email already exists (ALL collections) ---
        const [existingUser, existingSuperAdmin, existingClient] = await Promise.all([
            UserModel.findOne({ email: validatedEmail }).lean(),
            SuperAdminModel.findOne({ email: validatedEmail }).lean(),
            ClientModel.findOne({ email: validatedEmail }).lean(),
        ]);

        if (existingUser || existingSuperAdmin || existingClient) {
            return NextResponse.json(
                { error: 'An account with this email already exists' },
                { status: 409 }
            );
        }

        // --- Generate IDs ---
        const agencyId = generateId();
        const userId = generateId();

        // --- Trial dates ---
        const nowDate = new Date();
        const trialEnd = new Date(nowDate.getTime() + 7 * 24 * 60 * 60 * 1000); // 7 days

        // --- Use Pro plan defaults for trial ---
        const planDefaults = AGENCY_PLANS['pro'];

        // --- Create slug ---
        const slug = sanitizedAgencyName.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
        const existingAgency = await AgencyModel.findOne({ slug });
        const finalSlug = existingAgency ? `${slug}-${agencyId.slice(0, 6)}` : slug;

        // --- Create Agency ---
        // Get default AI config for trial agencies (if configured by super-admin)
        const { getDefaultAiConfigForSignup } = await import('@/lib/actions/super-admin');
        const defaultAiConfig = await getDefaultAiConfigForSignup();

        await AgencyModel.create({
            id: agencyId,
            name: sanitizedAgencyName,
            slug: finalSlug,
            plan: 'pro',
            status: 'trial',
            trialEndsAt: trialEnd.toISOString(),
            limits: planDefaults.limits,
            usage: {
                users: 1,
                projects: 0,
                clients: 0,
                storage: 0,
                monthlyInvoices: 0
            },
            features: planDefaults.features,
            billing: {
                billingEmail: validatedEmail,
                subscriptionStatus: 'trialing'
            },
            settings: {
                systemName: sanitizedAgencyName,
                timezone: 'Asia/Kolkata',
                currency: 'USD',
                dateFormat: 'DD/MM/YYYY',
                allowClientRegistration: false,
                requireEmailVerification: true,
                enableTwoFactor: false,
                emailNotificationsEnabled: true
            },
            // Apply default AI config if configured by super-admin
            ...(defaultAiConfig ? { aiConfig: defaultAiConfig } : {}),
            createdAt: nowDate.toISOString(),
            updatedAt: nowDate.toISOString(),
            createdBy: userId
        });

        // --- Create Admin User ---
        const hashedPassword = await bcrypt.hash(password, 12); // Increased from 10 to 12 rounds

        // Generate unique username from email prefix
        const baseUsername = validatedEmail.split('@')[0].toLowerCase().replace(/[^a-z0-9]/g, '');
        let username = baseUsername;
        let counter = 1;
        while (await UserModel.exists({ username, agencyId }) || await ClientModel.exists({ username, agencyId })) {
            username = `${baseUsername}${counter}`;
            counter++;
        }

        await UserModel.create({
            id: userId,
            agencyId,
            name: sanitizedOwnerName,
            email: validatedEmail,
            password: hashedPassword,
            role: 'admin',
            username,
            contactNumber: sanitizedPhone,
            gender: sanitizedGender,
            jobTitle: 'Agency Owner',
            salary: 0,
            createdAt: nowDate.toISOString()
        });

        // --- Create default Settings (with logo if provided) ---
        await SettingsModel.create({
            agencyId,
            systemName: sanitizedAgencyName,
            logo: sanitizedLogo
        });

        // --- Auto-login: set JWT cookie ---
        const token = await signToken({ userId, role: 'admin', agencyId });

        cookieStore.set('auth_token', token, {
            httpOnly: true,
            secure: process.env.NODE_ENV === 'production',
            sameSite: 'lax',
            path: '/',
            maxAge: 60 * 60 * 24
        });
        // S1 fix: Removed legacy userId/userRole cookies — JWT is the single source of truth
        cookieStore.set('logged_in', '1', {
            httpOnly: false,
            secure: process.env.NODE_ENV === 'production',
            sameSite: 'lax',
            path: '/',
            maxAge: 60 * 60 * 24
        });

        return NextResponse.json({
            success: true,
            redirectTo: '/dashboard',
            agencyId,
            trialEndsAt: trialEnd.toISOString()
        });

    } catch (error: any) {
        console.error('Signup error:', error);
        return NextResponse.json(
            { error: error.message || 'Something went wrong. Please try again.' },
            { status: 500 }
        );
    }
}

import { NextResponse } from 'next/server';
import { connectDB, UserModel, SuperAdminModel, ClientModel, OtpModel, RateLimitModel } from '@/lib/mongodb';
import { validateEmail, validateCsrfOrigin } from '@/lib/validation';
import { sendOtpEmail } from '@/lib/brevo';
import { randomInt } from 'crypto';
import { getPublicSecuritySettings } from '@/lib/actions/super-admin';

const MAX_OTP_REQUESTS = 5;
const OTP_RATE_WINDOW = 60 * 60 * 1000; // 1 hour
const MAX_IP_REQUESTS = 10;

function generateOtp(): string {
    return randomInt(100000, 999999).toString();
}

export async function POST(request: Request) {
    try {
        const csrf = validateCsrfOrigin(request);
        if (!csrf.valid) return csrf.response;

        const body = await request.json();
        const { email } = body;

        if (!email) {
            return NextResponse.json({ error: 'Email is required' }, { status: 400 });
        }

        // Check if self-registration is allowed
        const securitySettings = await getPublicSecuritySettings();
        if (!securitySettings.allowSelfRegistration) {
            return NextResponse.json(
                { error: 'Agency registration is currently disabled. Please contact the platform administrator.' },
                { status: 403 }
            );
        }

        // Validate email format
        let validatedEmail: string;
        try {
            validatedEmail = validateEmail(email);
        } catch (e: any) {
            return NextResponse.json({ error: e.message }, { status: 400 });
        }

        await connectDB();
        const now = new Date();

        // -- Rate limit by email (MongoDB-backed) --
        const emailRateKey = `otp:email:${validatedEmail}`;
        const emailRecord = await RateLimitModel.findOne({ key: emailRateKey, expiresAt: { $gt: now } }).lean();
        if (emailRecord) {
            if ((emailRecord as any).count >= MAX_OTP_REQUESTS) {
                return NextResponse.json(
                    { error: 'Too many OTP requests. Please try again later.' },
                    { status: 429 }
                );
            }
            await RateLimitModel.updateOne({ key: emailRateKey }, { $inc: { count: 1 } });
        } else {
            await RateLimitModel.findOneAndUpdate(
                { key: emailRateKey },
                { count: 1, expiresAt: new Date(now.getTime() + OTP_RATE_WINDOW) },
                { upsert: true }
            );
        }

        // -- Rate limit by IP (MongoDB-backed) --
        const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim()
            || request.headers.get('x-real-ip')
            || 'unknown';
        const ipRateKey = `otp:ip:${ip}`;
        const ipRecord = await RateLimitModel.findOne({ key: ipRateKey, expiresAt: { $gt: now } }).lean();
        if (ipRecord) {
            if ((ipRecord as any).count >= MAX_IP_REQUESTS) {
                return NextResponse.json(
                    { error: 'Too many requests from this device. Please try again later.' },
                    { status: 429 }
                );
            }
            await RateLimitModel.updateOne({ key: ipRateKey }, { $inc: { count: 1 } });
        } else {
            await RateLimitModel.findOneAndUpdate(
                { key: ipRateKey },
                { count: 1, expiresAt: new Date(now.getTime() + OTP_RATE_WINDOW) },
                { upsert: true }
            );
        }

        // -- Check if email already exists (across all collections) --
        const [existingUser, existingSuperAdmin, existingClient] = await Promise.all([
            UserModel.findOne({ email: validatedEmail }).lean(),
            SuperAdminModel.findOne({ email: validatedEmail }).lean(),
            ClientModel.findOne({ email: validatedEmail }).lean(),
        ]);

        if (existingUser || existingSuperAdmin || existingClient) {
            // Return same success-like response to prevent email enumeration
            return NextResponse.json(
                { message: 'If this email is not already registered, you will receive an OTP shortly.' },
                { status: 200 }
            );
        }

        // -- Generate OTP and store in MongoDB with TTL --
        const otp = generateOtp();
        await OtpModel.findOneAndUpdate(
            { email: validatedEmail, purpose: 'signup' },
            { otp, attempts: 0, expiresAt: new Date(now.getTime() + 5 * 60 * 1000), purpose: 'signup' },
            { upsert: true }
        );

        // -- Send OTP via Brevo --
        const result = await sendOtpEmail(validatedEmail, otp);
        if (!result.success) {
            return NextResponse.json(
                { error: 'Failed to send verification email. Please try again.' },
                { status: 500 }
            );
        }

        return NextResponse.json({
            success: true,
            message: 'Verification code sent to your email',
        });

    } catch (error: any) {
        console.error('Send OTP error:', error);
        return NextResponse.json(
            { error: 'Something went wrong. Please try again.' },
            { status: 500 }
        );
    }
}

/**
 * Verify an OTP (called internally by the signup or forgot-password routes).
 * Returns true if valid, throws error if invalid/expired.
 */
export async function verifyOtp(email: string, otp: string, purpose: 'signup' | 'password-reset' = 'signup'): Promise<boolean> {
    await connectDB();
    const query = { email, purpose };
    const record = await OtpModel.findOne(query).lean();
    if (!record) {
        throw new Error('No verification code found. Please request a new one.');
    }

    if (new Date() > new Date((record as any).expiresAt)) {
        await OtpModel.deleteOne(query);
        throw new Error('Verification code expired. Please request a new one.');
    }

    // Max 3 wrong attempts
    if ((record as any).attempts >= 3) {
        await OtpModel.deleteOne(query);
        throw new Error('Too many wrong attempts. Please request a new code.');
    }

    if ((record as any).otp !== otp) {
        await OtpModel.updateOne(query, { $inc: { attempts: 1 } });
        const remaining = 3 - ((record as any).attempts + 1);
        throw new Error(`Invalid verification code. ${remaining} attempts remaining.`);
    }

    // Valid — clean up
    await OtpModel.deleteOne(query);
    return true;
}

import { NextRequest, NextResponse } from "next/server";
import {
    createCheckpoint,
    getCheckpoints,
    analyzeRollback,
    executeRollback,
    getSingularitySession,
    getCheckpointSessionId,
} from "@/lib/singularity-history";
import { getSessionUser } from "@/lib/auth";
import { validateCsrfOrigin } from "@/lib/validation";

// Helper: verify session ownership (scoped inside getSingularitySession)
async function verifySessionOwnership(sessionId: string): Promise<boolean> {
    const chatSession = await getSingularitySession(sessionId);
    return !!chatSession;
}

// GET /api/singularity/history/checkpoint?sessionId=xxx — List checkpoints
export async function GET(req: NextRequest) {
    try {
        const session = await getSessionUser();
        if (!session) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { searchParams } = new URL(req.url);
        const sessionId = searchParams.get("sessionId");

        if (!sessionId) {
            return NextResponse.json({ error: "sessionId required" }, { status: 400 });
        }

        // Verify ownership
        if (!(await verifySessionOwnership(sessionId))) {
            return NextResponse.json({ error: "Forbidden" }, { status: 403 });
        }

        const checkpoints = await getCheckpoints(sessionId);
        return NextResponse.json(checkpoints);
    } catch (error: any) {
        console.error("[Checkpoint API] GET error:", error.message);
        return NextResponse.json({ error: "An internal error occurred" }, { status: 500 });
    }
}

// POST /api/singularity/history/checkpoint — Create checkpoint or analyze rollback
export async function POST(req: NextRequest) {
    try {
        const csrf = validateCsrfOrigin(req);
        if (!csrf.valid) return csrf.response;

        const session = await getSessionUser();
        if (!session) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const body = await req.json();

        // If analyzing rollback
        if (body.action === "analyze") {
            // Verify ownership via checkpoint's session
            const cpSessionId = await getCheckpointSessionId(body.checkpointId);
            if (!cpSessionId || !(await verifySessionOwnership(cpSessionId))) {
                return NextResponse.json({ error: "Forbidden" }, { status: 403 });
            }
            const analysis = await analyzeRollback(body.checkpointId);
            if (!analysis) {
                return NextResponse.json({ error: "Checkpoint not found" }, { status: 404 });
            }
            return NextResponse.json(analysis);
        }

        // Creating a checkpoint
        const { sessionId, messageIndex, actions, label } = body;

        if (!sessionId || messageIndex === undefined || !actions) {
            return NextResponse.json({ error: "sessionId, messageIndex, and actions required" }, { status: 400 });
        }

        // Verify ownership
        if (!(await verifySessionOwnership(sessionId))) {
            return NextResponse.json({ error: "Forbidden" }, { status: 403 });
        }

        const checkpointId = await createCheckpoint(sessionId, messageIndex, actions, label || "Checkpoint");
        return NextResponse.json({ checkpointId });
    } catch (error: any) {
        console.error("[Checkpoint API] POST error:", error.message);
        return NextResponse.json({ error: "An internal error occurred" }, { status: 500 });
    }
}

// PUT /api/singularity/history/checkpoint — Execute rollback
export async function PUT(req: NextRequest) {
    try {
        const csrf = validateCsrfOrigin(req);
        if (!csrf.valid) return csrf.response;

        const session = await getSessionUser();
        if (!session) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const body = await req.json();
        const { checkpointId, scope } = body;

        if (!checkpointId || !scope) {
            return NextResponse.json({ error: "checkpointId and scope ('safe' or 'all') required" }, { status: 400 });
        }

        // Verify ownership via the checkpoint's parent session
        const cpSessionId = await getCheckpointSessionId(checkpointId);
        if (!cpSessionId || !(await verifySessionOwnership(cpSessionId))) {
            return NextResponse.json({ error: "Forbidden" }, { status: 403 });
        }

        const result = await executeRollback(checkpointId, scope);
        return NextResponse.json(result);
    } catch (error: any) {
        console.error("[Checkpoint API] PUT error:", error.message);
        return NextResponse.json({ error: "An internal error occurred" }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import {
    getSingularitySessions,
    getSingularitySession,
    createSingularitySession,
    updateSingularitySession,
    updateSingularitySessionMode,
    deleteSingularitySession,
} from "@/lib/singularity-history";
import { getSessionUser } from "@/lib/auth";
import { validateCsrfOrigin } from "@/lib/validation";

// GET /api/singularity/history?sessionId=xxx — Load single session
// GET /api/singularity/history — List current user's sessions
export async function GET(req: NextRequest) {
    try {
        // Authentication check
        const session = await getSessionUser();
        if (!session) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { searchParams } = new URL(req.url);
        const sessionId = searchParams.get("sessionId");

        if (sessionId) {
            const chatSession = await getSingularitySession(sessionId);
            if (!chatSession) {
                return NextResponse.json({ error: "Session not found" }, { status: 404 });
            }
            return NextResponse.json(chatSession);
        }

        // Only return sessions for the authenticated user (Fix IDOR)
        const sessions = await getSingularitySessions(session.userId);
        return NextResponse.json(sessions);
    } catch (error: any) {
        console.error("[History API] GET error:", error.message);
        return NextResponse.json({ error: "An internal error occurred" }, { status: 500 });
    }
}

// POST /api/singularity/history
// — Create new session when body has { mode }
// — Update existing session when body has { sessionId, messages } (used by sendBeacon emergency save)
export async function POST(req: NextRequest) {
    try {
        const csrf = validateCsrfOrigin(req);
        if (!csrf.valid) return csrf.response;

        // Authentication check
        const session = await getSessionUser();
        if (!session) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const body = await req.json();
        const { mode, sessionId, messages, title } = body;

        // If sessionId is present — this is an emergency save from sendBeacon
        if (sessionId && messages) {
            // Verify ownership before updating
            const existingSession = await getSingularitySession(sessionId);
            if (!existingSession) {
                return NextResponse.json({ error: "Forbidden" }, { status: 403 });
            }
            await updateSingularitySession(sessionId, messages, title);
            return NextResponse.json({ success: true });
        }

        // Otherwise — create a new session for the authenticated user
        const newSessionId = await createSingularitySession(session.userId, mode || "chat");
        return NextResponse.json({ sessionId: newSessionId });
    } catch (error: any) {
        console.error("[History API] POST error:", error.message);
        return NextResponse.json({ error: "An internal error occurred" }, { status: 500 });
    }
}

// PUT /api/singularity/history — Update session (save messages)
export async function PUT(req: NextRequest) {
    try {
        const csrf = validateCsrfOrigin(req);
        if (!csrf.valid) return csrf.response;

        // Authentication check
        const session = await getSessionUser();
        if (!session) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const body = await req.json();
        const { sessionId, messages, title, mode: newMode } = body;

        if (!sessionId) {
            return NextResponse.json({ error: "sessionId required" }, { status: 400 });
        }

        // Verify ownership before updating
        const existingSession = await getSingularitySession(sessionId);
        if (!existingSession) {
            return NextResponse.json({ error: "Forbidden" }, { status: 403 });
        }

        if (newMode) {
            await updateSingularitySessionMode(sessionId, newMode);
        }

        if (messages) {
            await updateSingularitySession(sessionId, messages, title);
        }

        return NextResponse.json({ success: true });
    } catch (error: any) {
        console.error("[History API] PUT error:", error.message);
        return NextResponse.json({ error: "An internal error occurred" }, { status: 500 });
    }
}

// DELETE /api/singularity/history?id=xxx — Delete session
export async function DELETE(req: NextRequest) {
    try {
        const csrf = validateCsrfOrigin(req);
        if (!csrf.valid) return csrf.response;

        // Authentication check
        const session = await getSessionUser();
        if (!session) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        const { searchParams } = new URL(req.url);
        const id = searchParams.get("id");

        if (!id) {
            return NextResponse.json({ error: "id required" }, { status: 400 });
        }

        // Verify ownership before deleting
        const existingSession = await getSingularitySession(id);
        if (!existingSession) {
            return NextResponse.json({ error: "Forbidden" }, { status: 403 });
        }

        await deleteSingularitySession(id);
        return NextResponse.json({ success: true });
    } catch (error: any) {
        console.error("[History API] DELETE error:", error.message);
        return NextResponse.json({ error: "An internal error occurred" }, { status: 500 });
    }
}

import { NextRequest, NextResponse } from "next/server";
import { getAgencyAIConfigServer } from "@/lib/utils-server";
import { buildSingularityContext } from "@/lib/singularity-context";
import { SINGULARITY_TOOL_DECLARATIONS, getToolDisplayName } from "@/lib/singularity-tool-defs";
import { executeTool } from "@/lib/singularity-tools";
import { getSessionUser } from "@/lib/auth";
import { getAIPermissions } from "@/lib/actions";
import { getCurrentAgency, checkTrialExpired } from "@/lib/agency-context";
import { validateCsrfOrigin } from "@/lib/validation";
import type { AIPermissions } from "@/lib/types";

// Tool name ? AI permission flag mapping (must stay in sync with singularity-tools.ts)
const TOOL_PERMISSION_FLAGS: Record<string, keyof AIPermissions> = {
    pay_employee: 'canPayroll',
    bulk_pay_employees: 'canPayroll',
    approve_invoice_payment: 'canManageInvoices',
    reject_invoice_payment: 'canManageInvoices',
    update_invoice_status: 'canManageInvoices',
    bulk_create_invoices: 'canManageInvoices',
    create_refund: 'canRefund',
    create_employee: 'canCreateEmployee',
    delete_project: 'canDelete',
    delete_client: 'canDelete',
    delete_transaction: 'canDelete',
    delete_service: 'canDelete',
};

/** Filter tool declarations, removing tools whose AI permissions are disabled */
function filterToolsByPermissions(tools: typeof SINGULARITY_TOOL_DECLARATIONS, aiPerms: AIPermissions) {
    return tools.filter(tool => {
        const requiredFlag = TOOL_PERMISSION_FLAGS[tool.name];
        if (!requiredFlag) return true; // Not permission-gated ? always include
        return aiPerms[requiredFlag]; // Only include if the flag is enabled
    });
}

export const runtime = "nodejs";
export const dynamic = "force-dynamic";

// ---------------------------------------------------------------------------
// Short-response fallback helper
// If the AI's reply has fewer than 2 non-empty lines, we ask it whether the
// answer was complete or got cut off. The AI responds with either:
//   "COMPLETE" ? original answer was fine, return nothing extra
//   anything else ? that text is the continuation, append it
// ---------------------------------------------------------------------------
function isTooShort(text: string): boolean {
    const trimmed = text.trim();
    if (!trimmed) return true;
    // Consider response complete if it has reasonable length (>80 chars)
    if (trimmed.length > 80) return false;
    // Ends with sentence-ending punctuation ? complete
    if (/[.!?]$/.test(trimmed)) return false;
    // Ends with code block, list marker, closing tag, or other structural endings ? complete
    if (/```\s*$/.test(trimmed)) return false;
    if (/[)}\]>:`"']$/.test(trimmed)) return false;
    // Very short and no ending punctuation ? possibly cut off
    return trimmed.split('\n').filter(l => l.trim()).length < 2;
}

async function checkAndContinue(
    generateContent: (cfg: any, prompt: string, sys?: string) => Promise<{ text: string; tokens?: any }>,
    aiConfig: any,
    systemInstruction: string,
    originalPrompt: string,
    originalReply: string
): Promise<string | null> {
    const followUpPrompt =
        originalPrompt +
        `\n\nSingularity: ${originalReply}\n\n` +
        `User: Was your previous answer fully complete, or did it get cut off? ` +
        `If it was complete (even if short), reply with exactly the word COMPLETE and nothing else. ` +
        `If it was cut off or incomplete, continue your answer from exactly where you left off — do NOT repeat what you already said.`;

    const { text: continuation } = await generateContent(aiConfig, followUpPrompt, systemInstruction);
    const trimmed = continuation.trim();

    // AI signals it was done ? nothing to add
    if (!trimmed || trimmed.toUpperCase() === 'COMPLETE') return null;

    return trimmed;
}

export async function POST(req: NextRequest) {
    try {
        const csrf = validateCsrfOrigin(req);
        if (!csrf.valid) return csrf.response;

        // Authentication check
        const session = await getSessionUser();
        if (!session) {
            return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
        }

        // Trial expiration check
        const agency = await getCurrentAgency();
        if (await checkTrialExpired(agency)) {
            return NextResponse.json({ error: "Trial expired. Please upgrade your plan." }, { status: 403 });
        }

        const { history, message, images, documents, mode } = await req.json();
        const authenticatedUserId = session.userId;

        // Limit message size to prevent abuse
        if (typeof message === 'string' && message.length > 50000) {
            return NextResponse.json({ error: 'Message too long (max 50,000 characters)' }, { status: 400 });
        }

        const aiConfig = await getAgencyAIConfigServer();
        if (!aiConfig) {
            return NextResponse.json({ error: "AI not configured" }, { status: 500 });
        }

        // Build prompt with history
        let fullPrompt = '';
        if (history && history.length > 0) {
            fullPrompt += history
                .map((m: any) => `${m.role === 'user' ? 'User' : 'Singularity'}: ${m.content}`)
                .join('\n\n');
            fullPrompt += '\n\n';
        }
        fullPrompt += `User: ${message}`;

        // Append document text content to prompt
        if (documents && documents.length > 0) {
            fullPrompt += '\n\n--- UPLOADED DOCUMENTS ---\n';
            for (const doc of documents) {
                fullPrompt += `\n?? FILE: ${doc.fileName} (${doc.mimeType})\n`;
                if (doc.textContent && !doc.textContent.startsWith('[PDF Document:')) {
                    fullPrompt += `CONTENT:\n${doc.textContent}\n`;
                }
                fullPrompt += '---\n';
            }
        }

        const modelId = aiConfig.model || 'gemini-2.5-flash-lite';
        const isLive = modelId.includes('native-audio');

        // =====================================================================
        // AGENT MODE — TEXT modality + agency context + tool calling
        // =====================================================================
        if (mode === 'agent') {
            console.log('[Singularity Agent] Starting agent mode for userId:', authenticatedUserId);

            // Build agency context
            let systemInstruction = '';
            try {
                systemInstruction = await buildSingularityContext(authenticatedUserId);
                console.log('[Singularity Agent] Context built, length:', systemInstruction.length);
            } catch (ctxErr: any) {
                console.error('[Singularity Agent] Context build failed:', ctxErr?.message || ctxErr);
                systemInstruction = 'You are Singularity Agent — an AI assistant for agency management. Agency data could not be loaded.';
            }
            // Model-aware prompt: add extra guardrails for weaker/lite models
            const isLiteModel = modelId.includes('lite') || modelId.includes('flash-lite');
            if (isLiteModel) {
                systemInstruction += `\n\n?? MODEL-SPECIFIC RULES (you are a lightweight model):
- ALWAYS use bulk tools (bulk_create_tasks, bulk_update_task_status) instead of individual calls for batch operations.
- When moving tasks to Done with realistic dates, use bulk_update_task_status with autoBackdate=true.
- You MUST call a tool to perform an action. Reading data (get_project_tasks) does NOT modify anything.
- If you only see "Fetching tasks" in the Actions, you have NOT updated any tasks.
- Keep responses concise. Do not over-explain or repeat yourself.`;
            }
            const agentPrompt = systemInstruction + '\n\n---\n\n' + fullPrompt;

            // Fetch AI permissions and filter tool declarations
            let filteredTools = SINGULARITY_TOOL_DECLARATIONS;
            try {
                const aiPerms = await getAIPermissions();
                filteredTools = filterToolsByPermissions(SINGULARITY_TOOL_DECLARATIONS, aiPerms);
                console.log(`[Singularity Agent] Tools: ${SINGULARITY_TOOL_DECLARATIONS.length} total, ${filteredTools.length} after permission filter`);
            } catch (err) {
                console.error('[Singularity Agent] Failed to filter tools by permissions:', err);
            }

            if (!isLive) {
                // Non-live model: text API with tool calling support (BUG-031)
                const { GoogleGenerativeAI } = await import("@google/generative-ai");
                const genAI = new GoogleGenerativeAI(aiConfig.apiKey);
                const model = genAI.getGenerativeModel({
                    model: modelId,
                    systemInstruction,
                    tools: [{ functionDeclarations: filteredTools as any }],
                });
                const chat = model.startChat();
                const encoder = new TextEncoder();

                const stream = new ReadableStream({
                    async start(controller) {
                        try {
                            const MAX_TOOL_ROUNDS = 25;

                            // Send initial user message
                            const initialResult = await chat.sendMessage(fullPrompt);
                            let responseParts = initialResult.response.candidates?.[0]?.content?.parts || [];

                            for (let round = 0; round < MAX_TOOL_ROUNDS; round++) {
                                // Collect text parts
                                const textParts = responseParts.filter((p: any) => p.text).map((p: any) => p.text);
                                if (textParts.length > 0) {
                                    controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'response', text: textParts.join('') })}\n\n`));
                                }

                                // Check for function calls
                                const functionCalls = responseParts.filter((p: any) => p.functionCall);
                                if (functionCalls.length === 0) break; // No more tool calls — done

                                // Execute each tool call
                                const functionResponses: any[] = [];
                                for (const part of functionCalls) {
                                    const fc = part.functionCall!;
                                    const displayName = getToolDisplayName(fc.name);
                                    controller.enqueue(encoder.encode(
                                        `data: ${JSON.stringify({ type: 'tool_call', name: fc.name, displayName, args: fc.args })}\n\n`
                                    ));
                                    const toolResult = await executeTool(fc.name, fc.args || {}, authenticatedUserId);
                                    console.log('[Singularity Agent] Tool result:', fc.name, toolResult.success, toolResult.summary);
                                    controller.enqueue(encoder.encode(
                                        `data: ${JSON.stringify({ type: 'tool_result', name: fc.name, displayName, success: toolResult.success, summary: toolResult.summary, rollbackData: toolResult.rollbackData })}\n\n`
                                    ));
                                    functionResponses.push({
                                        functionResponse: {
                                            name: fc.name,
                                            response: toolResult,
                                        }
                                    });
                                }

                                // Send tool results back to the model and process the response in the next iteration
                                const toolResultMsg = await chat.sendMessage(functionResponses);
                                responseParts = toolResultMsg.response.candidates?.[0]?.content?.parts || [];
                            }
                        } catch (err: any) {
                            console.error('[Singularity Agent] Non-live error:', err?.message || err);
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'error', text: err?.message || 'Agent error' })}\n\n`));
                        }

                        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'done' })}\n\n`));
                        controller.close();
                    }
                });
                return new Response(stream, {
                    headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache', 'Connection': 'keep-alive' },
                });
            }

            // Live API — Agent mode with tools (AUDIO modality + transcription)
            const { GoogleGenAI, Modality } = await import("@google/genai");
            const ai = new GoogleGenAI({ apiKey: aiConfig.apiKey });
            const encoder = new TextEncoder();

            // Build parts once (reused across retries): text + optional PDF/image inline data
            const parts: any[] = [];
            if (documents && documents.length > 0) {
                for (const doc of documents) {
                    if (doc.mimeType === 'application/pdf' && doc.base64) {
                        parts.push({ inlineData: { mimeType: 'application/pdf', data: doc.base64 } });
                    }
                }
            }
            if (images && images.length > 0) {
                for (const img of images) {
                    parts.push({ inlineData: { mimeType: img.mimeType, data: img.base64 } });
                }
            }
            parts.push({ text: agentPrompt });

            const stream = new ReadableStream({
                async start(controller) {
                    try {
                        let totalResponseChars = 0;
                        let accumulatedText = '';

                        // Helper: poll messages from a Live session, stream to client, handle tools
                        const pollSession = async (liveSession: any, messageQueue: any[], label: string) => {
                            let done = false;
                            totalResponseChars = 0;
                            accumulatedText = '';
                            let msgCount = 0;
                            const timeout = setTimeout(() => {
                                console.log(`[Agent ${label}] Timeout reached`);
                                done = true;
                            }, 120000);

                            const waitMsg = (): Promise<any> => new Promise((resolve) => {
                                const check = () => {
                                    if (done) { resolve(null); return; }
                                    const msg = messageQueue.shift();
                                    if (msg) resolve(msg);
                                    else setTimeout(check, 50);
                                };
                                check();
                            });

                            while (!done) {
                                const msg = await waitMsg();
                                if (!msg) break;
                                msgCount++;

                                if (msg.serverContent?.modelTurn?.parts) {
                                    for (const part of msg.serverContent.modelTurn.parts) {
                                        if (part.text) {
                                            totalResponseChars += part.text.length;
                                            accumulatedText += part.text;
                                            controller.enqueue(encoder.encode(
                                                `data: ${JSON.stringify({ type: 'response', text: part.text })}\n\n`
                                            ));
                                        }
                                    }
                                }

                                if ((msg.serverContent as any)?.outputTranscription?.text) {
                                    const chunk = (msg.serverContent as any).outputTranscription.text;
                                    totalResponseChars += chunk.length;
                                    accumulatedText += chunk;
                                    controller.enqueue(encoder.encode(
                                        `data: ${JSON.stringify({ type: 'response', text: chunk })}\n\n`
                                    ));
                                }

                                // Handle tool calls
                                if (msg.toolCall && msg.toolCall.functionCalls) {
                                    console.log(`[Agent ${label}] Tool calls:`, msg.toolCall.functionCalls.map((fc: any) => fc.name));
                                    const functionResponses: any[] = [];

                                    const flushTranscripts = () => {
                                        while (messageQueue.length > 0) {
                                            const queued = messageQueue[0];
                                            if (queued.toolCall || queued.serverContent?.turnComplete) break;
                                            messageQueue.shift();
                                            if (queued.serverContent?.modelTurn?.parts) {
                                                for (const part of queued.serverContent.modelTurn.parts) {
                                                    if (part.text) {
                                                        totalResponseChars += part.text.length;
                                                        accumulatedText += part.text;
                                                        controller.enqueue(encoder.encode(
                                                            `data: ${JSON.stringify({ type: 'response', text: part.text })}\n\n`
                                                        ));
                                                    }
                                                }
                                            }
                                            if ((queued.serverContent as any)?.outputTranscription?.text) {
                                                const chunk = (queued.serverContent as any).outputTranscription.text;
                                                totalResponseChars += chunk.length;
                                                accumulatedText += chunk;
                                                controller.enqueue(encoder.encode(
                                                    `data: ${JSON.stringify({ type: 'response', text: chunk })}\n\n`
                                                ));
                                            }
                                        }
                                    };

                                    for (const fc of msg.toolCall.functionCalls) {
                                        const displayName = getToolDisplayName(fc.name);
                                        controller.enqueue(encoder.encode(
                                            `data: ${JSON.stringify({ type: 'tool_call', name: fc.name, displayName, args: fc.args })}\n\n`
                                        ));
                                        const result = await executeTool(fc.name, fc.args || {}, authenticatedUserId);
                                        console.log(`[Agent ${label}] Tool result:`, fc.name, result.success, result.summary);
                                        controller.enqueue(encoder.encode(
                                            `data: ${JSON.stringify({ type: 'tool_result', name: fc.name, displayName, success: result.success, summary: result.summary, rollbackData: result.rollbackData })}\n\n`
                                        ));
                                        functionResponses.push({ id: fc.id, name: fc.name, response: result });
                                        flushTranscripts();
                                    }

                                    liveSession.sendToolResponse({ functionResponses });
                                    continue;
                                }

                                if (msg.serverContent?.turnComplete) {
                                    console.log(`[Agent ${label}] turnComplete after ${msgCount} msgs. Response: ${totalResponseChars} chars`);
                                    done = true;
                                }
                            }

                            // Drain remaining chunks
                            let drainDeadline = Date.now() + 5000;
                            while (Date.now() < drainDeadline) {
                                const remaining = messageQueue.shift();
                                if (!remaining) { await new Promise(r => setTimeout(r, 100)); continue; }
                                let hadContent = false;
                                if (remaining.serverContent?.modelTurn?.parts) {
                                    for (const part of remaining.serverContent.modelTurn.parts) {
                                        if (part.text) {
                                            totalResponseChars += part.text.length;
                                            accumulatedText += part.text;
                                            controller.enqueue(encoder.encode(
                                                `data: ${JSON.stringify({ type: 'response', text: part.text })}\n\n`
                                            ));
                                            hadContent = true;
                                        }
                                    }
                                }
                                if ((remaining.serverContent as any)?.outputTranscription?.text) {
                                    const chunk = (remaining.serverContent as any).outputTranscription.text;
                                    totalResponseChars += chunk.length;
                                    accumulatedText += chunk;
                                    controller.enqueue(encoder.encode(
                                        `data: ${JSON.stringify({ type: 'response', text: chunk })}\n\n`
                                    ));
                                    hadContent = true;
                                }
                                if (hadContent) drainDeadline = Math.max(drainDeadline, Date.now() + 2000);
                            }
                            clearTimeout(timeout);
                        };

                        const isResponseBad = () => totalResponseChars === 0 || isTooShort(accumulatedText);

                        // --- Phase 1: Initial attempt on fresh connection ---
                        const messageQueue: any[] = [];
                        console.log('[Singularity Agent] Connecting with model:', modelId);

                        let session = await ai.live.connect({
                            model: `models/${modelId}`,
                            config: {
                                responseModalities: [Modality.AUDIO],
                                speechConfig: {
                                    voiceConfig: {
                                        prebuiltVoiceConfig: { voiceName: 'Zephyr' }
                                    }
                                },
                                outputAudioTranscription: {},
                                tools: [{ functionDeclarations: filteredTools }],
                            } as any,
                            callbacks: {
                                onopen: () => { console.log('[Singularity Agent] Connected'); },
                                onmessage: (msg: any) => messageQueue.push(msg),
                                onerror: (e: any) => {
                                    console.error('[Singularity Agent] WS Error:', e?.message || e);
                                    try {
                                        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'error', text: 'Connection error' })}\n\n`));
                                    } catch { }
                                },
                                onclose: () => { console.log('[Singularity Agent] Disconnected'); },
                            },
                        });

                        session.sendClientContent({ turns: [{ role: 'user', parts }] });
                        await pollSession(session, messageQueue, 'attempt-1');

                        // --- Phase 2: Same-connection retry if response was bad ---
                        if (isResponseBad()) {
                            console.log(`[Agent] Same-connection retry (was ${totalResponseChars} chars)`);
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'clear' })}\n\n`));
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'rechecking' })}\n\n`));
                            totalResponseChars = 0;
                            accumulatedText = '';
                            messageQueue.length = 0; // Clear stale messages
                            session.sendClientContent({ turns: [{ role: 'user', parts }] });
                            await pollSession(session, messageQueue, 'same-conn-retry');
                        }

                        session.close();

                        // --- Phase 3: Reconnect if still bad ---
                        if (isResponseBad()) {
                            console.log(`[Agent] Reconnecting (was ${totalResponseChars} chars)`);
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'clear' })}\n\n`));
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'rechecking' })}\n\n`));
                            totalResponseChars = 0;
                            accumulatedText = '';
                            await new Promise(r => setTimeout(r, 500));

                            const mq2: any[] = [];
                            session = await ai.live.connect({
                                model: `models/${modelId}`,
                                config: {
                                    responseModalities: [Modality.AUDIO],
                                    speechConfig: {
                                        voiceConfig: {
                                            prebuiltVoiceConfig: { voiceName: 'Zephyr' }
                                        }
                                    },
                                    outputAudioTranscription: {},
                                    tools: [{ functionDeclarations: filteredTools }],
                                } as any,
                                callbacks: {
                                    onopen: () => { console.log('[Singularity Agent] Reconnected'); },
                                    onmessage: (msg: any) => mq2.push(msg),
                                    onerror: (e: any) => {
                                        console.error('[Singularity Agent] WS Error:', e?.message || e);
                                        try {
                                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'error', text: 'Connection error' })}\n\n`));
                                        } catch { }
                                    },
                                    onclose: () => { console.log('[Singularity Agent] Disconnected'); },
                                },
                            });

                            session.sendClientContent({ turns: [{ role: 'user', parts }] });
                            await pollSession(session, mq2, 'reconnect');
                            session.close();
                        }

                        // --- Phase 4: Short-response fallback via text API (non-live model) ---
                        if (totalResponseChars > 0 && isTooShort(accumulatedText)) {
                            console.log('[Agent] Response too short, falling back to gemini-3.1-flash-lite-preview...');
                            const previousAnswer = accumulatedText;
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'clear' })}\n\n`));
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'rechecking' })}\n\n`));
                            totalResponseChars = 0;
                            accumulatedText = '';
                            try {
                                const { generateContent } = await import("@/lib/ai-provider");
                                const fallbackConfig = { ...aiConfig, model: 'gemini-3.1-flash-lite-preview' };
                                const continuation = await checkAndContinue(generateContent, fallbackConfig, systemInstruction, fullPrompt, previousAnswer);
                                if (continuation) {
                                    console.log('[Agent] Text API continuation appended.');
                                    controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'response', text: continuation })}\n\n`));
                                } else {
                                    console.log('[Agent] Text API confirmed answer was complete.');
                                }
                            } catch (err) {
                                console.error('[Agent] Text API fallback failed:', err);
                            }
                        }

                        if (totalResponseChars === 0) {
                            console.log('[Agent] All attempts returned 0 chars');
                        }

                        // Log AI usage for agent mode (Live API — estimate tokens from text)
                        const { logAIUsage: logAgentUsage } = await import("@/lib/ai-usage");
                        const agentInputTokens = Math.ceil((agentPrompt || '').length / 4);
                        const agentOutputTokens = Math.ceil((accumulatedText || '').length / 4);
                        logAgentUsage({ agencyId: agency!.id, userId: authenticatedUserId, feature: 'singularity-agent', model: modelId, provider: aiConfig.provider, inputTokens: agentInputTokens, outputTokens: agentOutputTokens, totalTokens: agentInputTokens + agentOutputTokens });

                        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'done' })}\n\n`));
                        controller.close();
                    } catch (error: any) {
                        console.error('[Singularity Agent] Error:', error?.message || error);
                        try {
                            controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'error', text: error?.message || 'Agent error' })}\n\n`));
                            controller.close();
                        } catch { }
                    }
                }
            });

            return new Response(stream, {
                headers: {
                    'Content-Type': 'text/event-stream',
                    'Cache-Control': 'no-cache',
                    'Connection': 'keep-alive',
                },
            });
        }

        // =====================================================================
        // CHAT MODE — Existing code, completely untouched
        // =====================================================================

        if (!isLive) {
            // Non-live model: single response, no streaming
            const { generateContent } = await import("@/lib/ai-provider");
            const { logAIUsage } = await import("@/lib/ai-usage");
            const { text: result, tokens } = await generateContent(aiConfig, fullPrompt);
            logAIUsage({ agencyId: agency!.id, userId: authenticatedUserId, feature: 'singularity-chat', model: modelId, provider: aiConfig.provider, ...tokens });
            const encoder = new TextEncoder();

            // Stream initial response immediately, fallback check runs inside stream before done
            const stream = new ReadableStream({
                async start(controller) {
                    // 1. Send initial response right away
                    controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'response', text: result })}\n\n`));

                    // 2. Short-response fallback check (non-live model)
                    if (isTooShort(result)) {
                        console.log('[Singularity Chat] Response too short, falling back to gemini-3.1-flash-lite-preview...');
                        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'clear' })}\n\n`));
                        controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'rechecking' })}\n\n`));
                        try {
                            const fallbackConfig = { ...aiConfig, model: 'gemini-3.1-flash-lite-preview' };
                            const continuation = await checkAndContinue(generateContent, fallbackConfig, '', fullPrompt, result);
                            if (continuation) {
                                console.log('[Singularity Chat] Appending continuation.');
                                controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'response', text: continuation })}\n\n`));
                            } else {
                                console.log('[Singularity Chat] AI confirmed answer was complete.');
                            }
                        } catch (err) {
                            console.error('[Singularity Chat] Fallback check failed:', err);
                        }
                    }

                    // 3. Done
                    controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'done' })}\n\n`));
                    controller.close();
                }
            });
            return new Response(stream, {
                headers: { 'Content-Type': 'text/event-stream', 'Cache-Control': 'no-cache', 'Connection': 'keep-alive' },
            });
        }

        // Live API — stream thinking + transcript in real-time
        const { GoogleGenAI, Modality } = await import("@google/genai");
        const ai = new GoogleGenAI({ apiKey: aiConfig.apiKey });
        const messageQueue: any[] = [];

        const encoder = new TextEncoder();

        const stream = new ReadableStream({
            async start(controller) {
                try {
                    const session = await ai.live.connect({
                        model: `models/${modelId}`,
                        config: {
                            responseModalities: [Modality.AUDIO],
                            speechConfig: {
                                voiceConfig: {
                                    prebuiltVoiceConfig: { voiceName: 'Zephyr' }
                                }
                            },
                            outputAudioTranscription: {},
                        } as any,
                        callbacks: {
                            onopen: () => { },
                            onmessage: (msg: any) => messageQueue.push(msg),
                            onerror: (e: any) => {
                                console.error('[Singularity Stream] Error:', e?.message || e);
                                controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'error', text: 'Connection error' })}\n\n`));
                            },
                            onclose: () => { },
                        },
                    });

                    // Build turn with text + optional images
                    const parts: any[] = [];

                    // Add images as inline data
                    if (images && images.length > 0) {
                        for (const img of images) {
                            parts.push({
                                inlineData: {
                                    mimeType: img.mimeType,
                                    data: img.base64,
                                }
                            });
                        }
                    }

                    // Add text prompt
                    parts.push({ text: fullPrompt });

                    session.sendClientContent({
                        turns: [{ role: 'user', parts }]
                    });

                    // Poll and stream messages
                    let done = false;
                    let liveChatAccumulatedText = '';
                    const timeout = setTimeout(() => { done = true; }, 60000);

                    const waitMsg = (): Promise<any> => new Promise((resolve) => {
                        const check = () => {
                            const msg = messageQueue.shift();
                            if (msg) resolve(msg);
                            else setTimeout(check, 50);
                        };
                        check();
                    });

                    while (!done) {
                        const msg = await waitMsg();

                        // Stream thinking text as it arrives
                        if (msg.serverContent?.modelTurn?.parts) {
                            for (const part of msg.serverContent.modelTurn.parts) {
                                if (part.text) {
                                    liveChatAccumulatedText += part.text;
                                    controller.enqueue(encoder.encode(
                                        `data: ${JSON.stringify({ type: 'thinking', text: part.text })}\n\n`
                                    ));
                                }
                            }
                        }

                        // Stream transcript text as it arrives
                        if ((msg.serverContent as any)?.outputTranscription?.text) {
                            liveChatAccumulatedText += (msg.serverContent as any).outputTranscription.text;
                            controller.enqueue(encoder.encode(
                                `data: ${JSON.stringify({ type: 'response', text: (msg.serverContent as any).outputTranscription.text })}\n\n`
                            ));
                        }

                        if (msg.serverContent?.turnComplete) {
                            done = true;
                        }
                    }

                    // IMPORTANT: Transcript chunks can arrive AFTER turnComplete.
                    // Use a rolling window: extend drain whenever new data arrives.
                    let drainDeadline = Date.now() + 5000;
                    while (Date.now() < drainDeadline) {
                        const remaining = messageQueue.shift();
                        if (!remaining) {
                            await new Promise(r => setTimeout(r, 100));
                            continue;
                        }
                        if ((remaining.serverContent as any)?.outputTranscription?.text) {
                            liveChatAccumulatedText += (remaining.serverContent as any).outputTranscription.text;
                            controller.enqueue(encoder.encode(
                                `data: ${JSON.stringify({ type: 'response', text: (remaining.serverContent as any).outputTranscription.text })}\n\n`
                            ));
                            // Extend drain window — more transcription may follow
                            drainDeadline = Math.max(drainDeadline, Date.now() + 2000);
                        }
                    }

                    clearTimeout(timeout);
                    session.close();

                    // Log AI usage for live chat mode (estimate tokens from text)
                    const { logAIUsage: logLiveChatUsage } = await import("@/lib/ai-usage");
                    const chatInputTokens = Math.ceil((fullPrompt || '').length / 4);
                    const chatOutputTokens = Math.ceil((liveChatAccumulatedText || '').length / 4);
                    logLiveChatUsage({ agencyId: agency!.id, userId: authenticatedUserId, feature: 'singularity-chat', model: modelId, provider: aiConfig.provider, inputTokens: chatInputTokens, outputTokens: chatOutputTokens, totalTokens: chatInputTokens + chatOutputTokens });

                    controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'done' })}\n\n`));
                    controller.close();
                } catch (error: any) {
                    console.error('[Singularity Stream] Error:', error);
                    // Sanitize error: only show safe user-facing messages, not internal details
                    const msg = error?.message || '';
                    const isSafe = msg.startsWith('Unauthorized') || msg.startsWith('AI permissions')
                        || msg.startsWith('Plan limit') || msg.includes('quota') || msg.includes('rate limit');
                    const safeMsg = isSafe ? msg : 'Something went wrong. Please try again.';
                    controller.enqueue(encoder.encode(`data: ${JSON.stringify({ type: 'error', text: safeMsg })}\n\n`));
                    controller.close();
                }
            }
        });

        return new Response(stream, {
            headers: {
                'Content-Type': 'text/event-stream',
                'Cache-Control': 'no-cache',
                'Connection': 'keep-alive',
            },
        });
    } catch (error: any) {
        console.error('[Singularity API] Error:', error);
        return NextResponse.json({ error: "An internal error occurred" }, { status: 500 });
    }
}

"use client";

import { useState, useEffect, useCallback, useMemo } from "react";
import { useRouter } from "next/navigation";
import { getClients, getArchivedClients, unarchiveClient, deleteClient, permanentlyDeleteClient, getCurrentUser } from "@/lib/actions";
import { Client } from "@/lib/types";
import { ClientCard } from "@/components/clients/ClientCard";
import { EditClientDialog } from "@/components/clients/EditClientDialog";
import { Plus, Archive, ArchiveRestore, Search } from "lucide-react";
import { ClientsSkeleton } from "@/components/clients/ClientsSkeleton";
import { Button } from "@/components/ui/button";
import { toast } from "sonner";
import { useProgressiveList } from "@/hooks/use-infinite-scroll";
import { Loader2 } from "lucide-react";
import { PermanentDeleteDialog } from "@/components/PermanentDeleteDialog";

export default function ClientsPage() {
    const [clients, setClients] = useState<Client[]>([]);
    const [loading, setLoading] = useState(true);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editingClient, setEditingClient] = useState<Client | null>(null);
    const [showArchived, setShowArchived] = useState(false);
    const [searchQuery, setSearchQuery] = useState("");
    const [permanentDeleteTarget, setPermanentDeleteTarget] = useState<Client | null>(null);
    const router = useRouter();

    const loadData = useCallback(async () => {
        setLoading(true);
        try {
            // C8 fix: Block client accounts from seeing other clients
            const user = await getCurrentUser();
            if (user?.role === 'client') {
                router.replace('/dashboard');
                return;
            }
            const data = showArchived ? await getArchivedClients() : await getClients();
            setClients(data);
        } catch (error) {
            console.error("Failed to load clients", error);
            toast.error("Failed to load clients");
        } finally {
            setLoading(false);
        }
    }, [showArchived]);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const filteredClients = useMemo(() => {
        if (!searchQuery.trim()) return clients;
        const q = searchQuery.toLowerCase();
        return clients.filter(c =>
            c.name.toLowerCase().includes(q) ||
            c.companyName.toLowerCase().includes(q) ||
            c.email.toLowerCase().includes(q) ||
            (c.phone && c.phone.includes(q))
        );
    }, [clients, searchQuery]);

    const { visibleCount, sentinelRef, hasMore } = useProgressiveList(filteredClients.length, 12, [searchQuery, showArchived]);

    const handleOpenDialog = (client?: Client) => {
        setEditingClient(client || null);
        setIsDialogOpen(true);
    };

    const handleUnarchive = async (clientId: string, clientName: string) => {
        try {
            await unarchiveClient(clientId);
            toast.success(`${clientName} restored successfully`);
            loadData();
        } catch (error) {
            console.error("Failed to unarchive client", error);
            toast.error("Failed to restore client");
        }
    };

    const handleDelete = async (clientId: string, clientName: string) => {
        if (confirm(`Archive "${clientName}"? Their login is disabled but all data is preserved. You can restore them anytime.`)) {
            try {
                await deleteClient(clientId);
                toast.success(`${clientName} archived successfully`);
                loadData();
            } catch (error) {
                console.error("Failed to archive client", error);
                toast.error("Failed to archive client");
            }
        }
    };

    const handlePermanentDelete = (client: Client) => {
        setPermanentDeleteTarget(client);
    };

    const executePermanentDelete = async (password: string) => {
        if (!permanentDeleteTarget) return;
        await permanentlyDeleteClient(permanentDeleteTarget.id, password);
        toast.success(`${permanentDeleteTarget.name} has been permanently deleted.`);
        setPermanentDeleteTarget(null);
        loadData();
    };

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row sm:items-center justify-between space-y-4 sm:space-y-0">
                <h1 className="text-2xl sm:text-3xl font-bold">
                    {showArchived ? "Archived Clients" : "Clients"}
                </h1>
                <div className="flex gap-2">
                    <Button
                        variant={showArchived ? "default" : "outline"}
                        onClick={() => setShowArchived(!showArchived)}
                        className="w-full sm:w-auto"
                    >
                        {showArchived ? (
                            <>
                                <ArchiveRestore className="mr-2 h-4 w-4" />
                                Show Active
                            </>
                        ) : (
                            <>
                                <Archive className="mr-2 h-4 w-4" />
                                Show Archived
                            </>
                        )}
                    </Button>
                    {!showArchived && (
                        <button
                            onClick={() => handleOpenDialog()}
                            className="w-full sm:w-auto inline-flex items-center justify-center rounded-md text-sm font-medium bg-primary text-primary-foreground hover:bg-primary/90 h-10 px-4 py-2"
                        >
                            <Plus className="mr-2 h-4 w-4" /> Add Client
                        </button>
                    )}
                </div>
            </div>

            {/* Search bar */}
            <div className="relative max-w-md">
                <Search className="absolute left-3 top-2.5 w-4 h-4 text-muted-foreground" />
                <input
                    type="text"
                    placeholder="Search by name, company, email..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="w-full bg-secondary border border-border rounded-lg py-2 pl-10 pr-4 text-sm focus:outline-none focus:ring-2 focus:ring-primary/20 text-foreground placeholder:text-muted-foreground"
                />
            </div>

            {loading ? (
                <ClientsSkeleton />
            ) : filteredClients.length === 0 ? (
                <div className="text-center py-12 text-muted-foreground">
                    {searchQuery.trim()
                        ? `No clients match "${searchQuery}".`
                        : showArchived
                            ? "No archived clients found."
                            : "No clients found. Click \"Add Client\" to get started."
                    }
                </div>
            ) : (
                <>
                    <div className="grid gap-6 grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
                        {filteredClients.slice(0, visibleCount).map(client => (
                            <ClientCard
                                key={client.id}
                                client={client}
                                onEdit={handleOpenDialog}
                                onUnarchive={showArchived ? handleUnarchive : undefined}
                                onDelete={!showArchived ? handleDelete : undefined}
                                onPermanentDelete={!showArchived ? handlePermanentDelete : undefined}
                                isArchived={showArchived}
                            />
                        ))}
                    </div>
                    {hasMore && (
                        <div ref={sentinelRef} className="flex justify-center py-6">
                            <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                        </div>
                    )}
                </>
            )}

            <EditClientDialog
                client={editingClient}
                open={isDialogOpen}
                onOpenChange={setIsDialogOpen}
                onSuccess={loadData}
            />

            <PermanentDeleteDialog
                open={!!permanentDeleteTarget}
                onOpenChange={(open) => { if (!open) setPermanentDeleteTarget(null); }}
                entityName={permanentDeleteTarget?.name || ""}
                entityType="client"
                warningItems={[
                    "Client account and login credentials",
                    "All projects owned by this client",
                    "All tasks within those projects",
                    "All invoices and payment records",
                    "All transactions linked to client projects",
                    "All project assets and files",
                ]}
                onConfirm={executePermanentDelete}
            />
        </div>
    );
}

