                    <h4 className={cn("text-sm font-semibold truncate", isActive ? "text-primary" : "text-foreground group-hover:text-primary")}>
                        {contact.name}
                        {contact.username && <span className="ml-1 text-xs text-muted-foreground font-normal">@{contact.username}</span>}
                    </h4>
                    {contact.lastMessage && !confirming && (
                        <span className="text-[10px] text-muted-foreground whitespace-nowrap ml-2 shrink-0">
                            {fmt.isToday(contact.lastMessage.timestamp)
                                ? fmt.time(contact.lastMessage.timestamp)
                                : fmt.isYesterday(contact.lastMessage.timestamp)
                                    ? "Yesterday"
                                    : fmt.dateShort(contact.lastMessage.timestamp)}
                        </span>
                    )}
                </div>

                {/* Last message or presence */}
                <div className="flex justify-between items-center mt-0.5">
                    {contact.lastMessage ? (
                        <p className="text-xs text-muted-foreground truncate max-w-[140px]">
                            {contact.lastMessage.content}
                        </p>
                    ) : (
                        <p className={cn("text-xs truncate max-w-[140px]", isOnline ? "text-green-500 font-medium" : "text-muted-foreground")}>
                            {presenceText}
                        </p>
                    )}
                    {contact.unreadCount > 0 && !confirming && (
                        <div className="bg-primary text-primary-foreground text-[10px] font-bold w-5 h-5 flex items-center justify-center rounded-full shrink-0 ml-1">
                            {contact.unreadCount}
                        </div>
                    )}
                </div>

                {/* Presence line */}
                {contact.lastMessage && (
                    <p className={cn("text-[10px] mt-0.5 truncate", isOnline ? "text-green-500 font-medium" : "text-muted-foreground/70")}>
                        {presenceText}
                    </p>
                )}
            </div>

            {/* Delete controls */}
            {onDelete && contact.lastMessage && (
                confirming ? (
                    <div
                        onClick={e => e.stopPropagation()}
                        className="absolute right-2 top-1/2 -translate-y-1/2 flex items-center gap-1 bg-card border border-border shadow-lg rounded-xl px-2 py-1 text-xs"
                    >
                        <span className="text-muted-foreground mr-1 whitespace-nowrap">Delete?</span>
                        <button
                            onClick={handleConfirm}
                            className="w-6 h-6 flex items-center justify-center bg-red-500 hover:bg-red-600 text-white rounded-lg transition"
                            title="Confirm delete"
                        >
                            <Check className="w-3.5 h-3.5" />
                        </button>
                        <button
                            onClick={handleCancel}
                            className="w-6 h-6 flex items-center justify-center bg-muted hover:bg-muted/80 text-foreground rounded-lg transition"
                            title="Cancel"
                        >
                            <span className="text-sm leading-none">&times;</span>
                        </button>
                    </div>
                ) : (
                    <button
                        onClick={handleDeleteClick}
                        title="Delete conversation"
                        className="absolute right-2 top-1/2 -translate-y-1/2 opacity-100 md:opacity-0 md:group-hover:opacity-100 transition p-1.5 rounded-lg hover:bg-red-500/10 hover:text-red-500 text-muted-foreground"
                    >
                        <Trash2 className="w-3.5 h-3.5" />
                    </button>
                )
            )}
        </div>
    );
}

"use client";

import { MessagesList, ContactItem, ContactSkeleton, MessagesSkeleton, EmojiPicker } from "./ChatComponents";
import { X, Send, Search, Smile, MessageCircle, Trash2, ArrowLeft, MessageSquare, Loader2 } from "lucide-react";
import { cn } from "@/lib/utils";
import { useDateFormat } from "@/context/TimezoneContext";
import { useChatPanelState } from "./useChatPanelState";

interface ChatOverlayProps {
    isOpen: boolean;
    onClose: () => void;
    currentUserId?: string;
    initialActiveId?: string | null;
}

export function ChatOverlay({ isOpen, onClose, currentUserId, initialActiveId }: ChatOverlayProps) {
    const fmt = useDateFormat();
    const {
        contacts,
        activeContactId,
        messages,
        newMessage,
        viewMode,
        searchQuery,
        showDeleteConfirm,
        mobileView,
        isLoadingContacts,
        isLoadingMessages,
        isSending,
        showEmoji,
        messagesEndRef,
        textareaRef,
        filteredContacts,
        activeContact,
        setNewMessage,
        setViewMode,
        setSearchQuery,
        setShowDeleteConfirm,
        setMobileView,
        setShowEmoji,
        handleSend,
        handleDeleteConversation,
        selectContact,
        handleEmojiSelect,
        handleKeyDown,
    } = useChatPanelState({
        currentUserId,
        enabled: isOpen,
        initialActiveId,
    });

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm p-4 md:p-8 animate-in fade-in duration-200">
            <div
                className="w-full max-w-6xl h-[85vh] bg-card border border-border rounded-3xl overflow-hidden shadow-2xl flex flex-col md:flex-row ring-1 ring-border"
                style={{ backdropFilter: 'blur(20px)' }}
            >
                {/* Sidebar / Contact List */}
                <div className={`w-full md:w-80 border-r border-border flex flex-col bg-secondary ${mobileView === 'chat' ? 'hidden md:flex' : 'flex'}`}>
                    <div className="p-4 border-b border-border flex justify-between items-center">
                        <h2 className="text-lg font-bold text-foreground">Messages</h2>
                        <button onClick={onClose} className="md:hidden p-2 hover:bg-muted rounded-full text-muted-foreground">
                            <X className="w-5 h-5" />
                        </button>
                    </div>

                    <div className="p-4 pt-2 space-y-3">
                        <div className="relative">
                            <Search className="absolute left-3 top-2.5 w-4 h-4 text-muted-foreground" />
                            <input
                                type="text"
                                placeholder="Search..."
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                className="w-full bg-secondary border border-border rounded-xl py-2 pl-9 pr-4 text-sm text-foreground focus:outline-none focus:ring-2 focus:ring-primary/50 placeholder:text-muted-foreground"
                            />
                        </div>
                        <button
                            onClick={() => setViewMode(viewMode === 'chats' ? 'users' : 'chats')}
                            className="w-full py-2 bg-muted hover:bg-accent text-foreground rounded-xl text-sm font-medium transition flex items-center justify-center border border-border"
                        >
                            {viewMode === 'chats' ? (
                                <><MessageCircle className="w-4 h-4 mr-2" />New Message</>
                            ) : (
                                <><X className="w-4 h-4 mr-2" />Cancel Selection</>
                            )}
                        </button>
                    </div>

                    <div className="flex-1 overflow-y-auto px-2 space-y-1 custom-scrollbar">
                        {isLoadingContacts && contacts.length === 0 ? (
                            <>
                                <ContactSkeleton />
                                <ContactSkeleton />
                                <ContactSkeleton />
                                <ContactSkeleton />
                            </>
                        ) : viewMode === 'chats' ? (
                            filteredContacts.filter(c => c.lastMessage).length > 0 ? (
                                filteredContacts
                                    .filter(c => c.lastMessage)
                                    .map(contact => (
                                        <ContactItem
                                            key={contact.id}
                                            contact={contact}
                                            isActive={contact.id === activeContactId}
                                            onClick={() => selectContact(contact.id)}
                                            onDelete={async (contactId) => {
                                                await handleDeleteConversation(contactId);
                                            }}
                                        />
                                    ))
                            ) : (
                                <div className="text-center py-8 text-muted-foreground text-sm">
                                    <p>No active chats.</p>
                                    <p className="mt-1">Click &quot;New Message&quot; to start.</p>
                                </div>
                            )
                        ) : (
                            filteredContacts.map(contact => (
                                <ContactItem
                                    key={contact.id}
                                    contact={contact}
                                    isActive={contact.id === activeContactId}
                                    onClick={() => {
                                        selectContact(contact.id);
                                        setViewMode('chats');
                                    }}
                                />
                            ))
                        )}
                    </div>
                </div>

                {/* Main Chat Area */}
                <div className={`flex-1 flex flex-col bg-background ${mobileView === 'sidebar' ? 'hidden md:flex' : 'flex'}`}>
                    {activeContact ? (
                        <>
                            {/* Chat Header */}
                            <div className="p-4 border-b border-border flex justify-between items-center bg-card/50 backdrop-blur-md">
                                <div className="flex items-center">
                                    <button
                                        onClick={() => setMobileView('sidebar')}
                                        className="md:hidden p-1.5 rounded-lg hover:bg-muted transition text-muted-foreground hover:text-foreground mr-2"
                                    >
                                        <ArrowLeft className="w-4 h-4" />
                                    </button>
                                    <div className="relative">
                                        <img
                                            src={activeContact.avatar || "/placeholder-avatar.jpg"}
                                            alt={activeContact.name}
                                            className="w-10 h-10 rounded-full border border-border"
                                        />
                                        {activeContact.isOnline && (
                                            <div className="absolute bottom-0 right-0 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-card shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
                                        )}
                                    </div>
                                    <div className="ml-3">
                                        <h3 className="font-semibold text-foreground leading-tight">{activeContact.name}</h3>
                                        <div className="text-xs text-muted-foreground flex items-center">
                                            {activeContact.isOnline ? (
                                                <span className="text-green-500 font-medium">Online</span>
                                            ) : (
                                                <span>
                                                    {activeContact.lastActiveAt
                                                        ? fmt.presence(activeContact.lastActiveAt)
                                                        : (activeContact.jobTitle || activeContact.role)}
                                                </span>
                                            )}
                                        </div>
                                    </div>
                                </div>
                                <div className="flex items-center gap-2 text-muted-foreground">
                                    {showDeleteConfirm ? (
                                        <div className="flex items-center gap-1.5 bg-card border border-border shadow-lg rounded-xl px-3 py-1.5 text-xs">
                                            <span className="text-muted-foreground whitespace-nowrap">Delete chat?</span>
                                            <button
                                                onClick={() => { handleDeleteConversation(); setShowDeleteConfirm(false); }}
                                                className="flex items-center gap-1 px-2 py-1 bg-red-500 hover:bg-red-600 text-white rounded-lg transition text-xs font-medium"
                                            >
                                                Delete
                                            </button>
                                            <button
                                                onClick={() => setShowDeleteConfirm(false)}
                                                className="flex items-center gap-1 px-2 py-1 bg-muted hover:bg-muted/80 text-foreground rounded-lg transition text-xs font-medium"
                                            >
                                                Cancel
                                            </button>
                                        </div>
                                    ) : (
                                        <button
                                            onClick={() => setShowDeleteConfirm(true)}
                                            title="Delete conversation"
                                            className="p-2 hover:bg-red-500/10 hover:text-red-500 rounded-full transition"
                                        >
                                            <Trash2 className="w-5 h-5" />
                                        </button>
                                    )}
                                    <button onClick={onClose} className="p-2 hover:bg-muted rounded-full transition">
                                        <X className="w-5 h-5" />
                                    </button>
                                </div>
                            </div>

                            {/* Messages */}
                            <div className="flex-1 overflow-y-auto p-4 space-y-1 custom-scrollbar">
                                {isLoadingMessages && messages.length === 0 ? (
                                    <MessagesSkeleton />
                                ) : messages.length === 0 ? (
                                    <div className="h-full flex flex-col items-center justify-center text-muted-foreground opacity-50">
                                        <div className="w-16 h-16 bg-secondary rounded-full flex items-center justify-center mb-4 border border-border">
                                            <Send className="w-8 h-8 text-muted-foreground" />
                                        </div>
                                        <p className="font-medium">Start messaging with {activeContact.name}</p>
                                        <p className="text-xs mt-1">Send the first message to begin the conversation.</p>
                                    </div>
                                ) : (
                                    <MessagesList messages={messages} currentUserId={currentUserId || ''} />
                                )}
                                <div ref={messagesEndRef} />
                            </div>

                            {/* Input Area */}
                            <div className="p-4 bg-card border-t border-border">
                                <div className="relative bg-secondary border border-border rounded-2xl p-2 flex items-end gap-1 shadow-lg">
                                    {showEmoji && (
                                        <EmojiPicker
                                            onSelect={handleEmojiSelect}
                                            onClose={() => setShowEmoji(false)}
                                        />
                                    )}
                                    <button
                                        onClick={() => setShowEmoji(!showEmoji)}
                                        className={`p-2 rounded-lg transition ${showEmoji ? 'text-primary bg-primary/10' : 'text-muted-foreground hover:text-foreground hover:bg-muted'}`}
                                        title="Emoji"
                                    >
                                        <Smile className="w-5 h-5" />
                                    </button>
                                    <textarea
                                        ref={textareaRef}
                                        value={newMessage}
                                        onChange={(e) => setNewMessage(e.target.value)}
                                        onKeyDown={handleKeyDown}
                                        placeholder="Type a message..."
                                        rows={1}
                                        className="flex-1 bg-transparent border-none focus:outline-none text-foreground placeholder:text-muted-foreground px-2 py-1.5 resize-none max-h-[120px] text-sm"
                                    />
                                    <button
                                        onClick={handleSend}
                                        disabled={!newMessage.trim() || isSending}
                                        className="bg-primary hover:bg-primary/90 text-primary-foreground p-2 rounded-xl transition disabled:opacity-50 disabled:cursor-not-allowed shrink-0"
                                    >
                                        {isSending ? <Loader2 className="w-5 h-5 animate-spin" /> : <Send className="w-5 h-5" />}
                                    </button>
                                </div>
                                <p className="text-center text-[10px] text-muted-foreground/50 mt-1.5">Press Enter to send, Shift + Enter for new line</p>
                            </div>
                        </>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-muted-foreground relative">
                            <div className="absolute top-4 right-4">
                                <button
                                    onClick={onClose}
                                    className="p-2 hover:bg-muted rounded-full text-muted-foreground hover:text-foreground transition"
                                >
                                    <X className="w-5 h-5" />
                                </button>
                            </div>
                            <div className="w-20 h-20 bg-primary/10 rounded-3xl flex items-center justify-center mb-6 shadow-2xl border border-primary/20">
                                <MessageSquare className="w-10 h-10 text-primary" />
                            </div>
                            <h2 className="text-2xl font-bold text-foreground mb-2">Agency Messenger</h2>
                            <p className="max-w-md text-center text-muted-foreground">Select a contact from the list to start a conversation.</p>
                            <p className="text-xs text-muted-foreground/60 mt-4">Secure &bull; Private &bull; Real-time</p>
                        </div>
                    )}
                </div>
            </div>
        </div>
    );
}

"use client";

import { useEffect, useRef, useState, type KeyboardEvent } from "react";
import { Contact, Message, deleteConversation, getContacts, getMessages, markAsRead, sendMessage } from "@/lib/chat";
import { useActivePolling } from "@/hooks/use-active-polling";
import { toast } from "sonner";

type ChatViewMode = 'chats' | 'users';
type ChatMobileView = 'sidebar' | 'chat';

interface UseChatPanelStateOptions {
    currentUserId?: string;
    enabled?: boolean;
    initialActiveId?: string | null;
}

export function useChatPanelState({
    currentUserId,
    enabled = true,
    initialActiveId = null,
}: UseChatPanelStateOptions) {
    const [contacts, setContacts] = useState<Contact[]>([]);
    const [activeContactId, setActiveContactId] = useState<string | null>(null);
    const [messages, setMessages] = useState<Message[]>([]);
    const [newMessage, setNewMessage] = useState("");
    const [viewMode, setViewMode] = useState<ChatViewMode>('chats');
    const [searchQuery, setSearchQuery] = useState("");
    const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
    const [mobileView, setMobileView] = useState<ChatMobileView>('sidebar');
    const [isLoadingContacts, setIsLoadingContacts] = useState(true);
    const [isLoadingMessages, setIsLoadingMessages] = useState(false);
    const [isSending, setIsSending] = useState(false);
    const [isDeleting, setIsDeleting] = useState(false);
    const [showEmoji, setShowEmoji] = useState(false);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const textareaRef = useRef<HTMLTextAreaElement>(null);

    useEffect(() => {
        if (enabled && currentUserId) {
            void loadContacts();
        }
    }, [enabled, currentUserId]);

    useEffect(() => {
        if (enabled && initialActiveId) {
            setActiveContactId(initialActiveId);
            setMobileView('chat');
            setViewMode('chats');
        }
    }, [enabled, initialActiveId]);

    useEffect(() => {
        setShowDeleteConfirm(false);
    }, [activeContactId]);

    useActivePolling(() => {
        void loadContacts(true);
    }, 120000, enabled && !!currentUserId);

    useEffect(() => {
        if (enabled && currentUserId && activeContactId) {
            void loadMessages();
            void markAsRead(currentUserId, activeContactId);
        }
    }, [enabled, currentUserId, activeContactId]);

    useActivePolling(() => {
        void loadMessages(true);
    }, 10000, enabled && !!currentUserId && !!activeContactId);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [messages]);

    useEffect(() => {
        if (textareaRef.current) {
            textareaRef.current.style.height = 'auto';
            textareaRef.current.style.height = Math.min(textareaRef.current.scrollHeight, 120) + 'px';
        }
    }, [newMessage]);

    async function loadContacts(silent = false) {
        if (!currentUserId) return;
        if (!silent) setIsLoadingContacts(true);
        try {
            setContacts(await getContacts(currentUserId));
        } catch (error) {
            console.error("Failed to load contacts", error);
            if (!silent) toast.error("Failed to load conversations");
        } finally {
            setIsLoadingContacts(false);
        }
    }

    async function loadMessages(silent = false) {
        if (!currentUserId || !activeContactId) return;
        if (!silent) setIsLoadingMessages(true);
        try {
            setMessages(await getMessages(currentUserId, activeContactId));
        } catch (error) {
            console.error("Failed to load messages", error);
            if (!silent) toast.error("Failed to load messages");
        } finally {
            setIsLoadingMessages(false);
        }
    }

    async function handleSend() {
        if (!currentUserId || !activeContactId || !newMessage.trim() || isSending) return;
        const content = newMessage.trim();

        const optimisticMessage: Message = {
            id: "temp-" + Date.now(),
            senderId: currentUserId,
            receiverId: activeContactId,
            content,
            timestamp: new Date().toISOString(),
            read: false,
            type: 'text',
            agencyId: 'optimistic',
        };

        setMessages((prev) => [...prev, optimisticMessage]);
        setNewMessage("");
        setIsSending(true);
        setShowEmoji(false);

        try {
            await sendMessage(currentUserId, activeContactId, content);
            await loadMessages(true);
            await loadContacts(true);
        } catch (error) {
            console.error("Failed to send", error);
            toast.error("Failed to send message");
        } finally {
            setIsSending(false);
            textareaRef.current?.focus();
        }
    }

    async function handleDeleteConversation(contactId?: string) {
        const targetId = contactId || activeContactId;
        if (!currentUserId || !targetId || isDeleting) return;

        setIsDeleting(true);
        try {
            await deleteConversation(currentUserId, targetId);
            setMessages([]);
            if (targetId === activeContactId) {
                setActiveContactId(null);
                setMobileView('sidebar');
            }
            await loadContacts(true);
            setShowDeleteConfirm(false);
            toast.success("Conversation deleted");
        } catch (error) {
            console.error("Failed to delete conversation", error);
            toast.error("Failed to delete conversation");
        } finally {
            setIsDeleting(false);
        }
    }

    function selectContact(id: string) {
        setActiveContactId(id);
        setMobileView('chat');
    }

    function handleEmojiSelect(emoji: string) {
        setNewMessage((prev) => prev + emoji);
        textareaRef.current?.focus();
    }

    function handleKeyDown(e: KeyboardEvent<HTMLTextAreaElement>) {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            void handleSend();
        }
    }

    const filteredContacts = searchQuery.trim()
        ? contacts.filter((contact) =>
            contact.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
            contact.role?.toLowerCase().includes(searchQuery.toLowerCase())
        )
        : contacts;
    const activeContact = contacts.find((contact) => contact.id === activeContactId);

    return {
        contacts,
        activeContactId,
        messages,
        newMessage,
        viewMode,
        searchQuery,
        showDeleteConfirm,
        mobileView,
        isLoadingContacts,
        isLoadingMessages,
        isSending,
        showEmoji,
        messagesEndRef,
        textareaRef,
        filteredContacts,
        activeContact,
        setNewMessage,
        setViewMode,
        setSearchQuery,
        setShowDeleteConfirm,
        setMobileView,
        setShowEmoji,
        handleSend,
        handleDeleteConversation,
        selectContact,
        handleEmojiSelect,
        handleKeyDown,
    };
}

"use client";

import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, PieChart, Pie, Cell, Legend } from "recharts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useCurrency } from "@/context/CurrencyContext";

interface RevenueChartProps {
    data: any[];
}

export function RevenueChart({ data }: RevenueChartProps) {
    const { symbol } = useCurrency();
    return (
        <Card className="col-span-4">
            <CardHeader>
                <CardTitle>Revenue vs Expenses</CardTitle>
            </CardHeader>
            <CardContent className="pl-2">
                <div className="h-[250px] sm:h-[350px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <BarChart data={data}>
                            <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
                            <XAxis
                                dataKey="name"
                                stroke="#888888"
                                fontSize={12}
                                tickLine={false}
                                axisLine={false}
                            />
                            <YAxis
                                stroke="#888888"
                                fontSize={12}
                                tickLine={false}
                                axisLine={false}
                                tickFormatter={(value) => `${symbol}${value}`}
                            />
                            <Tooltip
                                cursor={{ fill: 'transparent' }}
                                contentStyle={{ backgroundColor: 'var(--card)', color: 'var(--card-foreground)', borderRadius: '8px', border: '1px solid var(--border)', boxShadow: '0 4px 12px rgba(0,0,0,0.3)' }}
                            />
                            <Bar dataKey="revenue" fill="#a78bfa" radius={[4, 4, 0, 0]} name="Revenue" />
                            <Bar dataKey="expenses" fill="#fb7185" radius={[4, 4, 0, 0]} name="Expenses" />
                        </BarChart>
                    </ResponsiveContainer>
                </div>
            </CardContent>
        </Card>
    );
}

const COLORS = ['#a78bfa', '#34d399', '#fbbf24', '#fb7185'];

export function ProjectDistributionChart({ data }: { data: any[] }) {
    return (
        <Card className="col-span-3">
            <CardHeader>
                <CardTitle>Project Distribution</CardTitle>
            </CardHeader>
            <CardContent>
                <div className="h-[250px] sm:h-[350px] w-full">
                    <ResponsiveContainer width="100%" height="100%">
                        <PieChart>
                            <Pie
                                data={data}
                                cx="50%"
                                cy="50%"
                                innerRadius={60}
                                outerRadius={80}
                                paddingAngle={5}
                                dataKey="value"
                            >
                                {data.map((entry, index) => (
                                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                ))}
                            </Pie>
                            <Tooltip />
                            <Legend />
                        </PieChart>
                    </ResponsiveContainer>
                </div>
            </CardContent>
        </Card>
    )
}

"use client";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { FileText, Image, Code, Link as LinkIcon, Download } from "lucide-react";
import { Asset } from "@/lib/types";
import { useDateFormat } from "@/context/TimezoneContext";

interface ClientAssetsSectionProps {
    assets: Asset[];
    projects: any[];
}

export function ClientAssetsSection({ assets, projects }: ClientAssetsSectionProps) {
    const fmt = useDateFormat();
    const recentAssets = assets
        .sort((a, b) => new Date(b.uploadedAt).getTime() - new Date(a.uploadedAt).getTime())
        .slice(0, 10);

    const assetsByType = {
        image: assets.filter(a => a.type === 'image').length,
        file: assets.filter(a => a.type === 'file').length,
        code: assets.filter(a => a.type === 'code').length,
        link: assets.filter(a => a.type === 'link').length,
        zip: assets.filter(a => a.type === 'zip').length,
        folder: assets.filter(a => a.type === 'folder').length
    };

    const getProjectName = (projectId: string) => {
        const project = projects.find(p => p.id === projectId);
        return project?.name || 'Unknown Project';
    };

    const getAssetIcon = (type: string) => {
        switch (type) {
            case 'image':
                return <Image className="h-4 w-4 text-purple-400" />;
            case 'code':
            case 'zip':
                return <Code className="h-4 w-4 text-blue-400" />;
            case 'link':
                return <LinkIcon className="h-4 w-4 text-green-400" />;
            default:
                return <FileText className="h-4 w-4 text-muted-foreground" />;
        }
    };

    return (
        <Card className="col-span-1 transition-all duration-300 hover:shadow-md">
            <CardHeader>
                <CardTitle>Documents & Assets</CardTitle>
            </CardHeader>
            <CardContent>
                {/* Asset Type Distribution */}
                <div className="grid grid-cols-3 gap-2 mb-6">
                    <div className="p-2 rounded-lg bg-purple-500/10 border border-purple-500/20 text-center">
                        <Image className="h-4 w-4 text-purple-400 mx-auto mb-1" />
                        <div className="text-lg font-bold">{assetsByType.image}</div>
                        <div className="text-xs text-muted-foreground">Images</div>
                    </div>
                    <div className="p-2 rounded-lg bg-muted/50 border border-border text-center">
                        <FileText className="h-4 w-4 text-muted-foreground mx-auto mb-1" />
                        <div className="text-lg font-bold">{assetsByType.file}</div>
                        <div className="text-xs text-muted-foreground">Files</div>
                    </div>
                    <div className="p-2 rounded-lg bg-blue-500/10 border border-blue-500/20 text-center">
                        <Code className="h-4 w-4 text-blue-400 mx-auto mb-1" />
                        <div className="text-lg font-bold">{assetsByType.code + assetsByType.zip}</div>
                        <div className="text-xs text-muted-foreground">Code</div>
                    </div>
                </div>

                {/* Recent Assets */}
                <div>
                    <h4 className="text-sm font-semibold mb-3 text-muted-foreground">Recent Uploads</h4>
                    <ScrollArea className="h-[300px]">
                        <div className="space-y-2">
                            {recentAssets.length === 0 ? (
                                <div className="text-center py-8 text-muted-foreground">
                                    No assets uploaded yet
                                </div>
                            ) : (
                                recentAssets.map((asset) => (
                                    <div
                                        key={asset.id}
                                        className="flex items-center gap-3 p-3 rounded-lg border bg-card hover:bg-accent/50 transition group"
                                    >
                                        <div className="flex-shrink-0">
                                            {getAssetIcon(asset.type)}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <p className="text-sm font-medium truncate">{asset.name}</p>
                                            <p className="text-xs text-muted-foreground truncate">
                                                {getProjectName(asset.projectId)}
                                            </p>
                                            <p className="text-xs text-muted-foreground mt-1">
                                                {asset.size} • {fmt.date(asset.uploadedAt)}
                                            </p>
                                        </div>
                                        <a
                                            href={asset.url}
                                            download
                                            target="_blank"
                                            rel="noopener noreferrer"
                                            className="flex-shrink-0 opacity-100 md:opacity-0 md:group-hover:opacity-100 transition p-2 hover:bg-white/10 rounded"
                                            title="Download"
                                        >
                                            <Download className="h-4 w-4" />
                                        </a>
                                    </div>
                                ))
                            )}
                        </div>
                    </ScrollArea>
                </div>

                {/* Total Count */}
                <div className="mt-4 pt-4 border-t border-border">
                    <div className="flex items-center justify-between text-sm">
                        <span className="text-muted-foreground">Total Assets</span>
                        <span className="font-semibold">{assets.length}</span>
                    </div>
                </div>
            </CardContent>
        </Card>
    );
}

"use client";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { FolderKanban, CreditCard, MessageSquare, CheckCircle2, Wallet } from "lucide-react";
import { Project, Notification, Transaction, Task, Invoice, Asset } from "@/lib/types";
import { ClientProjectsList } from "./ClientProjectsList";
import { ClientNotificationsList } from "./ClientNotificationsList";
import { ClientFinancialOverview } from "./ClientFinancialOverview";
import { ClientTaskOverview } from "./ClientTaskOverview";
import { ClientAssetsSection } from "./ClientAssetsSection";
import { useDateFormat } from "@/context/TimezoneContext";
import { useCurrency } from "@/context/CurrencyContext";
import Link from "next/link";


interface ClientDashboardProps {
    initialProjects: Project[];
    initialNotifications: Notification[];
    clientName: string;
    clientId: string;
    metrics: {
        activeProjects: number;
        completedProjects: number;
        pendingInvoicesCount: number;
        totalDue: number;
        unreadNotificationsCount: number;
        totalSpent: number;
        totalBudget: number;
        totalTasks: number;
        completedTasks: number;
    };
    transactions?: Transaction[];
    tasks?: Task[];
    invoices?: Invoice[];
    assets?: Asset[];
}

export function ClientDashboard({
    initialProjects,
    initialNotifications,
    clientName,
    clientId,
    metrics,
    transactions = [],
    tasks = [],
    invoices = [],
    assets = []
}: ClientDashboardProps) {
    const fmt = useDateFormat();
    const { format: formatMoney } = useCurrency();
    // Next invoice due date
    const pendingInvoices = invoices
        .filter(i => i.status === 'Pending' || i.status === 'Overdue')
        .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());
    const nextInvoiceDue = pendingInvoices[0]?.date
        ? fmt.dateShort(pendingInvoices[0].date)
        : null;

    // Per-project progress
    const projectProgress = initialProjects.map(p => {
        const pTasks = tasks.filter(t => t.projectId === p.id);
        const done = pTasks.filter(t => t.status === 'Done').length;
        const total = pTasks.length;
        const pct = total > 0 ? Math.round((done / total) * 100) : 0;
        return { id: p.id, name: p.name, slug: (p as any).slug || p.id, pct, done, total };
    }).filter(p => p.total > 0).slice(0, 3);

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Welcome Banner */}
            <div className="relative overflow-hidden rounded-3xl bg-gradient-to-r from-indigo-900 to-purple-900 p-8 text-white shadow-2xl">
                <div className="relative z-10">
                    <h1 className="text-3xl font-bold mb-2">Welcome back, {clientName}</h1>
                    <p className="text-indigo-200">Here&#39;s what&#39;s happening with your projects today.</p>
                </div>
                {/* Abstract Shapes */}
                <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full blur-3xl -translate-y-1/2 translate-x-1/2"></div>
                <div className="absolute bottom-0 left-0 w-48 h-48 bg-purple-500/20 rounded-full blur-2xl translate-y-1/2 -translate-x-1/2"></div>
            </div>

            {/* Enhanced Quick Stats Grid */}
            <div className="grid gap-4 grid-cols-2 md:grid-cols-5">
                <Link href="/dashboard/projects" className="block">
                    <Card className="hover:border-indigo-500/50 transition-colors cursor-pointer h-full">
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground">Active Projects</CardTitle>
                            <FolderKanban className="h-4 w-4 text-indigo-500" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{metrics.activeProjects}</div>
                            <p className="text-xs text-muted-foreground">In progress</p>
                        </CardContent>
                    </Card>
                </Link>

                <Link href="/dashboard/projects" className="block">
                    <Card className="hover:border-emerald-500/50 transition-colors cursor-pointer h-full">
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground">Completed</CardTitle>
                            <CheckCircle2 className="h-4 w-4 text-emerald-500" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{metrics.completedProjects}</div>
                            <p className="text-xs text-muted-foreground">Projects done</p>
                        </CardContent>
                    </Card>
                </Link>

                <Link href="/dashboard/finance?tab=invoices" className="block">
                    <Card className="hover:border-amber-500/50 transition-colors cursor-pointer h-full">
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground">Pending Invoices</CardTitle>
                            <CreditCard className="h-4 w-4 text-amber-500" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{metrics.pendingInvoicesCount}</div>
                            <p className="text-xs text-muted-foreground">
                                {metrics.totalDue > 0 ? formatMoney(metrics.totalDue) : "All paid!"}
                            </p>
                            {nextInvoiceDue && (
                                <p className="text-xs text-amber-500 mt-1">Next due: {nextInvoiceDue}</p>
                            )}
                        </CardContent>
                    </Card>
                </Link>

                <Link href="/dashboard/finance?tab=history" className="block">
                    <Card className="hover:border-blue-500/50 transition-colors cursor-pointer h-full">
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium text-muted-foreground">Total Spent</CardTitle>
                            <Wallet className="h-4 w-4 text-blue-500" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">{formatMoney(metrics.totalSpent)}</div>
                            <p className="text-xs text-muted-foreground">Payments made</p>
                        </CardContent>
                    </Card>
                </Link>

                <Card className="hover:border-blue-500/50 transition-colors">
                    <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                        <CardTitle className="text-sm font-medium text-muted-foreground">Notifications</CardTitle>
                        <MessageSquare className="h-4 w-4 text-blue-500" />
                    </CardHeader>
                    <CardContent>
                        <div className="text-2xl font-bold">{metrics.unreadNotificationsCount}</div>
                        <p className="text-xs text-muted-foreground">Unread updates</p>
                    </CardContent>
                </Card>
            </div>

            {/* Project Progress Bars */}
            {projectProgress.length > 0 && (
                <div className="rounded-lg border bg-card p-4 space-y-3">
                    <p className="text-sm font-semibold text-muted-foreground">Project Progress</p>
                    {projectProgress.map(p => (
                        <Link key={p.id} href={`/dashboard/projects/${p.slug}`} className="block group">
                            <div className="space-y-1">
                                <div className="flex justify-between text-xs">
                                    <span className="font-medium truncate group-hover:text-indigo-400 transition-colors">{p.name}</span>
                                    <span className="text-muted-foreground ml-2 shrink-0">{p.done}/{p.total} tasks · {p.pct}%</span>
                                </div>
                                <div className="h-1.5 w-full rounded-full bg-muted overflow-hidden">
                                    <div
                                        className={`h-full rounded-full transition-all duration-500 ${p.pct === 100 ? 'bg-emerald-500' : p.pct >= 50 ? 'bg-indigo-500' : 'bg-amber-500'
                                            }`}
                                        style={{ width: `${p.pct}%` }}
                                    />
                                </div>
                            </div>
                        </Link>
                    ))}
                </div>
            )}

            {/* Financial & Task Overview */}
            <div className="grid gap-6 grid-cols-1 lg:grid-cols-3">
                <ClientFinancialOverview
                    transactions={transactions}
                    totalSpent={metrics.totalSpent}
                    totalBudget={metrics.totalBudget}
                    pendingAmount={metrics.totalDue}
                />
                <ClientAssetsSection assets={assets} projects={initialProjects} />
            </div>

            {/* Task Overview */}
            <ClientTaskOverview tasks={tasks} projects={initialProjects} />

            {/* Projects & Notifications */}
            <div className="grid gap-6 md:grid-cols-2">
                <ClientProjectsList initialProjects={initialProjects} />
                <ClientNotificationsList initialNotifications={initialNotifications} userId={clientId} />
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useInView } from "react-intersection-observer";
import { getNotifications } from "@/lib/actions";
import { Loader2, Activity } from "lucide-react";
import { Notification } from "@/lib/types";
import { useDateFormat } from "@/context/TimezoneContext";
import { toast } from "sonner";

interface ClientNotificationsListProps {
    initialNotifications: Notification[];
    userId: string;
}

export function ClientNotificationsList({ initialNotifications, userId }: ClientNotificationsListProps) {
    const fmt = useDateFormat();
    const [notifications, setNotifications] = useState<Notification[]>(initialNotifications);
    const [offset, setOffset] = useState(initialNotifications.length);
    const [hasMore, setHasMore] = useState(initialNotifications.length >= 5);
    const [loading, setLoading] = useState(false);
    const { ref, inView } = useInView();

    const loadMore = async () => {
        if (loading || !hasMore) return;
        setLoading(true);
        try {
            const newNotifications = await getNotifications(userId, offset, 5);
            if (newNotifications.length < 5) {
                setHasMore(false);
            }
            setNotifications((prev) => [...prev, ...newNotifications]);
            setOffset((prev) => prev + 5);
        } catch (error) {
            console.error("Failed to load more notifications", error);
            toast.error("Failed to load more notifications");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (inView) {
            loadMore();
        }
    }, [inView]);

    return (
        <Card className="col-span-1 h-full transition-all duration-300 hover:shadow-md">
            <CardHeader>
                <CardTitle>Recent Updates</CardTitle>
            </CardHeader>
            <CardContent>
                <ScrollArea
                    className="h-[300px] group pr-4"
                    scrollBarClassName="opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                >
                    {notifications.length === 0 ? (
                        <div className="text-center py-8 text-muted-foreground">No new notifications.</div>
                    ) : (
                        <div className="space-y-4">
                            {notifications.map((n, i) => (
                                <div key={i} className="flex gap-4 items-start p-3 rounded-lg hover:bg-muted/50 transition">
                                    <div className="bg-indigo-500/10 p-2 rounded-full mt-1">
                                        <Activity className="w-4 h-4 text-indigo-400" />
                                    </div>
                                    <div>
                                        <p className="text-sm text-foreground">{n.message}</p>
                                        <p className="text-xs text-muted-foreground mt-1">
                                            {fmt.date(n.timestamp)}
                                        </p>
                                    </div>
                                </div>
                            ))}
                            {hasMore && (
                                <div ref={ref} className="flex justify-center p-4">
                                    <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                                </div>
                            )}
                        </div>
                    )}
                </ScrollArea>
            </CardContent>
        </Card>
    );
}

"use client";

import { useState, useEffect } from "react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useInView } from "react-intersection-observer";
import { getProjects } from "@/lib/actions";
import { Loader2 } from "lucide-react";
import Link from "next/link";
import { Project } from "@/lib/types";
import { toast } from "sonner";

interface ClientProjectsListProps {
    initialProjects: Project[];
}

export function ClientProjectsList({ initialProjects }: ClientProjectsListProps) {
    const [projects, setProjects] = useState<Project[]>(initialProjects);
    const [offset, setOffset] = useState(initialProjects.length);
    const [hasMore, setHasMore] = useState(initialProjects.length >= 5);
    const [loading, setLoading] = useState(false);
    const { ref, inView } = useInView();

    const loadMore = async () => {
        if (loading || !hasMore) return;
        setLoading(true);
        try {
            // Note: getProjects checks for client role internally via CurrentUser, but here we call it from client side?
            // Actually Server Actions calleed from Client Components run on Server, so `getCurrentUser()` inside `getProjects` will work 
            // and identify the user correctly as the logged in client.
            const newProjects = await getProjects(offset, 5);
            if (newProjects.length < 5) {
                setHasMore(false);
            }
            setProjects((prev) => [...prev, ...newProjects]);
            setOffset((prev) => prev + 5);
        } catch (error) {
            console.error("Failed to load more projects", error);
            toast.error("Failed to load more projects");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (inView) {
            loadMore();
        }
    }, [inView]);

    return (
        <Card className="col-span-1 h-full transition-all duration-300 hover:shadow-md">
            <CardHeader>
                <CardTitle>Your Projects</CardTitle>
            </CardHeader>
            <CardContent>
                <ScrollArea
                    className="h-[300px] group pr-4"
                    scrollBarClassName="opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                >
                    {projects.length === 0 ? (
                        <div className="text-center py-8 text-muted-foreground">No active projects.</div>
                    ) : (
                        <div className="space-y-4">
                            {projects.map(project => (
                                <Link key={project.id} href={`/dashboard/projects/${project.slug || project.id}`}>
                                    <div className="flex items-center justify-between p-4 rounded-xl border bg-card hover:bg-accent/50 transition-colors cursor-pointer group/item">
                                        <div>
                                            <h3 className="font-semibold group-hover/item:text-indigo-400 transition-colors">{project.name}</h3>
                                            <div className="flex gap-2 text-xs text-muted-foreground mt-1">
                                                {project.services.slice(0, 2).map(s => <span key={s}>{s}</span>)}
                                            </div>
                                        </div>
                                        <div className={`px-2 py-1 rounded-full text-xs font-medium ${project.status === 'Active' ? 'bg-green-500/10 text-green-500' :
                                            project.status === 'Completed' ? 'bg-blue-500/10 text-blue-500' :
                                                'bg-muted text-muted-foreground'
                                            }`}>
                                            {project.status}
                                        </div>
                                    </div>
                                </Link>
                            ))}
                            {hasMore && (
                                <div ref={ref} className="flex justify-center p-4">
                                    <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                                </div>
                            )}
                        </div>
                    )}
                </ScrollArea>
            </CardContent>
        </Card>
    );
}

"use client";

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ScrollArea } from "@/components/ui/scroll-area";
import { CheckCircle2, Clock, AlertCircle, Calendar } from "lucide-react";
import { Task } from "@/lib/types";
import { useDateFormat } from "@/context/TimezoneContext";
import { toLocalCalendarDay } from "@/lib/date-utils";
import Link from "next/link";

interface ClientTaskOverviewProps {
    tasks: Task[];
    projects: any[];
}

export function ClientTaskOverview({ tasks, projects }: ClientTaskOverviewProps) {
    const fmt = useDateFormat();
    const todoTasks = tasks.filter(t => t.status === 'Todo').length;
    const inProgressTasks = tasks.filter(t => t.status === 'In Progress').length;
    const reviewTasks = tasks.filter(t => t.status === 'Review').length;
    const doneTasks = tasks.filter(t => t.status === 'Done').length;
    const today = toLocalCalendarDay(fmt.dateKey(new Date())) ?? new Date();

    // Get tasks requiring client review
    const tasksForReview = tasks.filter(t => t.status === 'Review').slice(0, 5);

    // Get upcoming deadlines
    const upcomingTasks = tasks
        .filter(t => {
            if (t.status === 'Done' || !t.dueDate) return false;
            const dueDate = toLocalCalendarDay(fmt.dateKey(t.dueDate));
            if (!dueDate) return false;
            return dueDate >= today;
        })
        .sort((a, b) => fmt.dateKey(a.dueDate!).localeCompare(fmt.dateKey(b.dueDate!)))
        .slice(0, 5);

    const getProjectName = (projectId: string) => {
        const project = projects.find(p => p.id === projectId);
        return project?.name || 'Unknown Project';
    };

    const getProjectSlug = (projectId: string) => {
        const project = projects.find(p => p.id === projectId);
        return project?.slug || project?.id || '';
    };

    return (
        <Card className="col-span-1 md:col-span-2 transition-all duration-300 hover:shadow-md">
            <CardHeader>
                <CardTitle>Task Overview</CardTitle>
            </CardHeader>
            <CardContent>
                {/* Task Statistics */}
                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 mb-6">
                    <div className="p-3 rounded-lg bg-muted/50 border border-border">
                        <div className="flex items-center gap-2 mb-1">
                            <Clock className="h-3 w-3 text-muted-foreground" />
                            <span className="text-xs text-muted-foreground">To Do</span>
                        </div>
                        <div className="text-xl font-bold">{todoTasks}</div>
                    </div>

                    <div className="p-3 rounded-lg bg-blue-500/10 border border-blue-500/20">
                        <div className="flex items-center gap-2 mb-1">
                            <AlertCircle className="h-3 w-3 text-blue-400" />
                            <span className="text-xs text-muted-foreground">In Progress</span>
                        </div>
                        <div className="text-xl font-bold text-blue-400">{inProgressTasks}</div>
                    </div>

                    <div className="p-3 rounded-lg bg-amber-500/10 border border-amber-500/20">
                        <div className="flex items-center gap-2 mb-1">
                            <Calendar className="h-3 w-3 text-amber-400" />
                            <span className="text-xs text-muted-foreground">Review</span>
                        </div>
                        <div className="text-xl font-bold text-amber-400">{reviewTasks}</div>
                    </div>

                    <div className="p-3 rounded-lg bg-emerald-500/10 border border-emerald-500/20">
                        <div className="flex items-center gap-2 mb-1">
                            <CheckCircle2 className="h-3 w-3 text-emerald-400" />
                            <span className="text-xs text-muted-foreground">Done</span>
                        </div>
                        <div className="text-xl font-bold text-emerald-400">{doneTasks}</div>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {/* Tasks for Review */}
                    <div>
                        <h4 className="text-sm font-semibold mb-3 text-muted-foreground">
                            Awaiting Your Review ({reviewTasks})
                        </h4>
                        <ScrollArea className="h-[180px]">
                            <div className="space-y-2">
                                {tasksForReview.length === 0 ? (
                                    <div className="text-center py-8 text-muted-foreground text-sm">
                                        No tasks awaiting review
                                    </div>
                                ) : (
                                    tasksForReview.map((task) => (
                                        <Link
                                            key={task.id}
                                            href={`/dashboard/projects/${getProjectSlug(task.projectId)}`}
                                        >
                                            <div className="p-3 rounded-lg border bg-card hover:bg-accent/50 transition cursor-pointer">
                                                <p className="text-sm font-medium">{task.title}</p>
                                                <p className="text-xs text-muted-foreground mt-1">
                                                    {getProjectName(task.projectId)}
                                                </p>
                                            </div>
                                        </Link>
                                    ))
                                )}
                            </div>
                        </ScrollArea>
                    </div>

                    {/* Upcoming Deadlines */}
                    <div>
                        <h4 className="text-sm font-semibold mb-3 text-muted-foreground">
                            Upcoming Deadlines
                        </h4>
                        <ScrollArea className="h-[180px]">
                            <div className="space-y-2">
                                {upcomingTasks.length === 0 ? (
                                    <div className="text-center py-8 text-muted-foreground text-sm">
                                        No upcoming deadlines
                                    </div>
                                ) : (
                                    upcomingTasks.map((task) => (
                                        <Link
                                            key={task.id}
                                            href={`/dashboard/projects/${getProjectSlug(task.projectId)}`}
                                        >
                                            <div className="p-3 rounded-lg border bg-card hover:bg-accent/50 transition cursor-pointer">
                                                <div className="flex items-start justify-between">
                                                    <div className="flex-1">
                                                        <p className="text-sm font-medium">{task.title}</p>
                                                        <p className="text-xs text-muted-foreground mt-1">
                                                            {getProjectName(task.projectId)}
                                                        </p>
                                                    </div>
                                                    <div className="text-xs text-amber-400 ml-2">
                                                        {task.dueDate ? fmt.date(task.dueDate) : ''}
                                                    </div>
                                                </div>
                                            </div>
                                        </Link>
                                    ))
                                )}
                            </div>
                        </ScrollArea>
                    </div>
                </div>
            </CardContent>
        </Card>
    );
}

import { Task, User } from "@/lib/types";
import { dateKeyTz, fmtDateShort, getLocaleForTimezone, toLocalCalendarDay } from "@/lib/date-utils";
import { getDashboardMetrics, getRevenueData, getProjectDistribution, getRecentActivity, getUrgentTasks, getClientDashboardData, getEmployeeDashboardData } from "@/lib/actions";

import { MetricCard } from "@/components/dashboard/MetricCard";
import { RevenueChart, ProjectDistributionChart } from "@/components/dashboard/Charts";
import { RecentActivityList } from "@/components/dashboard/RecentActivityList";
import { UrgentTasksList } from "@/components/dashboard/UrgentTasksList";
import { EmployeeTasksList } from "@/components/dashboard/EmployeeTasksList";
import { Banknote, Briefcase, FileText, Activity as ActivityIcon, CheckCircle2, Clock, Users, Calendar } from "lucide-react";
import { formatCurrency } from "@/lib/currency";
import { getDefaultCurrency } from "@/lib/actions/super-admin";
import { ClientDashboard } from "@/components/dashboard/ClientDashboard";
import { ExportReportButton } from "@/components/dashboard/ExportReportButton";
import Link from "next/link";

export async function DashboardContent({ currentUser }: { currentUser: User }) {
    // Client Dashboard View
    if (currentUser.role === 'client') {
        const data = await getClientDashboardData(currentUser.id);

        return (
            <ClientDashboard
                initialProjects={data.projects}
                initialNotifications={data.notifications}
                clientName={currentUser.name}
                clientId={currentUser.id}
                metrics={data.metrics}
                transactions={data.transactions}
                tasks={data.tasks}
                invoices={data.invoices}
                assets={data.assets}
            />
        );
    }

    // Admin/Employee Dashboard View
    const isAdmin = currentUser.role === 'admin' || currentUser.role === 'manager';
    const userId = currentUser.id;

    if (isAdmin) {
        // Parallel Fetch for Admin
        const [metrics, revenueData, projectDist, activities, urgentTasks, currency] = await Promise.all([
            getDashboardMetrics(),
            getRevenueData(),
            getProjectDistribution(),
            getRecentActivity(),
            getUrgentTasks(),
            getDefaultCurrency()
        ]);

        return (
            <div className="flex-1 space-y-4">
                <div className="flex flex-col sm:flex-row sm:items-center justify-between space-y-4 sm:space-y-0">
                    <div>
                        <h2 className="text-2xl sm:text-3xl font-bold tracking-tight">Overview</h2>
                        <p className="text-muted-foreground hidden sm:block">Welcome back, {currentUser.name}</p>
                    </div>
                    <div className="flex items-center gap-2">
                        <div className="hidden md:flex h-9 items-center rounded-md border border-input bg-transparent px-3 py-1 text-sm shadow-sm whitespace-nowrap">
                            <span className="text-muted-foreground">{fmtDateShort(new Date(new Date().getFullYear(), new Date().getMonth(), 1), currentUser.timezone || 'UTC', getLocaleForTimezone(currentUser.timezone || 'UTC'))} — {fmtDateShort(new Date(new Date().getFullYear(), new Date().getMonth() + 1, 0), currentUser.timezone || 'UTC', getLocaleForTimezone(currentUser.timezone || 'UTC'))}</span>
                        </div>
                        <ExportReportButton />
                    </div>
                </div>

                <div className="grid gap-4 grid-cols-1 sm:grid-cols-2 lg:grid-cols-4">
                    <MetricCard
                        title="Total Revenue"
                        value={formatCurrency(metrics?.revenue, currency)}
                        description={`${(metrics?.growth ?? 0) > 0 ? '+' : ''}${metrics?.growth ?? 0}% from last month`}
                        icon={Banknote}
                        trend={(metrics?.growth ?? 0) > 0 ? 'up' : (metrics?.growth ?? 0) < 0 ? 'down' : 'neutral'}
                        href="/dashboard/finance?tab=overview"
                    />
                    <MetricCard
                        title="Active Projects"
                        value={metrics?.activeProjects ?? 0}
                        description={`High priority: ${metrics?.highPriorityCount ?? 0}`}
                        icon={Briefcase}
                        href="/dashboard/projects"
                    />
                    <MetricCard
                        title="Pending Invoices"
                        value={formatCurrency(metrics?.pending, currency)}
                        description={`${metrics?.overdueCount ?? 0} invoices overdue`}
                        icon={FileText}
                        href="/dashboard/finance?tab=invoices"
                    />
                    <MetricCard
                        title="Team Members"
                        value={`${metrics?.assignedMembers ?? 0}/${metrics?.totalMembers ?? 0}`}
                        description="Members assigned right now"
                        icon={Users}
                        href="/dashboard/team"
                    />
                </div>

                {/* Pending Leave Requests Alert */}
                {(metrics?.pendingLeaveCount ?? 0) > 0 && (
                    <Link href="/dashboard/team" className="block">
                        <div className="flex items-center gap-3 rounded-lg border border-amber-500/30 bg-amber-500/5 px-4 py-3 hover:bg-amber-500/10 transition-colors">
                            <Calendar className="h-4 w-4 text-amber-500 shrink-0" />
                            <p className="text-sm text-amber-600 dark:text-amber-400 font-medium">
                                {metrics?.pendingLeaveCount} leave request{(metrics?.pendingLeaveCount ?? 0) > 1 ? 's' : ''} pending approval
                            </p>
                            <span className="ml-auto text-xs text-amber-500 hover:underline">Review ?</span>
                        </div>
                    </Link>
                )}

                <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-7">
                    <RevenueChart data={revenueData || []} />
                    <ProjectDistributionChart data={projectDist || []} />
                </div>

                <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-7">
                    <UrgentTasksList initialTasks={urgentTasks || []} />
                    <RecentActivityList initialActivities={activities || []} />
                </div>
            </div>
        );
    }


    // EMPLOYEE VIEW
    const data = await getEmployeeDashboardData(userId);
    const myTasks = data.tasks;
    const myProjects = data.projects;
    const myLeaves = data.leaveRequests ?? [];

    // Upcoming deadlines: tasks not done, due within next 3 days
    const userTimezone = currentUser.timezone || 'UTC';
    const now = toLocalCalendarDay(dateKeyTz(new Date(), userTimezone)) ?? new Date();
    const threeDaysLater = new Date(now);
    threeDaysLater.setDate(now.getDate() + 3);

    const upcomingDeadlines = myTasks
        .filter((t: Task) => {
            if (t.status === 'Done') return false;
            const dueValue = (t as any).dueDate;
            if (!dueValue) return false;
            const due = toLocalCalendarDay(dateKeyTz(dueValue, userTimezone));
            if (!due) return false;
            return due >= now && due <= threeDaysLater;
        })
        .sort((a: Task, b: Task) => {
            const aKey = (a as any).dueDate ? dateKeyTz((a as any).dueDate, userTimezone) : '9999-12-31';
            const bKey = (b as any).dueDate ? dateKeyTz((b as any).dueDate, userTimezone) : '9999-12-31';
            return aKey.localeCompare(bKey);
        })
        .slice(0, 3);

    // Most recent leave request for status card
    const latestLeave = myLeaves[0];
    const pendingLeave = myLeaves.find((l: any) => l.status === 'Pending');

    return (
        <div className="flex-1 space-y-4">
            <div className="flex flex-col space-y-2">
                <h2 className="text-2xl sm:text-3xl font-bold tracking-tight">My Dashboard</h2>
                <p className="text-muted-foreground">Welcome back, {currentUser.name}</p>
            </div>

            <div className="grid gap-4 grid-cols-2 sm:grid-cols-3 lg:grid-cols-5">
                <MetricCard
                    title="Active Tasks"
                    value={myTasks?.filter((t: Task) => t.status === 'In Progress').length || 0}
                    description="Currently in progress"
                    icon={ActivityIcon}
                    href="/dashboard/projects"
                />
                <MetricCard
                    title="Pending Tasks"
                    value={myTasks?.filter((t: Task) => t.status === 'Todo').length || 0}
                    description="Waiting for you"
                    icon={Clock}
                    href="/dashboard/projects"
                />
                <MetricCard
                    title="Done This Week"
                    value={myTasks?.filter((t: Task) => {
                        if (t.status !== 'Done') return false;
                        const weekAgo = new Date();
                        weekAgo.setDate(weekAgo.getDate() - 7);
                        return new Date(t.updatedAt || t.createdAt || 0) >= weekAgo;
                    }).length || 0}
                    description="Completed this week"
                    icon={CheckCircle2}
                    href="/dashboard/projects"
                />
                <MetricCard
                    title="My Projects"
                    value={myProjects?.length || 0}
                    description="Projects involved in"
                    icon={Briefcase}
                    href="/dashboard/projects"
                />
                {/* Leave Status Card */}
                <Link href="/dashboard/team" className="col-span-1 block">
                    <div className={`h-full rounded-lg border p-4 hover:border-primary/50 transition-colors cursor-pointer ${pendingLeave ? 'border-amber-500/40 bg-amber-500/5' :
                        latestLeave?.status === 'Approved' ? 'border-emerald-500/40 bg-emerald-500/5' :
                            latestLeave?.status === 'Rejected' ? 'border-red-500/40 bg-red-500/5' :
                                'border-border'
                        }`}>
                        <p className="text-xs font-medium text-muted-foreground mb-1">My Leave</p>
                        {latestLeave ? (
                            <>
                                <p className={`text-lg font-bold ${latestLeave.status === 'Pending' ? 'text-amber-500' :
                                    latestLeave.status === 'Approved' ? 'text-emerald-500' : 'text-red-500'
                                    }`}>{latestLeave.status}</p>
                                <p className="text-xs text-muted-foreground truncate mt-0.5">{(latestLeave as any).leaveType || 'Leave'}</p>
                            </>
                        ) : (
                            <>
                                <p className="text-lg font-bold">None</p>
                                <p className="text-xs text-muted-foreground">No requests</p>
                            </>
                        )}
                    </div>
                </Link>
            </div>

            {/* Upcoming Deadlines Alert */}
            {upcomingDeadlines.length > 0 && (
                <div className="rounded-lg border border-red-500/20 bg-red-500/5 px-4 py-3 space-y-2">
                    <p className="text-xs font-semibold text-red-500 uppercase tracking-wide">? Deadlines in the next 3 days</p>
                    <div className="flex flex-wrap gap-2">
                        {upcomingDeadlines.map((t: Task) => {
                            const due = toLocalCalendarDay(dateKeyTz((t as any).dueDate, userTimezone));
                            const daysLeft = due ? Math.round((due.getTime() - now.getTime()) / (1000 * 60 * 60 * 24)) : 0;
                            const project = myProjects.find((p: any) => p.id === (t as any).projectId);
                            return (
                                <Link
                                    key={t.id}
                                    href={`/dashboard/projects/${(project as any)?.slug || (t as any).projectId}?task=${t.id}`}
                                    className="flex items-center gap-2 rounded-md border border-red-500/20 bg-background px-3 py-1.5 text-xs hover:bg-muted transition-colors"
                                >
                                    <span className="font-medium truncate max-w-[150px]">{t.title}</span>
                                    <span className={`shrink-0 font-semibold ${daysLeft === 0 ? 'text-red-500' : 'text-amber-500'}`}>
                                        {daysLeft === 0 ? 'Today' : `${daysLeft}d`}
                                    </span>
                                </Link>
                            );
                        })}
                    </div>
                </div>
            )}

            <div className="grid gap-4 grid-cols-1 md:grid-cols-3">
                {/* My Active Tasks List */}
                <div className="col-span-2">
                    <EmployeeTasksList
                        initialTasks={myTasks?.filter((t: Task) => t.status === 'In Progress' || t.status === 'Todo').slice(0, 5) || []}
                        userId={userId}
                        allProjects={myProjects}
                    />
                </div>

                {/* My Recent Activity */}
                <div className="col-span-1">
                    <RecentActivityList initialActivities={data.activities?.slice(0, 5) || []} />
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useInView } from "react-intersection-observer";
import { getUserTasks } from "@/lib/actions";
import { Loader2, Calendar } from "lucide-react";
import { useDateFormat } from "@/context/TimezoneContext";
import Link from 'next/link';
import { Project } from "@/lib/types";
import { toast } from "sonner";

interface Task {
    id: string;
    title: string;
    dueDate: string;
    status: string;
    priority?: string;
    projectId: string;
}

interface EmployeeTasksListProps {
    initialTasks: Task[];
    userId: string;
    allProjects: Project[];
}

export function EmployeeTasksList({ initialTasks, userId, allProjects }: EmployeeTasksListProps) {
    const fmt = useDateFormat();
    const [tasks, setTasks] = useState<Task[]>(initialTasks);
    const [offset, setOffset] = useState(initialTasks.length);
    const [hasMore, setHasMore] = useState(initialTasks.length >= 5);
    const [loading, setLoading] = useState(false);
    const { ref, inView } = useInView();

    const loadMore = async () => {
        if (loading || !hasMore) return;
        setLoading(true);
        try {
            const newTasks = await getUserTasks(userId, offset, 5);
            if (newTasks.length < 5) {
                setHasMore(false);
            }
            // Filter out tasks already in 'tasks' to avoid duplicates if any weirdness
            const newUniqueTasks = newTasks.filter(nt => !tasks.some(t => t.id === nt.id));
            setTasks((prev) => [...prev, ...newUniqueTasks]);
            setOffset((prev) => prev + 5);
        } catch (error) {
            console.error("Failed to load more employee tasks", error);
            toast.error("Failed to load more tasks");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (inView) {
            loadMore();
        }
    }, [inView]);

    const activeTasks = tasks.filter(t => t.status === 'In Progress' || t.status === 'Todo');

    return (
        <Card className="h-full transition-all duration-300 hover:shadow-md">
            <CardHeader>
                <CardTitle>My Active Tasks</CardTitle>
            </CardHeader>
            <CardContent>
                <ScrollArea
                    className="h-[300px] group pr-4"
                    scrollBarClassName="opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                >
                    <div className="space-y-4">
                        {activeTasks.length === 0 && (
                            <div className="text-center py-8 text-muted-foreground">
                                No active tasks assigned.
                            </div>
                        )}
                        {activeTasks.map((task) => {
                            const project = allProjects.find((p) => p.id === task.projectId);
                            const projectSlug = project?.slug || task.projectId;
                            return (
                                <Link key={task.id} href={`/dashboard/projects/${projectSlug}?task=${task.id}`} className="flex items-center p-3 rounded-lg hover:bg-muted/50 transition border border-transparent hover:border-border cursor-pointer">
                                    <div className={`w-2 h-2 rounded-full mr-4 ${task.status === 'In Progress' ? 'bg-amber-500' : 'bg-slate-500'}`} />
                                    <div className="flex-1 space-y-1">
                                        <p className="text-sm font-medium leading-none text-foreground">{task.title}</p>
                                        <p className="text-xs text-muted-foreground flex items-center gap-1">
                                            <Calendar className="w-3 h-3 text-yellow-500" /> Due {fmt.date(task.dueDate)}
                                        </p>
                                    </div>
                                    <div className={`px-2 py-1 rounded text-xs font-medium ${task.priority === 'High' ? 'bg-red-500/10 text-red-500' : 'bg-slate-500/10 text-slate-500'}`}>
                                        {task.priority || 'Normal'}
                                    </div>
                                </Link>
                            );
                        })}
                        {hasMore && (
                            <div ref={ref} className="flex justify-center p-4">
                                <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                            </div>
                        )}
                    </div>
                </ScrollArea>
            </CardContent>
        </Card>
    );
}

"use client";

import { useState, useEffect } from "react";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { useInView } from "react-intersection-observer";
import { getRecentActivity } from "@/lib/actions";
import { Loader2, ArrowUpRight } from "lucide-react";
import { useDateFormat } from "@/context/TimezoneContext";
import { Activity } from "@/lib/types";
import Link from "next/link";
import { toast } from "sonner";

interface RecentActivityListProps {
    initialActivities: Activity[];
}

function buildActivityLink(activity: Activity): string | null {
    // Use structured entityId/entityType if available (future activities)
    if (activity.entityId && activity.entityType) {
        switch (activity.entityType) {
            case 'task': return `/dashboard/projects/${activity.entityId}`;
            case 'project': return `/dashboard/projects/${activity.entityId}`;
            case 'invoice': return `/dashboard/finance`;
            case 'client': return `/dashboard/clients`;
            case 'user': return `/dashboard/team`;
        }
    }

    // Fallback: infer from action text for existing records
    const action = activity.action.toLowerCase();
    if (action.includes('task') || action.includes('assigned') || action.includes('completed')) {
        return `/dashboard/projects`;
    }
    if (action.includes('invoice') || action.includes('payment') || action.includes('transaction')) {
        return `/dashboard/finance`;
    }
    if (action.includes('project') || action.includes('created project')) {
        return `/dashboard/projects`;
    }
    if (action.includes('client')) {
        return `/dashboard/clients`;
    }
    if (action.includes('team') || action.includes('user') || action.includes('employee')) {
        return `/dashboard/team`;
    }
    return null;
}

export function RecentActivityList({ initialActivities }: RecentActivityListProps) {
    const fmt = useDateFormat();
    const [activities, setActivities] = useState<Activity[]>(initialActivities);
    const [offset, setOffset] = useState(initialActivities.length);
    const [hasMore, setHasMore] = useState(initialActivities.length >= 5);
    const [loading, setLoading] = useState(false);
    const { ref, inView } = useInView();

    const loadMore = async () => {
        if (loading || !hasMore) return;
        setLoading(true);
        try {
            const newActivities = await getRecentActivity(offset, 5);
            if (newActivities.length < 5) {
                setHasMore(false);
            }
            setActivities((prev) => [...prev, ...newActivities]);
            setOffset((prev) => prev + 5);
        } catch (error) {
            console.error("Failed to load more activities", error);
            toast.error("Failed to load more activity");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (inView) {
            loadMore();
        }
    }, [inView]);

    return (
        <Card className="col-span-3 transition-all duration-300 hover:shadow-md">
            <CardHeader>
                <CardTitle>Recent Activity</CardTitle>
                <CardDescription>
                    Latest actions performed by your team
                </CardDescription>
            </CardHeader>
            <CardContent>
                <ScrollArea
                    className="h-[300px] group pr-4"
                    scrollBarClassName="opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                >
                    <div className="space-y-8">
                        {activities.length === 0 && <p className="text-sm text-muted-foreground">No recent activity.</p>}

                        {activities.map((activity) => {
                            const link = buildActivityLink(activity);
                            const content = (
                                <div className={`flex items-center gap-2 rounded-lg p-1 -m-1 transition-colors ${link ? 'hover:bg-muted/40 cursor-pointer group/row' : ''}`}>
                                    <Avatar className="h-9 w-9 shrink-0">
                                        <AvatarFallback className="bg-indigo-500/20 text-indigo-400 font-medium">
                                            {activity.user.charAt(0)}
                                        </AvatarFallback>
                                    </Avatar>
                                    <div className="ml-2 space-y-1 flex-1 min-w-0">
                                        <p className="text-sm font-medium leading-none">
                                            <span className="font-bold text-foreground">{activity.user}</span>{" "}
                                            {activity.action}{" "}
                                            <span className="font-semibold text-foreground">{activity.target}</span>
                                        </p>
                                        <p className="text-xs text-muted-foreground">
                                            {fmt.date(activity.timestamp)}
                                        </p>
                                    </div>
                                    {link && (
                                        <ArrowUpRight className="h-3.5 w-3.5 text-muted-foreground opacity-0 group-hover/row:opacity-100 transition-opacity shrink-0" />
                                    )}
                                </div>
                            );

                            return (
                                <div key={activity.id}>
                                    {link ? (
                                        <Link href={link} className="block">
                                            {content}
                                        </Link>
                                    ) : content}
                                </div>
                            );
                        })}
                        {hasMore && (
                            <div ref={ref} className="flex justify-center p-4">
                                <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                            </div>
                        )}
                    </div>
                </ScrollArea>
            </CardContent>
        </Card>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { differenceInCalendarDays } from "date-fns";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { useInView } from "react-intersection-observer";
import { getHighPriorityTasks } from "@/lib/actions";
import { Loader2, AlertCircle } from "lucide-react";
import Link from "next/link";
import { toLocalCalendarDay } from "@/lib/date-utils";
import { toast } from "sonner";

interface Task {
    id: string;
    title: string;
    dueDate: string;
    status: string;
    projectId: string;
    projectName: string;
    projectSlug: string;
}

interface UrgentTasksListProps {
    initialTasks: Task[];
}

export function UrgentTasksList({ initialTasks }: UrgentTasksListProps) {
    const [tasks, setTasks] = useState<Task[]>(initialTasks);
    const [offset, setOffset] = useState(initialTasks.length);
    const [hasMore, setHasMore] = useState(initialTasks.length >= 5);
    const [loading, setLoading] = useState(false);
    const { ref, inView } = useInView();
    const loadingRef = useRef(false);

    const loadMore = async () => {
        if (loading || !hasMore || loadingRef.current) return;
        loadingRef.current = true;
        setLoading(true);
        try {
            const newTasks = await getHighPriorityTasks(offset, 5);
            if (newTasks.length < 5) setHasMore(false);
            setTasks((prev) => {
                const existingIds = new Set(prev.map((t) => t.id));
                return [...prev, ...newTasks.filter((t: Task) => !existingIds.has(t.id))];
            });
            setOffset((prev) => prev + newTasks.length);
        } catch (error) {
            console.error("Failed to load more urgent tasks", error);
            toast.error("Failed to load more urgent tasks");
        } finally {
            setLoading(false);
            loadingRef.current = false;
        }
    };

    useEffect(() => {
        if (inView) loadMore();
    }, [inView]);

    const today = toLocalCalendarDay(new Date());

    return (
        <Card className="col-span-4 transition-all duration-300 hover:shadow-md">
            <CardHeader className="flex flex-row items-center justify-between">
                <CardTitle>Urgent Tasks</CardTitle>
                <span className="text-xs text-amber-500 font-medium bg-amber-500/10 px-2 py-1 rounded-full">
                    High Priority
                </span>
            </CardHeader>
            <CardContent>
                <ScrollArea
                    className="h-[300px] group pr-4"
                    scrollBarClassName="opacity-0 group-hover:opacity-100 transition-opacity duration-300"
                >
                    <div className="space-y-3">
                        {tasks.length === 0 && (
                            <p className="text-sm text-muted-foreground text-center py-8">?? No urgent tasks right now</p>
                        )}
                        {tasks.map((task) => {
                            const due = toLocalCalendarDay(task.dueDate);
                            const daysUntilDue = due && today ? differenceInCalendarDays(due, today) : null;
                            const isOverdue = daysUntilDue !== null && daysUntilDue < 0;
                            const isDueSoon = daysUntilDue !== null && daysUntilDue >= 0 && daysUntilDue <= 2;

                            return (
                                <Link
                                    key={task.id}
                                    href={`/dashboard/projects/${task.projectSlug}?task=${task.id}`}
                                    className="flex items-start gap-3 p-2 rounded-lg hover:bg-muted/50 transition-colors border border-transparent hover:border-border cursor-pointer block"
                                >
                                    {(isOverdue || isDueSoon) && (
                                        <AlertCircle className={`h-4 w-4 mt-0.5 shrink-0 ${isOverdue ? 'text-red-500' : 'text-amber-500'}`} />
                                    )}
                                    {!isOverdue && !isDueSoon && (
                                        <div className="h-4 w-4 mt-0.5 shrink-0 rounded-full border-2 border-muted-foreground/30" />
                                    )}
                                    <div className="flex-1 min-w-0">
                                        <p className="text-sm font-medium leading-none truncate">{task.title}</p>
                                        <p className="text-xs text-muted-foreground mt-1 truncate">
                                            <span className="text-indigo-400">{task.projectName}</span>
                                        </p>
                                        <p className={`text-xs mt-0.5 font-medium ${isOverdue ? 'text-red-400' : isDueSoon ? 'text-amber-400' : 'text-muted-foreground'}`}>
                                            {daysUntilDue === null
                                                ? 'No due date'
                                                : isOverdue
                                                ? `Overdue by ${Math.abs(daysUntilDue)}d`
                                                : daysUntilDue === 0
                                                    ? 'Due today'
                                                    : daysUntilDue === 1
                                                        ? 'Due tomorrow'
                                                        : `Due in ${daysUntilDue}d`}
                                        </p>
                                    </div>
                                    <div className={`ml-auto font-medium text-xs px-2 py-1 rounded-full shrink-0 ${task.status === 'In Progress' ? 'bg-amber-500/15 text-amber-400' : 'bg-muted text-muted-foreground'}`}>
                                        {task.status}
                                    </div>
                                </Link>
                            );
                        })}
                        {hasMore && (
                            <div ref={ref} className="flex justify-center p-4">
                                <Loader2 className="h-4 w-4 animate-spin text-muted-foreground" />
                            </div>
                        )}
                    </div>
                </ScrollArea>
            </CardContent>
        </Card>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogDescription, DialogFooter, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { createTransaction, getUsers } from "@/lib/actions";
import { Plus, Lock } from "lucide-react";
import { useRouter } from "next/navigation";
import { TransactionCategory, TransactionType, User, Project, TRANSACTION_CATEGORIES } from "@/lib/types";
import { toast } from "sonner";
import { DateTimeInput } from "@/components/ui/DateTimeInput";
import { useCurrency } from "@/context/CurrencyContext";

// Categories shown when inside a specific project
const PROJECT_SCOPED_CATEGORIES: TransactionCategory[] = ["Project", "Refund", "Freelancer", "Retainer"];

interface AddTransactionModalProps {
    projectId?: string;
    projectName?: string;
    users?: User[];
    projects?: Project[];
}

export function AddTransactionModal({ projectId, projectName, users = [], projects = [] }: AddTransactionModalProps) {
    const isProjectScoped = !!projectId;
    const { format: formatMoney } = useCurrency();
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [availableUsers, setAvailableUsers] = useState<User[]>(users);
    const router = useRouter();

    // Main Category State
    const [selectedCategory, setSelectedCategory] = useState<TransactionCategory>("Project");

    // Form States
    const [formData, setFormData] = useState({
        description: "",
        amount: "",
        type: "expense" as TransactionType,
        date: new Date().toISOString().split('T')[0],
        projectId: projectId || "",
        memberId: "",
        // Employee Specific
        baseSalary: 0,
        bonus: "",
        deduction: "",
        // Internal Transfer Specific
        transferDirection: "to_member" as "to_member" | "from_member",
        status: "completed" as "completed" | "pending",
        // Tax Specific
        taxType: "" as string,
        // Reimbursement Specific
        expenseType: "" as string
    });

    // Validation Errors
    const [errors, setErrors] = useState<Record<string, string>>({});

    // Auto-calculate amount for Employee category
    useEffect(() => {
        if (selectedCategory === "Salary") {
            const base = formData.baseSalary || 0;
            const bonus = parseFloat(formData.bonus) || 0;
            const deduction = parseFloat(formData.deduction) || 0;
            const total = base + bonus - deduction;
            setFormData(prev => ({ ...prev, amount: total > 0 ? total.toString() : "0" }));
        }
    }, [formData.baseSalary, formData.bonus, formData.deduction, selectedCategory]);

    useEffect(() => {
        setAvailableUsers(users);
    }, [users]);

    useEffect(() => {
        if (!open || !isProjectScoped) return;

        let cancelled = false;
        getUsers()
            .then((loadedUsers) => {
                if (!cancelled) {
                    setAvailableUsers(loadedUsers);
                }
            })
            .catch((error) => {
                console.error("Failed to load users for project transaction modal", error);
            });

        return () => {
            cancelled = true;
        };
    }, [open, isProjectScoped]);

    const handleCategoryChange = (val: string) => {
        const cat = val as TransactionCategory;
        if (cat === selectedCategory) return;
        setSelectedCategory(cat);
        // In project-scoped mode, always keep the projectId locked
        const lockedProjectId = isProjectScoped ? projectId! : "";
        if (cat === "Salary") {
            setFormData(prev => ({ ...prev, type: "expense", projectId: lockedProjectId, description: "" }));
        } else if (cat === "Refund") {
            setFormData(prev => ({ ...prev, type: "expense", projectId: projectId || prev.projectId || "", description: "" }));
        } else if (cat === "Internal Transfer") {
            setFormData(prev => ({ ...prev, type: "expense", projectId: lockedProjectId, transferDirection: "to_member", description: "" }));
        } else if (cat === "Investor") {
            setFormData(prev => ({ ...prev, type: "income", projectId: lockedProjectId, description: "" }));
        } else if (cat === "Freelancer") {
            setFormData(prev => ({ ...prev, type: "expense", projectId: projectId || prev.projectId || "", description: "", memberId: "" }));
        } else if (cat === "Tax") {
            setFormData(prev => ({ ...prev, type: "expense", projectId: lockedProjectId, description: "", taxType: "" }));
        } else if (cat === "Reimbursement") {
            setFormData(prev => ({ ...prev, type: "expense", projectId: lockedProjectId, description: "", memberId: "", expenseType: "" }));
        } else if (cat === "Retainer") {
            const autoDesc = isProjectScoped && projectName
                ? `Monthly Retainer - ${projectName} - ${new Date().toLocaleString('default', { month: 'long', year: 'numeric' })}`
                : "";
            setFormData(prev => ({ ...prev, type: "income", projectId: projectId || prev.projectId || "", description: autoDesc }));
        } else if (cat === "Project") {
            setFormData(prev => ({ ...prev, projectId: projectId || prev.projectId || "", description: "" }));
        } else {
            setFormData(prev => ({ ...prev, type: "expense", projectId: lockedProjectId, description: "" }));
        }
    };

    const handleMemberChange = (memberId: string) => {
        const member = availableUsers.find(u => u.id === memberId);
        if (member) {
            setFormData(prev => ({
                ...prev,
                memberId,
                baseSalary: member.salary || 0,
                // Auto-generate description for Employee
                description: selectedCategory === "Salary"
                    ? `Salary Payment - ${new Date().toLocaleString('default', { month: 'long', year: 'numeric' })} - ${member.name}`
                    : prev.description
            }));

            // For Internal Transfer, we update description dynamically too
            if (selectedCategory === "Internal Transfer") {
                updateTransferDescription(member.name, formData.transferDirection);
            }
        }
    };

    const updateTransferDescription = (memberName: string, direction: "to_member" | "from_member") => {
        const desc = direction === "to_member"
            ? `Transfer to ${memberName}`
            : `Transfer from ${memberName}`;
        setFormData(prev => ({ ...prev, description: desc }));
    }

    const handleDirectionChange = (val: "to_member" | "from_member") => {
        const member = availableUsers.find(u => u.id === formData.memberId);
        setFormData(prev => ({
            ...prev,
            transferDirection: val,
            type: val === "to_member" ? "expense" : "income"
        }));
        if (member) {
            updateTransferDescription(member.name, val);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setErrors({}); // Reset errors

        try {
            // STRICT VALIDATION
            const newErrors: Record<string, string> = {};
            let hasError = false;

            if (selectedCategory === "Project" && !formData.projectId) {
                newErrors.projectId = "Please select a Project.";
                hasError = true;
            }
            if (selectedCategory === "Refund" && !formData.projectId) {
                newErrors.projectId = "Refunds must be linked to a Project.";
                hasError = true;
            }
            if (selectedCategory === "Salary" && !formData.memberId) {
                newErrors.memberId = "Please select an Employee.";
                hasError = true;
            }
            if (selectedCategory === "Internal Transfer" && !formData.memberId) {
                newErrors.memberId = "Please select an Employee for the transfer.";
                hasError = true;
            }

            if (hasError) {
                setErrors(newErrors);
                setLoading(false);
                return;
            }

            // Map UI Category to DB Category & Enforce Types
            let dbCategory: TransactionCategory = "Other";
            let dbType: TransactionType = formData.type; // Default to user selection

            if (selectedCategory === "Project") {
                dbCategory = "Project";
                // Type comes from user selection (Income/Expense)
            }
            else if (selectedCategory === "Refund") {
                dbCategory = "Refund";
                dbType = "expense"; // STRICT: Refunds are always expense
            }
            else if (selectedCategory === "Salary") {
                dbCategory = "Salary";
                dbType = "expense"; // STRICT: Salary is always expense
            }
            else if (selectedCategory === "Internal Transfer") {
                dbCategory = "Internal Transfer";
                // Type is handled by handleDirectionChange (to_member=expense, from_member=income)
                // But let's double check logic here isn't overridden
                if (formData.transferDirection === "to_member") dbType = "expense";
                else dbType = "income";
            }
            else if (selectedCategory === "Investor") {
                dbCategory = "Investor";
                dbType = "income"; // STRICT: Investors are always income
            }
            else if (selectedCategory === "Freelancer") {
                dbCategory = "Freelancer";
                dbType = "expense";
            }
            else if (selectedCategory === "Tax") {
                dbCategory = "Tax";
                dbType = "expense";
            }
            else if (selectedCategory === "Reimbursement") {
                dbCategory = "Reimbursement";
                dbType = "expense";
            }
            else if (selectedCategory === "Retainer") {
                dbCategory = "Retainer";
                dbType = "income";
            }
            else {
                dbCategory = selectedCategory;
                dbType = "expense";
            }

            await createTransaction({
                description: formData.description,
                amount: parseFloat(formData.amount),
                type: dbType, // Use enforced type
                category: dbCategory,
                date: formData.date,
                projectId: formData.projectId || undefined,

                userId: formData.memberId || undefined,
                status: formData.status,
                taxType: formData.taxType ? formData.taxType as any : undefined,
                expenseType: formData.expenseType ? formData.expenseType as any : undefined
            });
            toast.success("Transaction created successfully");
            setOpen(false);
            // Reset form
            setFormData({
                description: "",
                amount: "",
                type: "expense",
                date: new Date().toISOString().split('T')[0],
                projectId: projectId || "",
                memberId: "",
                baseSalary: 0,
                bonus: "",
                deduction: "",

                transferDirection: "to_member",
                status: "completed",
                taxType: "",
                expenseType: ""
            });
            router.refresh();
        } catch (error) {
            console.error("Failed to create transaction", error);
            toast.error("Failed to create transaction");
            setErrors(prev => ({ ...prev, global: "Failed to create transaction. Please try again." }));
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={setOpen}>
            <DialogTrigger asChild>
                <Button>
                    <Plus className="mr-2 h-4 w-4" />
                    Add Transaction
                </Button>
            </DialogTrigger>
            <DialogContent className="max-w-[95vw] sm:max-w-[600px] max-h-[85dvh] overflow-y-auto">
                <form onSubmit={handleSubmit}>
                    <DialogHeader>
                        <DialogTitle>
                            {isProjectScoped ? `Add Transaction — ${projectName || 'Project'}` : 'Add Transaction'}
                        </DialogTitle>
                        <DialogDescription>
                            {isProjectScoped
                                ? 'Create a transaction for this project.'
                                : 'Create a new transaction record.'
                            }
                        </DialogDescription>
                    </DialogHeader>

                    <div className="grid gap-4 py-4">
                        {/* 1. Category Selection */}
                        <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                            <Label className="sm:text-right">Category</Label>
                            <Select value={selectedCategory} onValueChange={handleCategoryChange}>
                                <SelectTrigger className="col-span-3">
                                    <SelectValue placeholder="Select Category" />
                                </SelectTrigger>
                                <SelectContent>
                                    {(isProjectScoped ? PROJECT_SCOPED_CATEGORIES : TRANSACTION_CATEGORIES).map(cat => (
                                        <SelectItem key={cat} value={cat}>
                                            {cat === 'Salary' ? 'Salary (Employee)' : cat}
                                        </SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                        </div>

                        {/* 2. Dynamic Fields based on Category */}

                        {/* --- PROJECT CATEGORY --- */}
                        {selectedCategory === "Project" && (
                            <>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Project</Label>
                                    {isProjectScoped ? (
                                        <div className="col-span-3 flex items-center gap-2 h-10 px-3 rounded-md border border-input bg-muted/50">
                                            <Lock className="w-3.5 h-3.5 text-muted-foreground" />
                                            <span className="text-sm">{projectName || 'Current Project'}</span>
                                        </div>
                                    ) : (
                                        <Select
                                            value={formData.projectId}
                                            onValueChange={(val) => setFormData(prev => ({ ...prev, projectId: val }))}
                                        >
                                            <SelectTrigger className="col-span-3">
                                                <SelectValue placeholder="Select Project" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="" disabled>Select Project</SelectItem>
                                                {projects.map(p => (
                                                    <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    )}
                                    {errors.projectId && <p className="col-span-4 text-right text-xs text-red-500">{errors.projectId}</p>}
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Payment Direction</Label>
                                    <Select
                                        value={formData.type === "income" ? "client_to_company" : "company_to_client"}
                                        onValueChange={(val) => setFormData(prev => ({ ...prev, type: val === "client_to_company" ? "income" : "expense" }))}
                                    >
                                        <SelectTrigger className="col-span-3">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="client_to_company">Client to Company (Income)</SelectItem>
                                            <SelectItem value="company_to_client">Company to Client (Expense/Refund)</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Description</Label>
                                    <Input
                                        value={formData.description}
                                        onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                                        className="col-span-3"
                                        placeholder="e.g. Milestone Payment"
                                        required
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Amount</Label>
                                    <Input
                                        type="number"
                                        min="1"
                                        value={formData.amount}
                                        onChange={(e) => setFormData(prev => ({ ...prev, amount: e.target.value }))}
                                        className="col-span-3"
                                        required
                                    />
                                </div>
                            </>
                        )}

                        {/* --- REFUND CATEGORY --- */}
                        {selectedCategory === "Refund" && (
                            <>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Project</Label>
                                    {isProjectScoped ? (
                                        <div className="col-span-3 flex items-center gap-2 h-10 px-3 rounded-md border border-input bg-muted/50">
                                            <Lock className="w-3.5 h-3.5 text-muted-foreground" />
                                            <span className="text-sm">{projectName || 'Current Project'}</span>
                                        </div>
                                    ) : (
                                        <Select
                                            value={formData.projectId}
                                            onValueChange={(val) => setFormData(prev => ({ ...prev, projectId: val }))}
                                        >
                                            <SelectTrigger className="col-span-3">
                                                <SelectValue placeholder="Select Project" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                <SelectItem value="" disabled>Select Project</SelectItem>
                                                {projects.map(p => (
                                                    <SelectItem key={p.id} value={p.id}>{p.name}</SelectItem>
                                                ))}
                                            </SelectContent>
                                        </Select>
                                    )}
                                    {errors.projectId && <p className="col-span-4 text-right text-xs text-red-500">{errors.projectId}</p>}
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Refund Reason</Label>
                                    <Input
                                        value={formData.description}
                                        onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                                        className="col-span-3"
                                        placeholder="e.g. Partial refund for delayed delivery"
                                        required
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Refund Amount</Label>
                                    <Input
                                        type="number"
                                        min="1"
                                        value={formData.amount}
                                        onChange={(e) => setFormData(prev => ({ ...prev, amount: e.target.value }))}
                                        className="col-span-3"
                                        required
                                    />
                                </div>
                                <div className="text-sm text-muted-foreground bg-amber-50 dark:bg-amber-950 p-3 rounded-md border border-amber-200 dark:border-amber-800">
                                    <p className="font-medium text-amber-900 dark:text-amber-100">Note:</p>
                                    <p className="text-amber-800 dark:text-amber-200">This refund will reduce total revenue on admin dashboard and reduce client's total spent.</p>
                                </div>
                            </>
                        )}

                        {/* --- EMPLOYEE CATEGORY --- */}
                        {selectedCategory === "Salary" && (
                            <>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Employee</Label>
                                    <Select value={formData.memberId} onValueChange={handleMemberChange}>
                                        <SelectTrigger className="col-span-3">
                                            <SelectValue placeholder="Select Employee" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="" disabled>Select Employee</SelectItem>
                                            {availableUsers.map(u => (
                                                <SelectItem key={u.id} value={u.id}>{u.name}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                    {errors.memberId && <p className="col-span-4 text-right text-xs text-red-500">{errors.memberId}</p>}
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Base Salary</Label>
                                    <Input
                                        type="number"
                                        value={formData.baseSalary}
                                        disabled
                                        className="col-span-3 bg-muted"
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Bonus (+)</Label>
                                    <Input
                                        type="number"
                                        value={formData.bonus}
                                        placeholder="0"
                                        onChange={(e) => setFormData(prev => ({ ...prev, bonus: e.target.value }))}
                                        className="col-span-3"
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Deduction (-)</Label>
                                    <Input
                                        type="number"
                                        value={formData.deduction}
                                        placeholder="0"
                                        onChange={(e) => setFormData(prev => ({ ...prev, deduction: e.target.value }))}
                                        className="col-span-3"
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right font-bold">Total Pay</Label>
                                    <Input
                                        type="number"
                                        min="1"
                                        value={formData.amount}
                                        disabled
                                        className="col-span-3 font-bold"
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Description</Label>
                                    <Input
                                        value={formData.description}
                                        onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                                        className="col-span-3"
                                        required
                                    />
                                </div>
                            </>
                        )}

                        {/* --- INTERNAL TRANSFER CATEGORY --- */}
                        {selectedCategory === "Internal Transfer" && (
                            <>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Direction</Label>
                                    <Select
                                        value={formData.transferDirection}
                                        onValueChange={(val: any) => handleDirectionChange(val)}
                                    >
                                        <SelectTrigger className="col-span-3">
                                            <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="to_member">Company to Employee (Expense)</SelectItem>
                                            <SelectItem value="from_member">Employee to Company (Income)</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Employee</Label>
                                    <Select value={formData.memberId} onValueChange={handleMemberChange}>
                                        <SelectTrigger className="col-span-3">
                                            <SelectValue placeholder="Select Employee" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="" disabled>Select Employee</SelectItem>
                                            {availableUsers.map(u => (
                                                <SelectItem key={u.id} value={u.id}>{u.name}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                    {errors.memberId && <p className="col-span-4 text-right text-xs text-red-500">{errors.memberId}</p>}
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Amount</Label>
                                    <Input
                                        type="number"
                                        min="1"
                                        value={formData.amount}
                                        onChange={(e) => setFormData(prev => ({ ...prev, amount: e.target.value }))}
                                        className="col-span-3"
                                        required
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Description</Label>
                                    <Input
                                        value={formData.description}
                                        onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                                        className="col-span-3"
                                        required
                                    />
                                </div>
                            </>
                        )}
                        {/* --- INVESTOR CATEGORY --- */}
                        {selectedCategory === "Investor" && (
                            <>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Investor / Source</Label>
                                    <Input
                                        value={formData.description}
                                        onChange={(e) => setFormData(prev => ({ ...prev, description: e.target.value }))}
                                        className="col-span-3"
                                        placeholder="e.g. Investor Name or Funding Source"
                                        required
                                    />
                                </div>
                                <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                    <Label className="sm:text-right">Amount</Label>
                                    <Input
                                        type="number"
                                        min="1"
                                        value={formData.amount}
                                        onChange={(e) => setFormData(prev => ({ ...prev, amount: e.target.value }))}
                                        className="col-span-3"
                                        required
                                    />
                                </div>
                                <div className="text-sm text-muted-foreground bg-emerald-50 dark:bg-emerald-950 p-3 rounded-md border border-emerald-200 dark:border-emerald-800">
                                    <p className="font-medium text-emerald-900 dark:text-emerald-100">Note:</p>
                                    <p className="text-emerald-800 dark:text-emerald-200">This will be recorded as Income (investment into the company).</p>
                                </div>
                            </>
                        )}

                        {/* --- FREELANCER CATEGORY --- */}
                        {selectedCategory === "Freelancer" && (() => {
                            const freelancers = availableUsers.filter(u => u.employmentType === 'Freelancer');
                            return (
                                <>
                                    <div className="grid grid-cols-1 sm:grid-cols-4 items-start sm:items-center gap-2 sm:gap-4">
                                        <Label className="sm:text-right">Freelancer</Label>
                                        {freelancers.length > 0 ? (
                                            <Select
                                                value={formData.memberId || "none"}
                                                onValueChange={(val) => {
                                                    if (val === "none") {
                                                        setFormData(prev => ({ ...prev, memberId: "", description: "", amount: "" }));
                                                        return;
                                                    }
                                                    const member = freelancers.find(u => u.id === val);
                                                    if (member) {
                                                        setFormData(prev => ({
                                                            ...prev,
                                                            memberId: member.id,
                                                            description: `Freelancer Payment - ${member.name}`,
                                                            amount: member.salary ? member.salary.toString() : prev.amount,
                                                        }));
                                                    }
                                                }}
                                            >
                                                <SelectTrigger className="col-span-3">
                                                    <SelectValue placeholder="Select Freelancer" />
                                                </SelectTrigger>
                                                <SelectContent>
                                                    <SelectItem value="none">Select Freelancer</SelectItem>
                                                    {freelancers.map(u => (
                                                        <SelectItem key={u.id} value={u.id}>
                                                            {u.name} {u.jobTitle ? `(${u.jobTitle})` : ''} {u.salary ? `- ${formatMoney(u.salary)}` : ''}
                                                        </SelectItem>
                                                    ))}
                                                </SelectContent>
                                            </Select>
                                        ) : (
                                            <div className="col-span-3 text-sm text-muted-foreground bg-muted p-3 rounded-md">
                                                No freelancers found. Add team members with &quot;Freelancer&quot; employment type in Settings ? Team.
                                            </div>
                                        )}
                                    </div>
                                    {formData.memberId && (
                                        <>
