          </span>
        </Link>

        {/* Desktop Links */}
        <ul className="hidden md:flex space-x-14 text-xl font-glacial-bold tracking-wide">
          <li>
            <Link
              href="/"
              className={`transition-all duration-200 ${isActive("/") ? "text-[#F5EE30]" : "hover:text-[#F5EE30]"
                }`}
            >
              HOME
