                      }`}
                  >
                    {service.name}
                  </Link>
                ))}
              </div>
            </div>

          </li>
          <li>
            <Link
              href="/about"
              className={`transition-all duration-200 ${isActive("/about") ? "text-[#F5EE30]" : "hover:text-[#F5EE30]"
                }`}
            >
              ABOUT US
            </Link>
