          <li>
            <Link
              href={isLoggedIn ? "/dashboard" : "/login"}
              className={`transition-all duration-200 ${isActive("/login") || isActive("/dashboard") ? "text-[#F5EE30]" : "hover:text-[#F5EE30]"
                }`}
