        {/* Slide-in Panel */}
        <div className="absolute top-0 right-0 w-4/5 max-w-sm h-full bg-black shadow-[-5px_0_15px_rgba(0,0,0,0.5)] p-8 flex flex-col">
          {/* Close Icon */}
          <button
