              {/* Dropdown Menu */}
              <div
                className={`overflow-hidden transition-all duration-300 ${mobileServicesOpen ? "max-h-96" : "max-h-0"
                  }`}
              >
                <div className="pl-4 space-y-2 py-2">
                  {servicesList.map((service) => (
                    <Link
                      key={service.href}
                      href={service.href}
                      className={`block py-2 text-lg ${isActive(service.href)
                        ? "text-[#F5EE30]"
                        : "hover:text-[#F5EE30]"
                        }`}
                      onClick={() => setMobileOpen(false)}
                    >
                      {service.name}
                    </Link>
                  ))}
                </div>
              </div>
            </div>

            <Link
              href="/about"
              className={`block py-2 border-b border-white/10 ${isActive("/about") ? "text-[#F5EE30]" : "hover:text-[#F5EE30]"
                }`}
              onClick={() => setMobileOpen(false)}
            >
              ABOUT US
            </Link>
            <Link
              href={isLoggedIn ? "/dashboard" : "/login"}
              className="block py-2 text-[#F5EE30] border-b border-white/10"
              onClick={() => setMobileOpen(false)}
            >
              {isLoggedIn ? "DASHBOARD" : "LOGIN"}
            </Link>
            <Link
              href="/contact"
              className="block py-2 hover:text-[#F5EE30] transition-colors font-etna border-b border-white/10"
              onClick={() => setMobileOpen(false)}
            >
              GET IN TOUCH
            </Link>
          </nav>
        </div>
      </div>
    </nav>
  );
}

'use client';

import { useEffect, useRef, useState } from 'react';
import { Swiper, SwiperSlide } from 'swiper/react';
import { Pagination, Autoplay } from 'swiper/modules';
import 'swiper/css';
import 'swiper/css/pagination';

export default function TestimonialSection() {
  const [testimonials, setTestimonials] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchTestimonials();
  }, []);

  const fetchTestimonials = async () => {
    try {
      setLoading(true);
      const res = await fetch('/api/testimonial?status=active');
      if (res.ok) {
        const data = await res.json();
        setTestimonials(data.data || []);
      } else {
        setError('Failed to load testimonials');
      }
    } catch (err) {
      console.error('Error fetching testimonials:', err);
      setError('Failed to load testimonials');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <section className="bg-black text-white py-20 px-6">
        <div className="max-w-7xl mx-auto text-center">
          <p className="text-gray-400">Loading testimonials...</p>
        </div>
      </section>
    );
  }

  if (error || testimonials.length === 0) {
    return null; // Don't show section if no testimonials
  }

  return (
    <section className="bg-black text-white py-20 px-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center mb-16 gap-8">
          <div>
            <div className="flex items-center gap-3 mb-4">
              <span className="w-2 h-2 bg-[#F5EE30] rounded-full"></span>
              <span className="text-white text-lg font-glacial-bold tracking-wider">TESTIMONIAL</span>
            </div>
            <h2 className="text-5xl lg:text-6xl font-bold mb-2">HAPPY CLIENT</h2>
            <h3 className="text-5xl lg:text-6xl font-bold text-gray-600">FEEDBACK</h3>
          </div>

          <div className="max-w-md">
            <h4 className="text-base font-glacial-bold mb-3 tracking-wide">TRUSTED BY YOU, DRIVEN BY RESULTS</h4>
            <p className="text-gray-400 text-sm leading-relaxed">
              Your trust powers our creativity. At Digital Corvids, every win is a shared one—thank you for letting us be part of your story.
            </p>
          </div>
        </div>

        {/* Swiper Slider */}
        <Swiper
          modules={[Pagination, Autoplay]}
          slidesPerView={1}
          spaceBetween={30}
          loop={true}
          autoplay={{
            delay: 3000,
            disableOnInteraction: false,
          }}
          pagination={{
            clickable: true,
          }}
          breakpoints={{
            768: {
              slidesPerView: 2,
            },
            1024: {
              slidesPerView: 3,
            },
          }}
          className="pb-16"
        >
          {testimonials.map((testimonial, index) => (
            <SwiperSlide key={index}>
              <div className="bg-black p-8 rounded-lg h-full flex flex-col">
                {/* Icon */}
                <div className="mb-6">
                  <img
                    src="/Frame.svg"
                    alt="Quote"
                    className="w-12 h-12"
                  />
                </div>

                {/* Testimonial Text */}
                <p className="text-gray-300 text-sm leading-relaxed mb-8 flex-grow">
                  "{testimonial.text}"
                </p>

                {/* Author Info */}
                <div>
                  <h5 className="text-white text-xs font-bold mb-1">{testimonial.name}</h5>
                  <p className="text-[#F5EE30] text-xs font-medium">{testimonial.company}</p>
                </div>
              </div>
            </SwiperSlide>
          ))}
        </Swiper>
      </div>

    </section>
  );
}

"use client";

import { useState, useRef, useEffect, useCallback } from "react";
import { X, Sparkles, User, Bot, ArrowRight, Loader2 } from "lucide-react";
import { createAISession, sendAIMessage, closeAISession, extractTaskFields } from "@/lib/actions";
import type { ChatMessage, ExtractedTaskFields } from "@/lib/actions";
import { toast } from "sonner";

interface AIChatBoxProps {
    projectId: string;
    taskState: {
        title: string;
        description: string;
    };
    userId: string;
    availableCategories?: string[];
    onClose: () => void;
    onApply: (fields: ExtractedTaskFields) => void;
}

export function AIChatBox({ projectId, taskState, userId, availableCategories = [], onClose, onApply }: AIChatBoxProps) {
    const [messages, setMessages] = useState<ChatMessage[]>([]);
    const [inputValue, setInputValue] = useState("");
    const [isLoading, setIsLoading] = useState(false);
    const [sessionId, setSessionId] = useState<string | null>(null);
    const [isConnecting, setIsConnecting] = useState(true);
    const [applyingIdx, setApplyingIdx] = useState<number | null>(null);
    const scrollRef = useRef<HTMLDivElement>(null);
    const sessionRef = useRef<string | null>(null);

    // Keep ref in sync with state
    useEffect(() => {
        sessionRef.current = sessionId;
    }, [sessionId]);

    // Auto-scroll to bottom
    useEffect(() => {
        if (scrollRef.current) {
            scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
        }
    }, [messages, isLoading]);

    // Create persistent session on mount
    useEffect(() => {
        let mounted = true;
        const initSession = async () => {
            try {
                setIsConnecting(true);
                const id = await createAISession(
                    projectId,
                    taskState.title,
                    taskState.description,
                    userId
                );
                if (mounted) {
                    setSessionId(id);
                    setIsConnecting(false);
                }
            } catch (error) {
                console.error('[AIChatBox] Failed to create session:', error);
                if (mounted) {
                    setIsConnecting(false);
                    setSessionId('legacy');
                }
            }
        };
        initSession();

        // Close session on unmount using ref for latest value
        return () => {
            mounted = false;
            if (sessionRef.current && sessionRef.current !== 'legacy') {
                closeAISession(sessionRef.current).catch(() => { });
            }
        };
    }, []); // Only on mount

    // Close session handler
    const handleClose = useCallback(() => {
        if (sessionId && sessionId !== 'legacy') {
            closeAISession(sessionId).catch(() => { });
        }
        onClose();
    }, [sessionId, onClose]);

    const handleSend = async () => {
        if (!inputValue.trim() || isLoading || !sessionId) return;

        const userMsg = inputValue.trim();
        setInputValue("");

        // Optimistic Update
        const newHistory = [...messages, { role: 'user', content: userMsg } as ChatMessage];
        setMessages(newHistory);
        setIsLoading(true);

        try {
            const aiResponse = await sendAIMessage(
                sessionId,
                userMsg,
                // Legacy fallback params
                projectId,
                taskState.title,
                taskState.description,
                messages, // Previous history for legacy mode
                userId
            );

            setMessages(prev => [...prev, { role: 'model', content: aiResponse }]);
        } catch (error) {
            console.error(error);
            setMessages(prev => [...prev, { role: 'model', content: "Sorry, I encountered an error. Please try again." }]);
        } finally {
            setIsLoading(false);
        }
    };

    const handleApply = async (content: string, msgIdx: number) => {
        setApplyingIdx(msgIdx);
        try {
            const fields = await extractTaskFields(content, availableCategories);
            onApply(fields);
            toast.success("Task fields applied from AI response");
        } catch (error) {
            console.error('[AIChatBox] Apply error:', error);
            // Fallback: just use as description
            onApply({ description: content });
            toast.success("Applied as description (AI extraction unavailable)");
        } finally {
            setApplyingIdx(null);
        }
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' && !e.shiftKey) {
            e.preventDefault();
            handleSend();
        }
    };

    return (
        <div className="flex flex-col h-full bg-background/95 backdrop-blur-sm shadow-2xl z-50 animate-in slide-in-from-bottom lg:slide-in-from-right duration-300 w-full lg:w-[400px] inset-0 max-sm:absolute lg:static lg:border-l border-border min-h-0">
            {/* Header */}
            <div className="flex items-center justify-between p-4 border-b border-border/50 bg-muted/30">
                <div className="flex items-center gap-2 text-primary">
                    <Sparkles className="w-5 h-5 fill-primary/20" />
                    <h3 className="font-semibold text-sm">Singularity</h3>
                    {sessionId && sessionId !== 'legacy' && (
                        <span className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" title="Live session active" />
                    )}
                </div>
                <button
                    onClick={handleClose}
                    className="p-1 hover:bg-muted rounded-full transition-colors text-muted-foreground"
                >
                    <X className="w-5 h-5" />
                </button>
            </div>

            {/* Messages Area */}
            <div
                ref={scrollRef}
                className="flex-1 overflow-y-auto p-4 space-y-6 scroll-smooth no-scrollbar"
            >
                {isConnecting && (
                    <div className="flex flex-col items-center justify-center h-full text-center p-4 text-muted-foreground space-y-3 opacity-80">
                        <div className="w-12 h-12 rounded-full bg-indigo-500/15 flex items-center justify-center mb-2">
                            <Sparkles className="w-6 h-6 text-indigo-500 animate-spin" />
                        </div>
                        <p className="text-sm font-medium text-foreground">Connecting to Singularity...</p>
                    </div>
                )}

                {!isConnecting && messages.length === 0 && (
                    <div className="flex flex-col items-center justify-center h-full text-center p-4 text-muted-foreground space-y-3 opacity-80">
                        <div className="w-12 h-12 rounded-full bg-indigo-500/15 flex items-center justify-center mb-2">
                            <Sparkles className="w-6 h-6 text-indigo-500" />
                        </div>
                        <p className="text-sm font-medium text-foreground">How can I help with this task?</p>
                        <p className="text-xs max-w-[200px]">
                            Try &quot;Write a complete task for this&quot;, &quot;Add acceptance criteria&quot;, or &quot;Break this down into steps&quot;.
                        </p>
                    </div>
                )}

                {messages.map((msg, idx) => (
                    <div
                        key={idx}
                        className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}
                    >
                        {/* Avatar */}
                        <div className={`
                            w-8 h-8 rounded-full flex items-center justify-center shrink-0 border shadow-sm
                            ${msg.role === 'user' ? 'bg-primary/20 text-primary' : 'bg-emerald-900/30 text-emerald-400'}
                        `}>
                            {msg.role === 'user' ? <User className="w-4 h-4" /> : <Bot className="w-4 h-4" />}
                        </div>

                        {/* Bubble */}
                        <div className={`
                            relative group max-w-[85%] rounded-2xl p-3.5 text-sm leading-relaxed shadow-sm
                            ${msg.role === 'user'
                                ? 'bg-primary text-primary-foreground rounded-br-none'
                                : 'bg-card border border-border/60 text-foreground rounded-bl-none'
                            }
                        `}>
                            <div className="whitespace-pre-wrap">{msg.content}</div>

                            {/* Action Buttons (AI Only) */}
                            {msg.role === 'model' && (
                                <div className="mt-3 pt-2 border-t border-border/10 flex justify-end opacity-100 lg:opacity-0 lg:group-hover:opacity-100 transition-opacity">
                                    <button
                                        onClick={() => handleApply(msg.content, idx)}
                                        disabled={applyingIdx !== null}
                                        className="flex items-center gap-1.5 text-xs font-medium text-emerald-500 hover:text-emerald-400 bg-emerald-500/10 hover:bg-emerald-500/20 px-2.5 py-1.5 rounded-md transition-colors disabled:opacity-50"
                                        title="AI will extract title, description, category, and priority from this response"
                                    >
                                        {applyingIdx === idx ? (
                                            <>
                                                <Loader2 className="w-3 h-3 animate-spin" /> Extracting...
                                            </>
                                        ) : (
                                            <>
                                                <Sparkles className="w-3 h-3" /> Apply to Task
                                            </>
                                        )}
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                ))}

                {isLoading && (
                    <div className="flex gap-3">
                        <div className="w-8 h-8 rounded-full bg-emerald-500/15 flex items-center justify-center shrink-0">
                            <Bot className="w-4 h-4 text-emerald-500" />
                        </div>
                        <div className="bg-card border border-border/60 rounded-2xl rounded-bl-none p-4 shadow-sm flex items-center gap-1.5">
                            <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></span>
                            <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.15s]"></span>
                            <span className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></span>
                        </div>
                    </div>
                )}
            </div>

            {/* Input Area */}
            <div className="p-4 bg-background border-t border-border/50">
                <div className="relative flex items-end gap-2 bg-muted/40 p-1.5 rounded-xl border focus-within:ring-2 focus-within:ring-indigo-500/20 focus-within:border-indigo-500/50 transition-all">
                    <textarea
                        value={inputValue}
                        onChange={(e) => setInputValue(e.target.value)}
                        onKeyDown={handleKeyDown}
                        placeholder="Ask Singularity to refine or generate..."
                        className="flex-1 max-h-32 min-h-[44px] bg-transparent border-none focus:ring-0 resize-none py-2.5 px-3 text-sm"
                        rows={1}
                        disabled={isConnecting}
                    />
                    <button
                        onClick={handleSend}
                        disabled={!inputValue.trim() || isLoading || isConnecting}
                        className="h-9 w-9 flex items-center justify-center rounded-lg bg-indigo-600 text-white hover:bg-indigo-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors mb-0.5"
                    >
                        <ArrowRight className="w-4 h-4" />
                    </button>
                </div>
                <div className="text-center mt-2">
                    <p className="text-[10px] text-muted-foreground">Click &quot;Apply to Task&quot; on any response to auto-fill all task fields.</p>
                </div>
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
} from "@/components/ui/dialog";
import { ScrollArea } from "@/components/ui/scroll-area";
import { explainTask } from "@/lib/actions"; // Server Action
import { Sparkles, Loader2, RefreshCw } from "lucide-react";
import ReactMarkdown from "react-markdown";

interface AIExplanationModalProps {
    taskId: string | null;
    open: boolean;
    onOpenChange: (open: boolean) => void;
    userId?: string;
}

export function AIExplanationModal({ taskId, open, onOpenChange, userId }: AIExplanationModalProps) {
    const [explanation, setExplanation] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    useEffect(() => {
        if (open && taskId) {
            // Always fetch fresh when opening
            handleExplain();
        }
        if (!open) {
            // Reset on close so next open gets fresh data
            setExplanation(null);
            setError(null);
        }
    }, [open, taskId]);

    const handleExplain = async () => {
        if (!taskId) return;
        setLoading(true);
        setError(null);
        try {
            // Pass userId to server action if available
            const result = await explainTask(taskId, userId || "");
            setExplanation(result);
        } catch (err) {
            console.error(err);
            setError("Singularity is not configured. Contact your administrator.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Dialog open={open} onOpenChange={onOpenChange}>
            <DialogContent className="max-w-[95vw] sm:max-w-[600px] max-h-[85dvh] flex flex-col overflow-hidden">
                <DialogHeader>
                    <DialogTitle className="flex items-center gap-2">
                        <Sparkles className="h-5 w-5 text-primary" />
                        Singularity
                    </DialogTitle>
                    <DialogDescription>
                        Get a clear summary and next steps for this task.
                    </DialogDescription>
                </DialogHeader>

                <div className="mt-4">
                    {loading ? (
                        <div className="flex flex-col items-center justify-center py-10 space-y-3">
                            <div className="p-3 rounded-full bg-primary/10">
                                <Loader2 className="h-8 w-8 text-primary animate-spin" />
                            </div>
                            <p className="text-sm text-muted-foreground">Analyzing task context...</p>
                        </div>
                    ) : error ? (
                        <div className="text-center py-8 text-red-500 space-y-3">
                            <p>{error}</p>
                            <Button onClick={handleExplain} variant="outline" size="sm">
                                <RefreshCw className="mr-2 h-4 w-4" /> Try Again
                            </Button>
                        </div>
                    ) : (
                        <ScrollArea className="max-h-[50dvh] sm:h-[400px] w-full rounded-md border p-4 bg-secondary">
                            <div className="prose dark:prose-invert text-sm max-w-none">
                                <ReactMarkdown>{explanation || ""}</ReactMarkdown>
                            </div>
                        </ScrollArea>
                    )}
                </div>

                {!loading && !error && (
                    <div className="flex justify-end gap-2 mt-2">
                        <Button variant="ghost" onClick={() => onOpenChange(false)}>Close</Button>
                        <Button variant="outline" onClick={handleExplain}>
                            <RefreshCw className="mr-2 h-4 w-4" /> Regenerate
                        </Button>
                    </div>
                )}
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useEffect } from "react";
import { createTask, getProjectServices, getUsers, getCurrentUser, aiEstimateTaskHours } from "@/lib/actions";
import type { ExtractedTaskFields } from "@/lib/actions";
import { AIChatBox } from "./AIChatBox";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Plus, Loader2, Sparkles, Clock } from "lucide-react";
import { useRouter } from "next/navigation";
import { Task } from "@/lib/types";
import { toast } from "sonner";
import { DateTimeInput } from "@/components/ui/DateTimeInput";

type TaskPriority = 'Low' | 'Medium' | 'High';

interface CreateTaskModalProps {
    projectId: string;
    assigneeId?: string;
}

const PRIORITY_OPTIONS: TaskPriority[] = ["Low", "Medium", "High"];

export function CreateTaskModal({ projectId, assigneeId: defaultAssignee = "" }: CreateTaskModalProps) {
    const router = useRouter();
    const [open, setOpen] = useState(false);
    const [loading, setLoading] = useState(false);
    const [estimating, setEstimating] = useState(false);
    const [showChat, setShowChat] = useState(false);
    const [currentUserId, setCurrentUserId] = useState("");

    // Form state
    const [title, setTitle] = useState("");
    const [description, setDescription] = useState("");
    const [dueDate, setDueDate] = useState("");
    const [assigneeId, setAssigneeId] = useState(defaultAssignee);
    const [category, setCategory] = useState("");
    const [priority, setPriority] = useState<TaskPriority>("Medium");
    const [estimatedHours, setEstimatedHours] = useState<number>(0);

    const [users, setUsers] = useState<any[]>([]);
    const [services, setServices] = useState<any[]>([]);

    useEffect(() => {
        if (open) {
            Promise.all([getUsers(), getProjectServices(projectId), getCurrentUser()]).then(([u, s, currentUser]) => {
                setUsers(u);
                setServices(s);
                if (currentUser) setCurrentUserId(currentUser.id);
                // Set defaults only if not already set
                if (s.length > 0 && !category) setCategory(s[0].name);
                if (u.length > 0 && !assigneeId) setAssigneeId(u[0].id);
            });
        }
    }, [open]);

    const resetForm = () => {
        setTitle("");
        setDescription("");
        setDueDate("");
        setCategory("");
        setPriority("Medium");
        setEstimatedHours(0);
        setShowChat(false);
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            await createTask({
                projectId,
                title,
                description,
                status: "Todo",
                assigneeId,
                category,
                priority,
                dueDate: dueDate || undefined,
                estimatedHours: estimatedHours || undefined,
            });
            toast.success("Task created");
            setOpen(false);
            resetForm();
            router.refresh();
        } catch {
            toast.error("Failed to create task");
        } finally {
            setLoading(false);
        }
    };

    const inputCls = "flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ring";
    const labelCls = "text-sm font-medium text-foreground";

    return (
        <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) resetForm(); }}>
            <DialogTrigger asChild>
                <button className="inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium border border-border bg-background text-foreground hover:bg-accent h-9 px-4 py-2 transition-colors">
                    <Plus className="mr-2 h-4 w-4" /> Add Task
                </button>
            </DialogTrigger>
            <DialogContent className={`transition-all duration-300 w-full max-w-[95vw] ${showChat ? "lg:max-w-[900px] sm:max-w-[500px]" : "sm:max-w-[520px]"}`}>
                <DialogHeader>
                    <DialogTitle>Create New Task</DialogTitle>
                </DialogHeader>
                <div className="relative flex flex-col lg:flex-row max-h-[75dvh] sm:h-[580px] lg:gap-6 overflow-hidden min-h-0">
                    {/* Left Side: Form */}
                    <form onSubmit={handleSubmit} className="space-y-4 flex-1 overflow-y-auto px-1 no-scrollbar">
                        {/* Title */}
                        <div className="space-y-1.5">
                            <label className={labelCls}>Task Title</label>
                            <input
                                required
                                value={title}
                                onChange={e => setTitle(e.target.value)}
                                placeholder="Task name"
                                className={inputCls}
                            />
                        </div>

                        {/* Service + Assignee */}
                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                            <div className="space-y-1.5">
                                <label className={labelCls}>Service</label>
                                <select value={category} onChange={e => setCategory(e.target.value)} className={inputCls}>
                                    <option value="">No Service</option>
                                    {services.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                                </select>
                            </div>
                            <div className="space-y-1.5">
                                <label className={labelCls}>Assign To</label>
                                <select value={assigneeId} onChange={e => setAssigneeId(e.target.value)} className={inputCls}>
                                    <option value="">Unassigned</option>
                                    {users.map(u => <option key={u.id} value={u.id}>{u.name} ({u.jobTitle || u.role})</option>)}
                                </select>
                            </div>
                        </div>

                        {/* Priority */}
                        <div className="space-y-1.5">
                            <label className={labelCls}>Priority</label>
                            <div className="flex gap-2">
                                {PRIORITY_OPTIONS.map(p => (
                                    <button
                                        key={p}
                                        type="button"
                                        onClick={() => setPriority(p)}
                                        className={`flex-1 h-9 rounded-md border text-xs font-semibold transition-all ${priority === p
                                            ? p === 'High' ? 'bg-red-500/15 border-red-500/50 text-red-500'
                                                : p === 'Medium' ? 'bg-amber-500/15 border-amber-500/50 text-amber-600'
                                                    : 'bg-blue-500/15 border-blue-500/50 text-blue-500'
                                            : 'border-input bg-background text-muted-foreground hover:bg-muted'
                                            }`}
                                    >
                                        {p}
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Estimated Hours */}
                        <div className="space-y-1.5">
                            <label className={labelCls}>
                                <span className="flex items-center gap-1.5"><Clock className="h-3.5 w-3.5" /> Estimated Hours</span>
                            </label>
                            <div className="flex items-center gap-2">
                                <div className="relative">
                                    <input
                                        type="number"
                                        min="0"
                                        step="0.5"
                                        value={estimatedHours || ""}
                                        onChange={e => setEstimatedHours(parseFloat(e.target.value) || 0)}
                                        placeholder="e.g. 4"
                                        className={`${inputCls} w-28 pr-9`}
                                    />
                                    <button
                                        type="button"
                                        disabled={!title.trim() || estimating}
                                        title="AI Estimate"
                                        onClick={async () => {
                                            setEstimating(true);
                                            try {
                                                const hours = await aiEstimateTaskHours(projectId, title, description, priority);
                                                setEstimatedHours(hours);
                                                toast.success(`Estimated: ${hours}h`);
                                            } catch (e: any) {
                                                toast.error(e.message || 'Failed to estimate');
                                            } finally {
                                                setEstimating(false);
                                            }
                                        }}
                                        className="absolute right-1 top-1/2 -translate-y-1/2 h-7 w-7 flex items-center justify-center rounded-md transition-all text-muted-foreground hover:text-indigo-500 hover:bg-indigo-500/10 disabled:opacity-40 disabled:pointer-events-none"
                                    >
                                        {estimating ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Sparkles className="h-3.5 w-3.5" />}
                                    </button>
                                </div>
                                <span className="text-xs text-muted-foreground">hours</span>
                            </div>
                        </div>

                        {/* Description */}
                        <div className="space-y-1.5">
                            <div className="flex items-center justify-between">
                                <label className={labelCls}>Description</label>
                                <button
                                    onClick={() => setShowChat(!showChat)}
                                    type="button"
                                    disabled={!title}
                                    className={`text-xs flex items-center gap-1.5 px-2 py-1 rounded-md transition-all font-medium border ${showChat
                                        ? "bg-indigo-500/10 text-indigo-600 border-indigo-500/20 ring-1 ring-indigo-200"
                                        : "text-muted-foreground border-transparent hover:bg-muted"
                                        }`}
                                >
                                    <Sparkles className={`h-3 w-3 ${showChat ? "fill-indigo-400" : ""}`} />
                                    {showChat ? "Close Assistant" : "AI Assistant"}
                                </button>
                            </div>
                            <textarea
                                value={description}
                                onChange={e => setDescription(e.target.value)}
                                placeholder="Task details, acceptance criteria..."
                                className="flex min-h-[160px] w-full rounded-md border border-input bg-background px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-ring resize-none"
                            />
                        </div>

                        <div className="space-y-1.5">
                            <label className={labelCls}>Due Date &amp; Time</label>
                            <DateTimeInput
                                type="datetime-local"
                                value={dueDate}
                                onChange={e => setDueDate(e.target.value)}
                            />
                        </div>

                        <button
                            disabled={loading}
                            type="submit"
                            className="w-full inline-flex items-center justify-center gap-2 rounded-md text-sm font-medium bg-primary text-primary-foreground h-10 px-4 hover:bg-primary/90 transition-colors mt-2"
                        >
                            {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : "Create Task"}
                        </button>
                    </form>

                    {/* Right Side: AI Chat */}
                    {showChat && (
                        <AIChatBox
                            projectId={projectId}
                            taskState={{ title, description }}
                            userId={currentUserId}
                            availableCategories={services.map(s => s.name)}
                            onClose={() => setShowChat(false)}
                            onApply={(fields: ExtractedTaskFields) => {
                                if (fields.title) setTitle(fields.title);
                                if (fields.description) setDescription(fields.description);
                                if (fields.category && services.some(s => s.name === fields.category)) {
                                    setCategory(fields.category);
                                }
                                if (fields.priority) setPriority(fields.priority);
                                if (fields.estimatedHours) setEstimatedHours(fields.estimatedHours);
                            }}
                        />
                    )}
                </div>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useDroppable } from "@dnd-kit/core";
import { Task } from "@/lib/types";
import { TaskCard } from "./TaskCard";

interface DroppableColumnProps {
    id: string;
    title: string;
    tasks: Task[];
    users: any[];
    onViewTask: (task: Task) => void;
    onEditTask: (task: Task) => void;
    currentUserId?: string;
    readOnly?: boolean;
    permissions?: any;
    onQuickEdit?: (taskId: string, patch: Partial<Task>) => void;
    disableDrag?: boolean;
    onStatusChange?: (taskId: string, newStatus: Task['status']) => void;
}

export function DroppableColumn({ id, title, tasks, users, onViewTask, onEditTask, currentUserId, readOnly, permissions, onQuickEdit, disableDrag, onStatusChange }: DroppableColumnProps) {
    const { setNodeRef, isOver } = useDroppable({ id });

    return (
        <div
            ref={setNodeRef}
            className={`flex h-full min-h-0 min-w-0 w-full flex-col rounded-lg p-4 border transition-colors duration-200 overflow-hidden ${isOver
                ? 'bg-primary/5 border-primary/40 ring-2 ring-primary/20'
                : 'bg-muted/50 border-border/50'
                }`}
        >
            <div className="flex items-center justify-between mb-4">
                <h3 className="font-semibold text-sm uppercase text-muted-foreground flex items-center gap-2">
                    <span className={`inline-block w-2 h-2 rounded-full ${title === 'Done' ? 'bg-emerald-500' :
                        title === 'In Progress' ? 'bg-blue-500' :
                            title === 'Review' ? 'bg-yellow-500' :
                                'bg-muted-foreground/40'
                        }`} />
                    {title}
                </h3>
                <span className="text-xs font-bold bg-background text-foreground px-2 py-0.5 rounded-full border">
                    {tasks.length}
                </span>
            </div>

            <div className="flex-1 flex flex-col gap-2 min-h-[60px] overflow-y-auto no-scrollbar">
                {tasks.length === 0 ? (
                    <div className={`flex-1 flex items-center justify-center rounded-md border border-dashed min-h-[80px] transition-colors ${isOver ? 'border-primary/40 bg-primary/5' : 'border-border/50'
                        }`}>
                        <p className="text-xs text-muted-foreground/50 select-none">
                            {disableDrag ? 'No tasks' : isOver ? 'Drop here' : 'Drop tasks here'}
                        </p>
                    </div>
                ) : tasks.map((task) => (
                    <TaskCard
                        key={task.id}
                        task={task}
                        users={users}
                        onView={onViewTask}
                        onEdit={onEditTask}
                        currentUserId={currentUserId}
                        readOnly={readOnly}
                        permissions={permissions}
                        onQuickEdit={onQuickEdit}
                        disableDrag={disableDrag}
                        onStatusChange={onStatusChange}
                    />
                ))}
            </div>
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { updateTask, getUsers, getProjectServices, deleteTask, aiEstimateTaskHours } from "@/lib/actions";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Loader2, Trash2, AlertTriangle, Clock, Sparkles } from "lucide-react";
import { useRouter } from "next/navigation";
import { Task } from "@/lib/types";
import { toast } from "sonner";
import { DateTimeInput } from "@/components/ui/DateTimeInput";

interface EditTaskModalProps {
    task: Task;
    open: boolean;
    setOpen: (open: boolean) => void;
    permissions?: any;
    currentUserId?: string;
}

const PRIORITY_OPTIONS = ["Low", "Medium", "High"] as const;

export function EditTaskModal({ task, open, setOpen, permissions, currentUserId }: EditTaskModalProps) {
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [confirmDelete, setConfirmDelete] = useState(false);
    const [estimating, setEstimating] = useState(false);

    const [title, setTitle] = useState(task.title);
    const [description, setDescription] = useState(task.description || "");
    const [dueDate, setDueDate] = useState(task.dueDate || "");
    const [status, setStatus] = useState(task.status);
    const [assigneeId, setAssigneeId] = useState(task.assigneeId);
    const [category, setCategory] = useState(task.category || "");
    const [priority, setPriority] = useState<Task['priority']>(task.priority || "Medium");
    const [estimatedHours, setEstimatedHours] = useState<number>(task.estimatedHours || 0);

    const [users, setUsers] = useState<any[]>([]);
    const [services, setServices] = useState<any[]>([]);

    useEffect(() => {
        if (open) {
            // Reset confirm delete state when reopened
            setConfirmDelete(false);
            Promise.all([getUsers(), getProjectServices(task.projectId)]).then(([u, s]) => {
                setUsers(u);
                setServices(s);
            });
        }
    }, [open]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            await updateTask(task.id, {
                title,
                description,
                status: status as Task['status'],
                assigneeId,
                category,
                priority,
                dueDate: dueDate || undefined,
                estimatedHours: estimatedHours || undefined,
            });
            toast.success("Task updated successfully");
            setOpen(false);
            router.refresh();
        } catch {
            toast.error("Failed to update task");
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async () => {
        setLoading(true);
        try {
            await deleteTask(task.id);
            toast.success("Task deleted");
            setOpen(false);
            router.refresh();
        } catch {
            toast.error("Failed to delete task");
        } finally {
            setLoading(false);
        }
    };

    const canEdit = permissions?.canManageTasks ?? true;
    const canDelete = !permissions ||
        permissions.deleteAccess === 'any' ||
        (permissions.deleteAccess === 'own' && task.createdBy === currentUserId);

    const inputCls = "flex h-10 w-full rounded-md border border-input bg-background px-3 py-2 text-sm disabled:opacity-50 focus:outline-none focus:ring-2 focus:ring-ring";
    const labelCls = "text-sm font-medium text-foreground";

    return (
        <Dialog open={open} onOpenChange={(o) => { setOpen(o); if (!o) setConfirmDelete(false); }}>
            <DialogContent className="max-w-[95vw] sm:max-w-[520px] max-h-[85dvh] flex flex-col overflow-hidden">
                <DialogHeader className="shrink-0">
                    <DialogTitle>Edit Task</DialogTitle>
                </DialogHeader>
                <form onSubmit={handleSubmit} className="space-y-4 pt-1 overflow-y-auto flex-1 px-1 -mx-1">
                    {/* Title */}
                    <div className="space-y-1.5">
                        <label className={labelCls}>Task Title</label>
                        <input
                            required
                            disabled={!canEdit}
                            value={title}
                            onChange={e => setTitle(e.target.value)}
                            placeholder="Task title"
                            className={inputCls}
                        />
                    </div>

                    {/* Service + Assignee */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        <div className="space-y-1.5">
                            <label className={labelCls}>Service</label>
                            <select disabled={!canEdit} value={category} onChange={e => setCategory(e.target.value)} className={inputCls}>
                                <option value="">No Service</option>
                                {services.map(s => <option key={s.id} value={s.name}>{s.name}</option>)}
                            </select>
                        </div>
                        <div className="space-y-1.5">
                            <label className={labelCls}>Assign To</label>
                            <select disabled={!canEdit} value={assigneeId} onChange={e => setAssigneeId(e.target.value)} className={inputCls}>
                                <option value="">Unassigned</option>
                                {users.map(u => <option key={u.id} value={u.id}>{u.name} ({u.jobTitle || u.role})</option>)}
                            </select>
                        </div>
                    </div>

                    {/* Priority + Status */}
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                        <div className="space-y-1.5">
                            <label className={labelCls}>Priority</label>
                            <select disabled={!canEdit} value={priority} onChange={e => setPriority(e.target.value as Task['priority'])} className={inputCls}>
                                {PRIORITY_OPTIONS.map(p => <option key={p} value={p}>{p}</option>)}
                            </select>
                        </div>
                        <div className="space-y-1.5">
                            <label className={labelCls}>Status</label>
                            <select disabled={!canEdit} value={status} onChange={e => setStatus(e.target.value as Task['status'])} className={inputCls}>
                                {["Todo", "In Progress", "Review", "Done"].map(s => <option key={s} value={s}>{s}</option>)}
                            </select>
                        </div>
                    </div>

                    {/* Estimated Hours */}
                    <div className="space-y-1.5">
                        <label className={labelCls}>
                            <span className="flex items-center gap-1.5"><Clock className="h-3.5 w-3.5" /> Estimated Hours</span>
                        </label>
                        <div className="flex items-center gap-2">
                            <div className="relative">
                                <input
                                    type="number"
                                    min="0"
                                    step="0.5"
                                    value={estimatedHours || ""}
                                    onChange={e => setEstimatedHours(parseFloat(e.target.value) || 0)}
                                    placeholder="e.g. 4"
                                    className={`${inputCls} w-28 pr-9`}
                                />
                                <button
                                    type="button"
                                    disabled={!title.trim() || estimating}
                                    title="AI Estimate"
                                    onClick={async () => {
                                        setEstimating(true);
                                        try {
                                            const hours = await aiEstimateTaskHours(task.projectId, title, description, priority || 'Medium');
                                            setEstimatedHours(hours);
                                            toast.success(`Estimated: ${hours}h`);
                                        } catch (e: any) {
                                            toast.error(e.message || 'Failed to estimate');
                                        } finally {
                                            setEstimating(false);
                                        }
                                    }}
                                    className="absolute right-1 top-1/2 -translate-y-1/2 h-7 w-7 flex items-center justify-center rounded-md transition-all text-muted-foreground hover:text-indigo-500 hover:bg-indigo-500/10 disabled:opacity-40 disabled:pointer-events-none"
                                >
                                    {estimating ? <Loader2 className="h-3.5 w-3.5 animate-spin" /> : <Sparkles className="h-3.5 w-3.5" />}
                                </button>
                            </div>
                            <span className="text-xs text-muted-foreground">hours</span>
                        </div>
                    </div>

                    {/* Description */}
                    <div className="space-y-1.5">
                        <label className={labelCls}>Description</label>
                        <textarea
                            disabled={!canEdit}
                            value={description}
                            onChange={e => setDescription(e.target.value)}
                            placeholder="Task details..."
                            className="flex min-h-[80px] w-full rounded-md border border-input bg-background px-3 py-2 text-sm disabled:opacity-50 focus:outline-none focus:ring-2 focus:ring-ring resize-none"
                        />
                    </div>

                    {/* Due Date */}
                    <div className="space-y-1.5">
                        <label className={labelCls}>Due Date &amp; Time</label>
                        <DateTimeInput
                            type="datetime-local"
                            value={dueDate}
                            onChange={e => setDueDate(e.target.value)}
                            disabled={!canEdit}
                        />
                    </div>

                    {/* Delete confirmation inline */}
                    {canDelete && confirmDelete && (
                        <div className="flex items-center gap-2 p-3 rounded-md bg-red-500/10 border border-red-500/20">
                            <AlertTriangle className="h-4 w-4 text-red-500 shrink-0" />
                            <span className="text-sm text-red-600 dark:text-red-400 flex-1">Delete this task permanently?</span>
                            <button type="button" onClick={() => setConfirmDelete(false)} className="text-xs text-muted-foreground hover:text-foreground px-2 py-1 rounded">Cancel</button>
                            <button type="button" disabled={loading} onClick={handleDelete} className="text-xs font-semibold bg-red-500 text-white px-3 py-1 rounded hover:bg-red-600 flex items-center gap-1">
                                {loading ? <Loader2 className="h-3 w-3 animate-spin" /> : "Delete"}
                            </button>
                        </div>
                    )}

                    {/* Actions */}
                    <div className="flex gap-2 pt-1">
                        {canDelete && !confirmDelete && (
                            <button
                                type="button"
                                disabled={loading}
                                onClick={() => setConfirmDelete(true)}
                                className="inline-flex items-center gap-1.5 rounded-md text-sm font-medium bg-red-500/10 text-red-600 dark:text-red-400 h-10 px-3 hover:bg-red-500/20 transition-colors"
                            >
                                <Trash2 className="h-4 w-4" /> Delete
                            </button>
                        )}
                        {canEdit && (
                            <button
                                disabled={loading}
                                type="submit"
                                className="flex-1 inline-flex items-center justify-center gap-2 rounded-md text-sm font-medium bg-primary text-primary-foreground h-10 px-4 hover:bg-primary/90 transition-colors"
                            >
                                {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : "Save Changes"}
                            </button>
                        )}
                    </div>
                </form>
            </DialogContent>
        </Dialog>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { createPortal } from "react-dom";
import {
    DndContext,
    DragOverlay,
    KeyboardSensor,
    PointerSensor,
    TouchSensor,
    useSensor,
    useSensors,
    DragStartEvent,
    DragEndEvent,
    rectIntersection,
    CollisionDetection,
} from "@dnd-kit/core";
import { Task, UserPermissions } from "@/lib/types";
import { updateTaskStatus } from "@/lib/actions";
import { TaskCard } from "./TaskCard";
import { toast } from "sonner";
import { DroppableColumn } from "./DroppableColumn";
import { ViewTaskModal } from "./ViewTaskModal";
import { EditTaskModal } from "./EditTaskModal";

const COLUMNS = ["Todo", "In Progress", "Review", "Done"];

const COLUMN_COLORS: Record<string, string> = {
    "Todo": "text-muted-foreground",
    "In Progress": "text-blue-500",
    "Review": "text-yellow-500",
    "Done": "text-emerald-500",
};

interface KanbanBoardProps {
    initialTasks: Task[];
    projectId: string;
    categories?: { id: string; name: string }[];
    users?: any[];
    currentUserId?: string;
    selectedCategory?: string;
    readOnly?: boolean;
    permissions?: UserPermissions;
}

// Custom collision detection: checks if pointer is within any column's bounding rect
// Handles both desktop IDs ("Todo") and mobile IDs ("mobile-Todo")
const kanbanCollision: CollisionDetection = (args) => {
    const { pointerCoordinates, droppableContainers } = args;
    if (!pointerCoordinates) return rectIntersection(args);

    const { x, y } = pointerCoordinates;
    const collisions: { id: string | number; data: { droppableContainer: any; value: number } }[] = [];

    for (const container of droppableContainers) {
        const id = container.id as string;
        const colName = id.startsWith('mobile-') ? id.slice(7) : id;
        if (!COLUMNS.includes(colName)) continue;

        const rect = container.rect.current;
        if (!rect || (rect.width === 0 && rect.height === 0)) continue;

        if (
            x >= rect.left && x <= rect.left + rect.width &&
            y >= rect.top && y <= rect.top + rect.height
        ) {
            collisions.push({
                id: container.id,
                data: { droppableContainer: container, value: 0 },
            });
        }
    }

    return collisions;
};

export function KanbanBoard({ initialTasks, users, currentUserId, selectedCategory = "All", readOnly = false, permissions }: KanbanBoardProps) {
    const [mounted, setMounted] = useState(false);
    const [tasks, setTasks] = useState<Task[]>(initialTasks);
    const [activeTask, setActiveTask] = useState<Task | null>(null);
    const [activeColumn, setActiveColumn] = useState(0);
    const overlayRef = useRef<HTMLDivElement>(null);

    const [viewTaskId, setViewTaskId] = useState<string | null>(null);
    const [editTaskId, setEditTaskId] = useState<string | null>(null);

    const viewingTask = tasks.find(t => t.id === viewTaskId);
    const editingTask = tasks.find(t => t.id === editTaskId);

    useEffect(() => { setMounted(true); }, []);
    useEffect(() => { setTasks(initialTasks); }, [initialTasks]);

    // Track mouse/touch position for custom drag overlay — direct DOM manipulation for smooth 60fps
    useEffect(() => {
        if (!activeTask) return;
        let rafId: number;
        const updateOverlay = (clientX: number, clientY: number) => {
            cancelAnimationFrame(rafId);
            rafId = requestAnimationFrame(() => {
                if (overlayRef.current) {
                    overlayRef.current.style.transform = `translate3d(${clientX - 140}px, ${clientY - 20}px, 0)`;
                }
            });
        };
        const mouseHandler = (e: MouseEvent) => updateOverlay(e.clientX, e.clientY);
        const touchHandler = (e: TouchEvent) => {
            if (e.touches.length > 0) {
                updateOverlay(e.touches[0].clientX, e.touches[0].clientY);
            }
        };
        window.addEventListener('mousemove', mouseHandler, { passive: true });
        window.addEventListener('touchmove', touchHandler, { passive: true });
        return () => {
            window.removeEventListener('mousemove', mouseHandler);
            window.removeEventListener('touchmove', touchHandler);
            cancelAnimationFrame(rafId);
        };
    }, [activeTask]);

    const sensors = useSensors(
        useSensor(PointerSensor, { activationConstraint: { distance: 5 } }),
        useSensor(TouchSensor, { activationConstraint: { delay: 200, tolerance: 5 } }),
        useSensor(KeyboardSensor)
    );

    const handleDragStart = (event: DragStartEvent) => {
        if (readOnly) return;
        if (permissions && !permissions.canManageTasks && !permissions.canMarkDone) return;
        const pointerEvent = event.activatorEvent as MouseEvent;
        if (pointerEvent && overlayRef.current) {
            overlayRef.current.style.transform = `translate3d(${pointerEvent.clientX - 140}px, ${pointerEvent.clientY - 20}px, 0)`;
        }
        setActiveTask(event.active.data.current?.task);
    };

    const handleDragEnd = async (event: DragEndEvent) => {
        const draggedTask = activeTask;
        setActiveTask(null);
        if (readOnly || !draggedTask) return;

        const { over } = event;
        if (!over) return;

        const taskId = draggedTask.id;
        const rawOverId = over.id as string;
        // Strip mobile- prefix if present
        const overId = rawOverId.startsWith('mobile-') ? rawOverId.slice(7) : rawOverId;

        // Determine target column
        let newStatus: string | null = null;
        if (COLUMNS.includes(overId)) {
            newStatus = overId;
        }

        if (!newStatus || newStatus === draggedTask.status) return;

        // Permission check
        if (permissions) {
            if (newStatus === 'Done' && !permissions.canMarkDone) {
                toast.error("You don't have permission to mark tasks as Done.");
                return;
            }
            if (newStatus !== 'Done' && !permissions.canManageTasks) {
                toast.error("You don't have permission to manage task status.");
                return;
            }
        }

        // Optimistic update
        setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: newStatus as Task['status'] } : t));

        try {
            await updateTaskStatus(taskId, newStatus as Task['status']);
        } catch {
            setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: draggedTask.status } : t));
            toast.error("Failed to move task");
        }
    };

    const handleQuickEdit = (taskId: string, patch: Partial<Task>) => {
        setTasks(prev => prev.map(t => t.id === taskId ? { ...t, ...patch } : t));
    };

    // Mobile: direct status change (replaces drag-and-drop)
    const handleMobileStatusChange = async (taskId: string, newStatus: Task['status']) => {
        if (readOnly) return;
        const task = tasks.find(t => t.id === taskId);
        if (!task || task.status === newStatus) return;

        // Permission check
        if (permissions) {
            if (newStatus === 'Done' && !permissions.canMarkDone) {
                toast.error("You don't have permission to mark tasks as Done.");
                return;
            }
            if (newStatus !== 'Done' && !permissions.canManageTasks) {
                toast.error("You don't have permission to manage task status.");
                return;
            }
        }

        const oldStatus = task.status;
        // Optimistic update
        setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: newStatus } : t));

        try {
            await updateTaskStatus(taskId, newStatus);
            toast.success(`Moved to ${newStatus}`);
        } catch {
            setTasks(prev => prev.map(t => t.id === taskId ? { ...t, status: oldStatus } : t));
            toast.error("Failed to move task");
        }
    };

    const filteredTasks = selectedCategory === "All"
        ? tasks
        : tasks.filter(t => t.category === selectedCategory);

    if (!mounted) {
        return (
            <div className="flex flex-col h-full">
                <div className="grid grid-cols-2 md:grid-cols-4 h-full gap-4 pb-4">
                    {COLUMNS.map((col) => (
                        <div key={col} className="flex h-full min-w-0 w-full flex-col rounded-md bg-muted/50 p-4 border border-dashed">
                            <h3 className="font-semibold mb-3 text-sm text-foreground">{col}</h3>
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="flex flex-col h-full gap-4">
            {/* Mobile: column tab selector */}
            <div className="flex md:hidden rounded-lg bg-muted p-1 gap-1">
                {COLUMNS.map((col, i) => {
                    const count = filteredTasks.filter(t => t.status === col).length;
                    return (
                        <button
                            key={col}
                            onClick={() => setActiveColumn(i)}
                            className={`flex-1 flex items-center justify-center gap-1.5 rounded-md py-1.5 text-xs font-semibold transition-all ${activeColumn === i
                                ? 'bg-background shadow-sm text-foreground'
                                : 'text-muted-foreground hover:text-foreground'
                                }`}
                        >
                            <span className={activeColumn === i ? COLUMN_COLORS[col] : ''}>
                                {col === "In Progress" ? "Progress" : col}
                            </span>
                            <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-bold ${activeColumn === i ? 'bg-primary/10 text-primary' : 'bg-muted-foreground/10'}`}>
                                {count}
                            </span>
                        </button>
                    );
                })}
            </div>

            <DndContext
                sensors={sensors}
                collisionDetection={kanbanCollision}
                onDragStart={handleDragStart}
                onDragEnd={handleDragEnd}
            >
                {/* Desktop: all 4 columns */}
                <div className="hidden md:grid grid-cols-4 h-full gap-4 pb-4">
                    {COLUMNS.map((col) => (
                        <DroppableColumn
                            key={col}
                            id={col}
                            title={col}
                            tasks={filteredTasks.filter(t => t.status === col)}
                            users={users || []}
                            onViewTask={(task) => setViewTaskId(task.id)}
                            onEditTask={(task) => !readOnly && setEditTaskId(task.id)}
                            currentUserId={currentUserId}
                            readOnly={readOnly}
                            permissions={permissions}
                            onQuickEdit={handleQuickEdit}
                        />
                    ))}
                </div>

                {/* Mobile: single active column — uses 'mobile-' prefix to avoid ID conflict with desktop */}
                <div className="flex md:hidden h-full pb-4">
                    <DroppableColumn
                        key={`mobile-${COLUMNS[activeColumn]}`}
                        id={`mobile-${COLUMNS[activeColumn]}`}
                        title={COLUMNS[activeColumn]}
                        tasks={filteredTasks.filter(t => t.status === COLUMNS[activeColumn])}
                        users={users || []}
                        onViewTask={(task) => setViewTaskId(task.id)}
                        onEditTask={(task) => !readOnly && setEditTaskId(task.id)}
                        currentUserId={currentUserId}
                        readOnly={readOnly}
                        permissions={permissions}
                        onQuickEdit={handleQuickEdit}
                        disableDrag={true}
                        onStatusChange={handleMobileStatusChange}
                    />
                </div>

                <DragOverlay dropAnimation={null} />
            </DndContext>

            {/* Custom drag overlay via portal to document.body */}
            {mounted && createPortal(
                <div
                    ref={overlayRef}
                    style={{
                        position: 'fixed',
                        left: 0,
                        top: 0,
                        width: 'min(280px, 85vw)',
                        zIndex: 99999,
                        pointerEvents: 'none',
                        willChange: 'transform',
                        display: activeTask ? 'block' : 'none',
                    }}
                >
                    {activeTask && (
                        <TaskCard
                            task={activeTask}
                            users={users || []}
                            onView={() => { }}
                            onEdit={() => { }}
                            currentUserId={currentUserId}
                            permissions={permissions}
                            onQuickEdit={() => { }}
                            dragOverlay={true}
                        />
                    )}
                </div>,
                document.body
            )}

            {viewingTask && (
                <ViewTaskModal
                    task={viewingTask}
                    open={!!viewingTask}
                    setOpen={(open) => !open && setViewTaskId(null)}
                    onEdit={() => {
                        setEditTaskId(viewingTask.id);
                        setViewTaskId(null);
                    }}
                    users={users}
                    readOnly={readOnly}
                    permissions={permissions}
                    currentUserId={currentUserId}
                />
            )}

            {editingTask && (
                <EditTaskModal
                    task={editingTask}
                    open={!!editingTask}
                    setOpen={(open) => !open && setEditTaskId(null)}
                    permissions={permissions}
                    currentUserId={currentUserId}
                />
            )}
        </div>
    );
}

"use client";

import { useState, useCallback, useEffect } from "react";
import { addService, deleteService, updateService, getProjectServices, getServiceTaskCount, getUsers } from "@/lib/actions";
import { User } from "@/lib/types";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import {
    Dialog, DialogContent, DialogDescription, DialogFooter,
    DialogHeader, DialogTitle
} from "@/components/ui/dialog";
import {
    AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent,
    AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle
} from "@/components/ui/alert-dialog";
import { Plus, Trash2, Edit2, Users, Loader2, X, ChevronDown, Check, AlertTriangle } from "lucide-react";
import { toast } from "sonner";
import { useRouter } from "next/navigation";

type ServiceItem = {
    id: string;
    name: string;
    projectId?: string;
    employees?: string[];
};

type Props = {
    projectId: string;
    users: User[];
};

export function ProjectServices({ projectId, users }: Props) {
    const router = useRouter();
    const [services, setServices] = useState<ServiceItem[]>([]);
    const [directoryUsers, setDirectoryUsers] = useState<User[]>(users.filter(u => u.role !== 'client'));
    const [loading, setLoading] = useState(true);
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [editing, setEditing] = useState<ServiceItem | null>(null);
    const [deleteTarget, setDeleteTarget] = useState<{ id: string; name: string; taskCount: number } | null>(null);
    const [checkingDelete, setCheckingDelete] = useState(false);

    // Form state
    const [name, setName] = useState("");
    const [selectedEmployees, setSelectedEmployees] = useState<string[]>([]);
    const [submitting, setSubmitting] = useState(false);
    const [dropdownOpen, setDropdownOpen] = useState(false);

    const loadServices = useCallback(async () => {
        try {
            const data = await getProjectServices(projectId);
            setServices((data || []).map((s: any) => ({
                id: s.id,
                name: s.name,
                projectId: s.projectId,
                employees: Array.isArray(s.employees) ? s.employees : [],
            })));
        } catch (err) {
            console.error("Failed to load services", err);
            toast.error("Failed to load services");
        } finally {
            setLoading(false);
        }
    }, [projectId]);

    useEffect(() => {
        loadServices();
    }, [loadServices]);

    useEffect(() => {
        setDirectoryUsers(users.filter(u => u.role !== 'client'));
    }, [users]);

    useEffect(() => {
        if (!isDialogOpen) return;

        let cancelled = false;
        getUsers()
            .then((loadedUsers) => {
                if (!cancelled) {
                    setDirectoryUsers(loadedUsers.filter((user) => user.role !== 'client'));
                }
            })
            .catch((error) => {
                console.error("Failed to load assignable users", error);
                toast.error("Failed to load team members");
            });

        return () => {
            cancelled = true;
        };
    }, [isDialogOpen]);

    const handleOpenDialog = (service?: ServiceItem) => {
        if (service) {
            setEditing(service);
            setName(service.name);
            setSelectedEmployees([...(service.employees || [])]);
        } else {
            setEditing(null);
            setName("");
            setSelectedEmployees([]);
        }
        setDropdownOpen(false);
        setIsDialogOpen(true);
    };

    const toggleEmployee = (userId: string) => {
        setSelectedEmployees(prev => {
            const idx = prev.indexOf(userId);
            if (idx >= 0) return prev.filter(id => id !== userId);
            return [...prev, userId];
        });
    };

    const getUserName = (uid: string) => {
        return directoryUsers.find(u => u.id === uid)?.name || users.find(u => u.id === uid)?.name || uid;
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!name.trim()) return;

        setSubmitting(true);
        try {
            if (editing) {
                await updateService(editing.id, name.trim(), projectId, selectedEmployees);
                toast.success("Service updated");
            } else {
                await addService(name.trim(), projectId, selectedEmployees);
                toast.success("Service created");
            }
            setIsDialogOpen(false);
            await loadServices();
            router.refresh();
        } catch (error: any) {
            toast.error(error?.message || "Failed to save service");
        } finally {
            setSubmitting(false);
        }
    };

    const handleDeleteClick = async (service: ServiceItem) => {
        setCheckingDelete(true);
        try {
            const count = await getServiceTaskCount(projectId, service.name);
            setDeleteTarget({ id: service.id, name: service.name, taskCount: count });
        } catch {
            toast.error("Failed to check service usage");
        } finally {
            setCheckingDelete(false);
        }
    };

    const handleConfirmDelete = async () => {
        if (!deleteTarget || deleteTarget.taskCount > 0) return;
        try {
            await deleteService(deleteTarget.id);
            toast.success(`"${deleteTarget.name}" deleted`);
            await loadServices();
            router.refresh();
        } catch (error: any) {
            toast.error(error?.message || "Failed to delete service");
        } finally {
            setDeleteTarget(null);
        }
    };

    // Only show non-client users in the employee dropdown
    const employeeUsers = directoryUsers;

    if (loading) {
        return (
            <div className="space-y-4 p-1">
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3 animate-pulse">
                    {[1, 2, 3].map(i => (
                        <div key={i} className="border border-border rounded-lg p-4 space-y-3">
                            <div className="h-5 w-32 bg-muted rounded" />
                            <div className="h-3 w-20 bg-muted/60 rounded" />
                            <div className="h-7 w-full bg-muted/40 rounded" />
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="space-y-4 p-1">
            <div className="flex items-center justify-between">
                <div>
                    <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Services</h3>
                </div>
                <Button onClick={() => handleOpenDialog()} size="sm" className="bg-primary text-primary-foreground hover:bg-primary/90">
                    <Plus className="mr-1.5 h-3.5 w-3.5" /> Add Service
                </Button>
            </div>

            {/* Service Cards */}
            {services.length > 0 ? (
                <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-3">
                    {services.map(service => (
                        <div key={service.id} className="border rounded-lg p-4 bg-background/50 hover:bg-background/80 transition-all border-border hover:border-primary/50 group relative">
                            <div className="flex justify-between items-start mb-3">
                                <div className="font-semibold text-sm">{service.name}</div>
                                <div className="flex gap-1 opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity">
                                    <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => handleOpenDialog(service)} aria-label={`Edit ${service.name}`} title={`Edit ${service.name}`}>
                                        <Edit2 className="h-3 w-3" />
                                    </Button>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        className="h-7 w-7 text-red-500 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20"
                                        disabled={checkingDelete}
                                        onClick={() => handleDeleteClick(service)}
                                        aria-label={`Delete ${service.name}`}
                                        title={`Delete ${service.name}`}
                                    >
                                        {checkingDelete ? <Loader2 className="h-3 w-3 animate-spin" /> : <Trash2 className="h-3 w-3" />}
                                    </Button>
                                </div>
                            </div>

                            <div className="flex items-center gap-1.5 text-xs text-muted-foreground mb-3">
                                <Users className="h-3.5 w-3.5" />
                                {(service.employees || []).length} Employee{(service.employees || []).length !== 1 ? 's' : ''}
                            </div>

                            {(service.employees || []).length > 0 ? (
                                <div className="flex flex-wrap gap-1">
                                    {(service.employees || []).map(empId => (
                                        <span key={empId} className="bg-primary/10 text-primary px-2 py-0.5 rounded-full text-[11px] font-medium">
                                            {getUserName(empId)}
                                        </span>
                                    ))}
                                </div>
                            ) : (
                                <div className="text-xs text-muted-foreground italic">No employees assigned</div>
                            )}
                        </div>
                    ))}
                </div>
            ) : (
                <div className="text-center py-12 text-muted-foreground text-sm border border-dashed border-border rounded-lg">
                    <Users className="h-8 w-8 mx-auto mb-2 opacity-30" />
                    No services added yet. Click "Add Service" to get started.
                </div>
            )}

            {/* Delete Confirmation */}
            <AlertDialog open={!!deleteTarget} onOpenChange={(open) => !open && setDeleteTarget(null)}>
                <AlertDialogContent>
                    <AlertDialogHeader>
                        <AlertDialogTitle>Delete Service</AlertDialogTitle>
                        <AlertDialogDescription asChild>
                            <div className="space-y-3">
                                {deleteTarget && deleteTarget.taskCount > 0 ? (
                                    <div className="flex items-start gap-3 p-3 rounded-lg bg-amber-500/10 border border-amber-500/30">
                                        <AlertTriangle className="h-5 w-5 text-amber-500 shrink-0 mt-0.5" />
                                        <div className="text-sm">
                                            <p className="font-semibold text-amber-600 dark:text-amber-400">
                                                Cannot delete &quot;{deleteTarget.name}&quot;
                                            </p>
                                            <p className="text-muted-foreground mt-1">
                                                <strong>{deleteTarget.taskCount} task{deleteTarget.taskCount !== 1 ? 's' : ''}</strong> {deleteTarget.taskCount === 1 ? 'is' : 'are'} still assigned to this service.
                                                Please reassign those tasks to another service first.
                                            </p>
                                        </div>
                                    </div>
                                ) : (
                                    <p>Are you sure you want to delete <strong>&quot;{deleteTarget?.name}&quot;</strong>? This action cannot be undone.</p>
                                )}
                            </div>
                        </AlertDialogDescription>
                    </AlertDialogHeader>
                    <AlertDialogFooter>
                        <AlertDialogCancel>Cancel</AlertDialogCancel>
                        {deleteTarget && deleteTarget.taskCount === 0 && (
                            <AlertDialogAction
                                onClick={handleConfirmDelete}
                                className="bg-red-600 hover:bg-red-700 text-white"
                            >
                                Delete
                            </AlertDialogAction>
                        )}
                    </AlertDialogFooter>
                </AlertDialogContent>
            </AlertDialog>

            {/* Add/Edit Service Dialog */}
            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent className="sm:max-w-[480px]">
                    <DialogHeader>
                        <DialogTitle>{editing ? "Edit Service" : "Add New Service"}</DialogTitle>
                        <DialogDescription>
                            {editing ? "Update the service name and assigned employees." : "Create a new service and assign employees."}
                        </DialogDescription>
                    </DialogHeader>
                    <form onSubmit={handleSubmit} className="space-y-5 py-4">
                        <div className="space-y-2">
                            <Label htmlFor="svc-name">Service Name <span className="text-red-500">*</span></Label>
                            <Input
                                id="svc-name"
                                value={name}
                                onChange={e => setName(e.target.value)}
                                placeholder="e.g. UI/UX Design, Web Development"
                                required
                                autoFocus
                            />
                        </div>

                        {/* Employee multi-select */}
                        <div className="space-y-2">
                            <Label>Assign Employees</Label>
                            <div className="relative">
                                <button
                                    type="button"
                                    onClick={() => setDropdownOpen(!dropdownOpen)}
                                    className="flex items-center justify-between w-full h-10 px-3 rounded-md border border-input bg-background text-sm text-left hover:bg-accent/50 transition-colors"
                                >
                                    <span className={selectedEmployees.length > 0 ? "text-foreground" : "text-muted-foreground"}>
                                        {selectedEmployees.length > 0
                                            ? `${selectedEmployees.length} employee${selectedEmployees.length > 1 ? 's' : ''} selected`
                                            : "Select employees..."}
                                    </span>
                                    <ChevronDown className={`h-4 w-4 text-muted-foreground transition-transform ${dropdownOpen ? 'rotate-180' : ''}`} />
                                </button>
                                {dropdownOpen && (
                                    <>
                                        <div className="fixed inset-0 z-[60]" onClick={() => setDropdownOpen(false)} />
                                        <div className="absolute top-full left-0 right-0 z-[70] mt-1 max-h-48 overflow-y-auto border border-border rounded-lg bg-popover shadow-lg">
                                            {employeeUsers.length > 0 ? employeeUsers.map(user => {
                                                const isSelected = selectedEmployees.includes(user.id);
                                                return (
                                                    <button
                                                        key={user.id}
                                                        type="button"
                                                        onClick={() => toggleEmployee(user.id)}
                                                        className={`w-full flex items-center gap-2.5 px-3 py-2.5 text-sm text-left hover:bg-accent/50 transition-colors ${isSelected ? 'bg-primary/5' : ''}`}
                                                    >
                                                        <div className={`w-4 h-4 rounded border flex items-center justify-center shrink-0 ${isSelected ? 'bg-primary border-primary' : 'border-input'}`}>
                                                            {isSelected && <Check className="w-3 h-3 text-primary-foreground" />}
                                                        </div>
                                                        <div className="flex-1 min-w-0">
                                                            <span className="font-medium">{user.name}</span>
                                                            {user.jobTitle && <span className="text-muted-foreground ml-1.5 text-xs">• {user.jobTitle}</span>}
                                                        </div>
                                                    </button>
                                                );
                                            }) : (
                                                <div className="px-3 py-3 text-sm text-muted-foreground">No team members found</div>
                                            )}
                                        </div>
                                    </>
                                )}
                            </div>

                            {/* Selected employee chips */}
                            {selectedEmployees.length > 0 && (
                                <div className="flex flex-wrap gap-1.5 pt-1">
                                    {selectedEmployees.map(empId => (
                                        <span
                                            key={empId}
                                            className="inline-flex items-center gap-1 px-2 py-0.5 rounded-full bg-primary/10 text-primary text-xs font-medium"
                                        >
                                            {getUserName(empId)}
                                            <button type="button" onClick={() => toggleEmployee(empId)} className="hover:text-red-500 transition-colors">
                                                <X className="h-3 w-3" />
                                            </button>
                                        </span>
                                    ))}
                                </div>
                            )}
                        </div>

                        <DialogFooter>
                            <Button type="button" variant="outline" onClick={() => setIsDialogOpen(false)}>Cancel</Button>
                            <Button type="submit" disabled={submitting} className="bg-primary text-primary-foreground hover:bg-primary/90">
                                {submitting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                {editing ? "Save Changes" : "Create Service"}
                            </Button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>
        </div>
    );
}

"use client";

import { useState, useMemo } from "react";
import Link from "next/link";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Plus, Search, AlertCircle, LayoutGrid, List, Loader2 } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { differenceInCalendarDays } from "date-fns";
import { CreateProjectWizard } from "@/components/projects/CreateProjectWizard";
import { useCurrency } from "@/context/CurrencyContext";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { useProgressiveList } from "@/hooks/use-infinite-scroll";
import { toLocalCalendarDay } from "@/lib/date-utils";

const STATUS_STYLES: Record<string, string> = {
    Active: "bg-emerald-500/15 text-emerald-600 dark:text-emerald-400",
    Completed: "bg-blue-500/15 text-blue-600 dark:text-blue-400",
    "On Hold": "bg-amber-500/15 text-amber-600 dark:text-amber-400",
    Cancelled: "bg-red-500/15 text-red-500",
};

function DaysLabel({ dueDate, status }: { dueDate?: string; status: string }) {
    if (!dueDate || status === 'Completed') return null;
    const today = toLocalCalendarDay(new Date());
    const due = toLocalCalendarDay(dueDate);
    if (!due || !today) return null;
    const diff = differenceInCalendarDays(due, today);

    if (diff < 0) return (
        <span className="text-[10px] font-semibold text-red-500 whitespace-nowrap">
            {Math.abs(diff)}d overdue
        </span>
    );
    if (diff === 0) return <span className="text-[10px] font-semibold text-amber-500 whitespace-nowrap">Due today</span>;
    if (diff <= 3) return <span className="text-[10px] font-semibold text-amber-500 whitespace-nowrap">{diff}d left</span>;
    return <span className="text-[10px] text-muted-foreground whitespace-nowrap">{diff}d left</span>;
}

function TaskStatusPills({ todo, inProgress, done }: { todo: number; inProgress: number; done: number }) {
    if (todo + inProgress + done === 0) return <span className="text-[10px] text-muted-foreground">No tasks yet</span>;
    return (
        <div className="flex items-center gap-2 text-[10px] font-medium">
            {todo > 0 && <span className="text-muted-foreground">{todo} Todo</span>}
            {inProgress > 0 && <span className="text-indigo-400">{inProgress} In Progress</span>}
            {done > 0 && <span className="text-emerald-500">{done} Done</span>}
        </div>
    );
}

interface ProjectsContentProps {
    initialProjects: any[];
    initialServices: any[];
    initialTasks: any[];
    initialUsers: any[];
    currentUser: any;
}

export function ProjectsContent({
    initialProjects,
    initialServices,
    initialTasks,
    initialUsers,
    currentUser,
}: ProjectsContentProps) {
    const [projects, setProjects] = useState(initialProjects);
    const { format: formatMoney } = useCurrency();
    const [services] = useState(initialServices);
    const [allTasks] = useState(initialTasks);
    const [allUsers] = useState(initialUsers);
    const [showWizard, setShowWizard] = useState(false);

    // Filters
    const [search, setSearch] = useState("");
    const [searchExpanded, setSearchExpanded] = useState(false);
    const [statusFilter, setStatusFilter] = useState("All");
    const [sortBy, setSortBy] = useState<"dueDate" | "budget" | "name" | "progress">("dueDate");
    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");

    const isAdmin = currentUser?.role === 'admin' || currentUser?.role === 'manager';
    const today = useMemo(() => toLocalCalendarDay(new Date()) ?? new Date(), []);

    // Per-project computed data
    const projectData = useMemo(() => {
        return projects.map(p => {
            const pTasks = allTasks.filter((t: any) => t.projectId === p.id);
            const done = pTasks.filter((t: any) => t.status === 'Done').length;
            const inProgress = pTasks.filter((t: any) => t.status === 'In Progress').length;
            const todo = pTasks.filter((t: any) => t.status === 'Todo').length;
            const total = pTasks.length;
            const pct = total > 0 ? Math.round((done / total) * 100) : 0;
            const due = toLocalCalendarDay(p.dueDate);
            const isOverdue = !!due && due < today && p.status !== 'Completed';
            const assigneeIds = [...new Set(pTasks.map((t: any) => t.assigneeId).filter(Boolean))] as string[];
            const totalAssignees = assigneeIds.length;
            const assignees = assigneeIds.slice(0, 3).map(id => allUsers.find((u: any) => u.id === id)).filter(Boolean);
            return { ...p, pct, done, inProgress, todo, total, isOverdue, assignees, totalAssignees };
        });
    }, [projects, allTasks, allUsers, today]);

    // Filtered + sorted
    const filtered = useMemo(() => {
        let list = projectData;
        if (statusFilter !== 'All') list = list.filter(p => p.status === statusFilter);
        if (search.trim()) list = list.filter(p =>
            p.name.toLowerCase().includes(search.toLowerCase()) ||
            (p.client || '').toLowerCase().includes(search.toLowerCase())
        );
        list = [...list].sort((a, b) => {
            if (sortBy === 'name') return a.name.localeCompare(b.name);
            if (sortBy === 'budget') return (b.budget || 0) - (a.budget || 0);
            if (sortBy === 'progress') return b.pct - a.pct;
            const da = toLocalCalendarDay(a.dueDate)?.getTime() ?? Infinity;
            const db = toLocalCalendarDay(b.dueDate)?.getTime() ?? Infinity;
            return da - db;
        });
        return list;
    }, [projectData, statusFilter, search, sortBy]);

    const statuses = ['All', ...Array.from(new Set(projects.map(p => p.status)))];

    const { visibleCount, sentinelRef, hasMore } = useProgressiveList(filtered.length, 12, [statusFilter, search, sortBy]);

    const handleProjectCreated = async () => {
        // Re-fetch projects from the server after creation
        const { getProjects } = await import("@/lib/actions");
        const freshProjects = await getProjects();
        setProjects(freshProjects);
    };

    const ProjectCard = ({ project }: { project: any }) => (
        <Link href={`/dashboard/projects/${project.slug || project.id}`} className="block group">
            <Card className={`h-full transition-all border-border hover:border-primary/50 hover:shadow-lg ${project.isOverdue ? 'border-red-500/30' : ''}`}>
                <CardHeader className="pb-2">
                    <div className="flex justify-between items-start gap-2">
                        <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-1.5">
                                {project.isOverdue && <AlertCircle className="h-3.5 w-3.5 text-red-500 shrink-0" />}
                                <h2 className="font-semibold leading-none tracking-tight text-base truncate group-hover:text-primary transition-colors">{project.name}</h2>
                            </div>
                            <div className="flex flex-wrap gap-1 mt-1.5">
                                {project.client && project.client !== project.name && (
                                    <Badge variant="outline" className="font-normal text-xs">{project.client}</Badge>
                                )}
                                {project.services?.slice(0, 2).map((svcId: string) => {
                                    const svc = services.find((s: any) => s.id === svcId);
                                    return (
                                        <Badge key={svcId} variant="secondary" className="font-normal text-xs bg-yellow-500/10 text-yellow-600 border-yellow-500/20">
                                            {svc?.name || svcId}
                                        </Badge>
                                    );
                                })}
                            </div>
                        </div>
                        <span className={`shrink-0 px-2 py-0.5 rounded-full text-xs font-semibold ${STATUS_STYLES[project.status] || 'bg-muted text-muted-foreground'}`}>
                            {project.status}
                        </span>
                    </div>
                </CardHeader>

                <CardContent className="space-y-3">
                    {/* Task status breakdown */}
                    <TaskStatusPills todo={project.todo} inProgress={project.inProgress} done={project.done} />

                    {/* Progress Bar */}
                    <div className="space-y-1">
                        <div className="flex justify-between text-xs text-muted-foreground">
                            <span>{project.done}/{project.total} tasks</span>
                            <span className="font-semibold">{project.pct}%</span>
                        </div>
                        <div className="h-1.5 w-full rounded-full bg-muted overflow-hidden">
                            <div
                                className={`h-full rounded-full transition-all duration-500 ${project.pct === 100 ? 'bg-emerald-500' : project.pct >= 50 ? 'bg-indigo-500' : 'bg-amber-500'}`}
                                style={{ width: `${project.pct}%` }}
                            />
                        </div>
                    </div>

                    {/* Footer */}
                    <div className="flex items-center justify-between pt-0.5">
                        {/* Assignee Avatars */}
                        <div className="flex items-center gap-1.5">
                            <div className="flex -space-x-2">
                                {project.assignees.length > 0 ? project.assignees.map((u: any) => (
                                    <Avatar key={u.id} className="h-6 w-6 border-2 border-background" title={u.name}>
                                        <AvatarImage src={u.avatar} alt={u.name || 'Team member'} />
                                        <AvatarFallback className="text-[8px] bg-primary/10 text-primary font-bold">
                                            {u.name?.substring(0, 2).toUpperCase()}
                                        </AvatarFallback>
                                    </Avatar>
                                )) : (
                                    <span className="text-[10px] text-muted-foreground">No assigned</span>
                                )}
                                {project.totalAssignees > 3 && (
                                    <div className="h-6 w-6 rounded-full bg-muted border-2 border-background flex items-center justify-center text-[8px] font-bold text-muted-foreground" title={`${project.totalAssignees - 3} more`}>
                                        +{project.totalAssignees - 3}
                                    </div>
                                )}
                            </div>
                        </div>

                        <div className="flex items-center gap-2">
                            {project.budget > 0 && (
                                <span className="text-xs text-muted-foreground font-medium">{formatMoney(project.budget)}</span>
                            )}
                            <DaysLabel dueDate={project.dueDate} status={project.status} />
                        </div>
                    </div>
                </CardContent>
            </Card>
        </Link>
    );

    const ProjectRow = ({ project }: { project: any }) => (
        <Link href={`/dashboard/projects/${project.slug || project.id}`} className="block group">
            <div className={`flex items-center gap-4 rounded-lg border px-4 py-3 bg-card transition-all hover:border-primary/50 hover:shadow-md ${project.isOverdue ? 'border-red-500/30' : 'border-border'}`}>
                {/* Name + badges */}
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1.5">
                        {project.isOverdue && <AlertCircle className="h-3.5 w-3.5 text-red-500 shrink-0" />}
                        <span className="font-medium text-sm truncate group-hover:text-primary transition-colors">{project.name}</span>
                    </div>
                    <div className="flex items-center gap-2 mt-0.5">
                        {project.client && project.client !== project.name && (
                            <span className="text-[10px] text-muted-foreground">{project.client}</span>
                        )}
                        <TaskStatusPills todo={project.todo} inProgress={project.inProgress} done={project.done} />
                    </div>
                </div>

                {/* Progress pill */}
                <div className="hidden sm:flex items-center gap-2 w-32">
                    <div className="flex-1 h-1.5 rounded-full bg-muted overflow-hidden">
                        <div className={`h-full rounded-full ${project.pct === 100 ? 'bg-emerald-500' : project.pct >= 50 ? 'bg-indigo-500' : 'bg-amber-500'}`} style={{ width: `${project.pct}%` }} />
                    </div>
                    <span className="text-[10px] font-semibold text-muted-foreground w-7 shrink-0">{project.pct}%</span>
                </div>

                {/* Avatars */}
                <div className="hidden md:flex -space-x-1.5">
                    {project.assignees.map((u: any) => (
                        <Avatar key={u.id} className="h-5 w-5 border border-background" title={u.name}>
                            <AvatarImage src={u.avatar} alt={u.name || 'Team member'} />
                            <AvatarFallback className="text-[7px] bg-primary/10 text-primary font-bold">{u.name?.substring(0, 2).toUpperCase()}</AvatarFallback>
                        </Avatar>
                    ))}
                    {project.totalAssignees > 3 && (
                        <div className="h-5 w-5 rounded-full bg-muted border border-background flex items-center justify-center text-[7px] font-bold text-muted-foreground" title={`${project.totalAssignees - 3} more`}>
                            +{project.totalAssignees - 3}
                        </div>
                    )}
                </div>

                {/* Status */}
                <span className={`shrink-0 px-2 py-0.5 rounded-full text-[10px] font-semibold ${STATUS_STYLES[project.status] || 'bg-muted text-muted-foreground'}`}>{project.status}</span>

                {/* Days left */}
                <div className="w-16 text-right">
                    <DaysLabel dueDate={project.dueDate} status={project.status} />
                </div>
            </div>
        </Link>
    );

    return (
        <div className="space-y-5">
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
                <div>
                    <h1 className="text-2xl sm:text-3xl font-bold">Projects</h1>
                    <p className="text-sm text-muted-foreground mt-0.5">
                        {filtered.length} of {projects.length} project{projects.length !== 1 ? 's' : ''}
                    </p>
                </div>
                <div className="flex items-center gap-2 flex-wrap">
                    {/* Search */}
                    <div className={`flex items-center transition-all duration-200 border border-input rounded-md bg-background overflow-hidden ${searchExpanded ? 'w-52' : 'w-9'} h-9`}>
                        <button aria-label="Search projects" className="p-2 shrink-0" onClick={() => setSearchExpanded(v => !v)}>
                            <Search className="h-4 w-4 text-muted-foreground" />
                        </button>
                        {searchExpanded && (
                            <input
                                autoFocus
                                value={search}
                                onChange={e => setSearch(e.target.value)}
                                placeholder="Search..."
                                className="flex-1 bg-transparent text-sm outline-none pr-2"
                            />
                        )}
                    </div>

                    {/* Sort */}
                    <select
                        aria-label="Sort projects"
                        value={sortBy}
                        onChange={e => setSortBy(e.target.value as any)}
                        className="h-9 rounded-md border border-input bg-background px-3 text-sm text-muted-foreground cursor-pointer"
                    >
                        <option value="dueDate">Sort: Due Date</option>
                        <option value="progress">Sort: Progress</option>
                        <option value="budget">Sort: Budget</option>
                        <option value="name">Sort: Name</option>
                    </select>

                    {/* View toggle */}
                    <div className="flex items-center border border-input rounded-md overflow-hidden h-9">
                        <button aria-label="Grid view" onClick={() => setViewMode('grid')} className={`px-2.5 h-full flex items-center transition-colors ${viewMode === 'grid' ? 'bg-primary text-primary-foreground' : 'hover:bg-muted text-muted-foreground'}`}>
                            <LayoutGrid className="h-4 w-4" />
                        </button>
                        <button aria-label="List view" onClick={() => setViewMode('list')} className={`px-2.5 h-full flex items-center transition-colors ${viewMode === 'list' ? 'bg-primary text-primary-foreground' : 'hover:bg-muted text-muted-foreground'}`}>
                            <List className="h-4 w-4" />
                        </button>
                    </div>

                    {isAdmin && (
                        <button
                            onClick={() => setShowWizard(true)}
                            className="inline-flex items-center gap-1.5 rounded-md text-sm font-medium bg-primary text-primary-foreground hover:bg-primary/90 h-9 px-4 transition-colors"
                        >
                            <Plus className="h-4 w-4" /> New Project
                        </button>
                    )}
                </div>
            </div>

            {/* Status Pills */}
            <div className="flex flex-wrap gap-2">
                {statuses.map(s => (
                    <button
                        key={s}
                        onClick={() => setStatusFilter(s)}
                        className={`px-3 py-1 rounded-full text-xs font-medium transition-colors border ${statusFilter === s
                            ? 'bg-primary text-primary-foreground border-primary'
                            : 'border-border bg-background hover:bg-muted text-muted-foreground'
                            }`}
                    >{s}</button>
                ))}
            </div>

            <CreateProjectWizard open={showWizard} onOpenChange={setShowWizard} onProjectCreated={handleProjectCreated} />

            {filtered.length === 0 ? (
                <div className="text-center py-16 text-muted-foreground">
                    <p className="text-lg font-medium">No projects found</p>
                    <p className="text-sm mt-1">Try a different filter or search term</p>
                </div>
            ) : viewMode === 'grid' ? (
                <>
                    <div className="grid gap-4 grid-cols-1 md:grid-cols-2 lg:grid-cols-3">
                        {filtered.slice(0, visibleCount).map(project => <ProjectCard key={project.id} project={project} />)}
                    </div>
                    {hasMore && (
                        <div ref={sentinelRef} className="flex justify-center py-6">
                            <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                        </div>
                    )}
                </>
            ) : (
                <>
                    <div className="flex flex-col gap-2">
                        {/* List header */}
                        <div className="hidden sm:grid grid-cols-[1fr_140px_80px_100px_80px] gap-4 px-4 text-xs font-medium text-muted-foreground uppercase tracking-wide">
                            <span>Project</span>
                            <span>Progress</span>
                            <span>Team</span>
                            <span>Status</span>
                            <span className="text-right">Due</span>
                        </div>
                        {filtered.slice(0, visibleCount).map(project => <ProjectRow key={project.id} project={project} />)}
                    </div>
                    {hasMore && (
                        <div ref={sentinelRef} className="flex justify-center py-6">
                            <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                        </div>
                    )}
                </>
            )}
        </div>
    );
}

