"use client";

import { createContext, useContext, useEffect, useState } from "react";

type Theme = "dark" | "light";

interface ThemeContextType {
    theme: Theme;
    setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextType>({
    theme: "dark",
    setTheme: () => { },
});

export function ThemeProvider({ children }: { children: React.ReactNode }) {
    const [theme, setTheme] = useState<Theme>("dark");
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        // Read from localStorage on mount
        const stored = localStorage.getItem("agency-os-theme") as Theme | null;
        if (stored === "light" || stored === "dark") {
            setTheme(stored);
        }
        setMounted(true);
    }, []);

    useEffect(() => {
        if (!mounted) return;

        const root = document.documentElement;
        // Toggle dark class on <html> element
        if (theme === "dark") {
            root.classList.add("dark");
        } else {
            root.classList.remove("dark");
        }

        // Also update the body class for backward compat
        if (theme === "dark") {
            document.body.classList.add("dark");
        } else {
            document.body.classList.remove("dark");
        }

        // Update sonner toaster theme
        const toaster = document.querySelector('[data-sonner-toaster]');
        if (toaster) {
            toaster.setAttribute('data-theme', theme);
        }

        localStorage.setItem("agency-os-theme", theme);
    }, [theme, mounted]);

    // Prevent flash of wrong theme
    if (!mounted) {
        return <>{children}</>;
    }

    return (
        <ThemeContext.Provider value={{ theme, setTheme }}>
            {children}
        </ThemeContext.Provider>
    );
}

export function useTheme() {
    const context = useContext(ThemeContext);
    if (!context) {
        throw new Error("useTheme must be used within a ThemeProvider");
    }
    return context;
}

"use client";

import { useState, useEffect } from "react";
import { updateAgencyDetails } from "@/lib/actions";
import { toast } from "sonner";
import { Loader2, Building, Upload, Image as ImageIcon } from "lucide-react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";

interface AgencySettingsProps {
    initialSettings?: {
        name: string;
        logo: string;
        primaryColor?: string;
        secondaryColor?: string;
    } | null;
    loading?: boolean;
    onSaved?: () => void;
}

export function AgencySettings({ initialSettings, loading: parentLoading, onSaved }: AgencySettingsProps) {
    const [name, setName] = useState("");
    const [logo, setLogo] = useState("");
    const [saving, setSaving] = useState(false);
    const [logoPreview, setLogoPreview] = useState("");

    // Sync from parent props
    useEffect(() => {
        if (initialSettings) {
            setName(initialSettings.name);
            setLogo(initialSettings.logo);
            setLogoPreview(initialSettings.logo);

        }
    }, [initialSettings]);

    const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > 2 * 1024 * 1024) {
            toast.error("Logo file is too large. Max 2MB.");
            return;
        }

        const reader = new FileReader();
        reader.onload = (e) => {
            const result = e.target?.result as string;
            setLogo(result);
            setLogoPreview(result);
        };
        reader.readAsDataURL(file);
    };



    const handleSave = async (e: React.FormEvent) => {
        e.preventDefault();
        setSaving(true);
        try {
            await updateAgencyDetails(name, logo);
            toast.success("Agency details updated successfully!");
            onSaved?.();
        } catch (error) {
            console.error("Failed to update agency details", error);
            toast.error("Failed to update details.");
        } finally {
            setSaving(false);
        }
    };

    if (parentLoading) {
        return <div className="p-4 flex justify-center"><Loader2 className="h-6 w-6 animate-spin text-muted-foreground" /></div>;
    }

    return (
        <Card>
            <CardHeader>
                <div className="flex items-center gap-2">
                    <div className="p-2 bg-indigo-500/10 rounded-full">
                        <Building className="h-6 w-6 text-indigo-500" />
                    </div>
                    <div>
                        <CardTitle>Agency Branding</CardTitle>
                        <CardDescription>Update your agency's identity and logo.</CardDescription>
                    </div>
                </div>
            </CardHeader>
            <CardContent>
                <form onSubmit={handleSave} className="space-y-6 max-w-lg">
                    <div className="space-y-2">
                        <Label htmlFor="agency-name">Agency Name</Label>
                        <Input
                            id="agency-name"
                            value={name}
                            onChange={(e) => setName(e.target.value)}
                            placeholder="My Awesome Agency"
                            required
                        />
                    </div>

                    {/* Logo Upload */}
                    <div className="space-y-4">
                        <Label>Agency Logo</Label>
                        <div className="flex items-center gap-6">
                            <Avatar className="h-20 w-20 border-2 border-dashed border-border">
                                <AvatarImage src={logoPreview} />
                                <AvatarFallback className="bg-muted text-muted-foreground">
                                    <ImageIcon className="h-8 w-8 opacity-50" />
                                </AvatarFallback>
                            </Avatar>

                            <div className="space-y-2">
                                <div className="flex items-center gap-2">
                                    <Button type="button" variant="outline" size="sm" className="relative cursor-pointer overflow-hidden">
                                        <Upload className="mr-2 h-4 w-4" />
                                        Upload Logo
                                        <Input
                                            type="file"
                                            className="absolute inset-0 opacity-0 cursor-pointer"
                                            accept="image/*"
                                            onChange={handleLogoUpload}
                                        />
                                    </Button>
                                    {logo && (
                                        <Button type="button" variant="ghost" size="sm" onClick={() => { setLogo(""); setLogoPreview(""); }}>
                                            Remove
                                        </Button>
                                    )}
                                </div>
                                <p className="text-xs text-muted-foreground">
                                    Recommended: Square PNG or JPG, max 2MB.
                                </p>
                            </div>
                        </div>
                    </div>



                    <div className="pt-2">
                        <Button type="submit" disabled={saving}>
                            {saving && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                            Save Changes
                        </Button>
                    </div>
                </form>
            </CardContent>
        </Card>
    );
}

"use client";

import { useState, useEffect } from "react";
import { updateEmailSettings, updateEmailCategorySettings, updateTaskEmailEvents } from "@/lib/actions";
import { toast } from "sonner";
import { Loader2, Mail, AlertTriangle, Shield, Zap } from "lucide-react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { EMAIL_CATEGORY_INFO, DEFAULT_EMAIL_CATEGORIES, TASK_EMAIL_EVENTS, DEFAULT_TASK_EMAIL_EVENTS } from "@/lib/email-constants";
import type { EmailCategory, TaskEmailEventKey, TaskEmailEventConfig } from "@/lib/email-constants";

interface EmailSettingsProps {
    initialEnabled?: boolean;
    initialCategories?: Record<string, any>;
    loading?: boolean;
}

const DEFAULT_EVENTS = { ...DEFAULT_TASK_EMAIL_EVENTS };

export function EmailSettings({ initialEnabled = true, initialCategories, loading: parentLoading }: EmailSettingsProps) {
    const [enabled, setEnabled] = useState(initialEnabled);
    const [updating, setUpdating] = useState(false);
    const [categories, setCategories] = useState<Record<string, boolean>>(
        initialCategories || { ...DEFAULT_EMAIL_CATEGORIES }
    );
    const [taskEmailEvents, setTaskEmailEvents] = useState<Record<TaskEmailEventKey, TaskEmailEventConfig>>(() => {
        const events = { ...DEFAULT_EVENTS };
        if (initialCategories?.taskEmailEvents) {
            for (const key of Object.keys(events) as TaskEmailEventKey[]) {
                if (initialCategories.taskEmailEvents[key]) {
                    events[key] = { ...events[key], ...initialCategories.taskEmailEvents[key] };
                }
            }
        }
        return events;
    });
    const [updatingCategory, setUpdatingCategory] = useState<string | null>(null);
    const [updatingEvent, setUpdatingEvent] = useState<string | null>(null);

    useEffect(() => {
        setEnabled(initialEnabled);
    }, [initialEnabled]);

    useEffect(() => {
        if (initialCategories) {
            setCategories({ ...DEFAULT_EMAIL_CATEGORIES, ...initialCategories });
            if (initialCategories.taskEmailEvents) {
                setTaskEmailEvents(prev => {
                    const merged = { ...prev };
                    for (const key of Object.keys(prev) as TaskEmailEventKey[]) {
                        if (initialCategories.taskEmailEvents[key]) {
                            merged[key] = { ...prev[key], ...initialCategories.taskEmailEvents[key] };
                        }
                    }
                    return merged;
                });
            }
        }
    }, [initialCategories]);

    const handleToggle = async (checked: boolean) => {
        setEnabled(checked);
        setUpdating(true);
        try {
            await updateEmailSettings(checked);
            toast.success(checked ? "Email notifications enabled" : "Email notifications disabled");
        } catch (error) {
            console.error("Failed to update email settings", error);
            toast.error("Failed to update settings");
            setEnabled(!checked);
        } finally {
            setUpdating(false);
        }
    };

    const handleCategoryToggle = async (category: string, checked: boolean) => {
        setCategories(prev => ({ ...prev, [category]: checked }));
        setUpdatingCategory(category);
        try {
            await updateEmailCategorySettings({ [category]: checked });
            const info = EMAIL_CATEGORY_INFO[category as EmailCategory];
            toast.success(`${info?.label || category} emails ${checked ? 'enabled' : 'disabled'}`);
        } catch (error) {
            console.error("Failed to update category", error);
            toast.error("Failed to update");
            setCategories(prev => ({ ...prev, [category]: !checked }));
        } finally {
            setUpdatingCategory(null);
        }
    };

    const handleEventToggle = async (eventKey: TaskEmailEventKey, field: keyof TaskEmailEventConfig, checked: boolean) => {
        setTaskEmailEvents(prev => ({
            ...prev,
            [eventKey]: { ...prev[eventKey], [field]: checked },
        }));
        setUpdatingEvent(`${eventKey}-${field}`);
        try {
            await updateTaskEmailEvents({ [eventKey]: { [field]: checked } });
            const info = TASK_EMAIL_EVENTS[eventKey];
            toast.success(`${info.label} — ${field === 'enabled' ? (checked ? 'enabled' : 'disabled') : `${field} ${checked ? 'on' : 'off'}`}`);
        } catch (error) {
            console.error("Failed to update event", error);
            toast.error("Failed to update");
            setTaskEmailEvents(prev => ({
                ...prev,
                [eventKey]: { ...prev[eventKey], [field]: !checked },
            }));
        } finally {
            setUpdatingEvent(null);
        }
    };

    if (parentLoading) {
        return <div className="p-4 flex justify-center"><Loader2 className="h-6 w-6 animate-spin text-muted-foreground" /></div>;
    }

    const categoryEntries = Object.entries(EMAIL_CATEGORY_INFO) as [EmailCategory, typeof EMAIL_CATEGORY_INFO[EmailCategory]][];

    return (
        <div className="space-y-4">
            {/* Global Kill Switch */}
            <Card className={enabled ? "border-green-500/20 bg-green-500/5" : "border-red-500/20 bg-red-500/5"}>
                <CardHeader className="pb-3">
                    <div className="flex items-center gap-2">
                        <div className={`p-2 rounded-full ${enabled ? 'bg-green-500/10' : 'bg-red-500/10'}`}>
                            <Mail className={`h-5 w-5 ${enabled ? 'text-green-500' : 'text-red-500'}`} />
                        </div>
                        <div className="flex-1">
                            <CardTitle className="text-base">Email Service</CardTitle>
                            <CardDescription>Master switch for all outgoing emails</CardDescription>
                        </div>
                        <div className="flex items-center gap-2">
                            {updating && <Loader2 className="h-3 w-3 animate-spin text-muted-foreground" />}
                            <Switch
                                id="email-switch"
                                checked={enabled}
                                onCheckedChange={handleToggle}
                                disabled={updating}
                            />
                        </div>
                    </div>
                    {!enabled && (
                        <div className="flex items-center gap-2 mt-2 text-xs text-red-400 bg-red-500/10 px-2 py-1 rounded w-fit">
                            <AlertTriangle className="h-3 w-3" />
                            <span>All emails are currently disabled. No emails will be sent.</span>
                        </div>
                    )}
                </CardHeader>
            </Card>

            {/* Per-Category Toggles */}
            {enabled && (
                <Card>
                    <CardHeader className="pb-3">
                        <CardTitle className="text-base">Email Categories</CardTitle>
                        <CardDescription>Choose which email types to send. Critical emails are recommended to stay ON.</CardDescription>
                    </CardHeader>
                    <CardContent className="space-y-1">
                        {categoryEntries.map(([key, info]) => {
                            const isOn = categories[key] ?? DEFAULT_EMAIL_CATEGORIES[key];
                            const isUpdating = updatingCategory === key;

                            return (
                                <div key={key}>
                                    <div className="flex items-center justify-between py-2.5 px-3 rounded-lg hover:bg-muted/50 transition-colors">
                                        <div className="flex items-center gap-3 flex-1 min-w-0">
                                            <div className={`p-1.5 rounded-md ${info.priority === 'critical' ? 'bg-amber-500/10' : 'bg-blue-500/10'}`}>
                                                {info.priority === 'critical'
                                                    ? <Shield className="h-4 w-4 text-amber-500" />
                                                    : <Zap className="h-4 w-4 text-blue-500" />
                                                }
                                            </div>
                                            <div className="min-w-0">
                                                <div className="flex items-center gap-2">
                                                    <Label className="text-sm font-medium cursor-pointer">{info.label}</Label>
                                                    <Badge variant={info.priority === 'critical' ? 'default' : 'secondary'} className="text-[10px] px-1.5 py-0">
                                                        {info.priority}
                                                    </Badge>
                                                </div>
                                                <p className="text-xs text-muted-foreground truncate">{info.description}</p>
                                            </div>
                                        </div>
                                        <div className="flex items-center gap-2 ml-2">
                                            {isUpdating && <Loader2 className="h-3 w-3 animate-spin text-muted-foreground" />}
                                            <Switch
                                                checked={isOn}
                                                onCheckedChange={(checked) => handleCategoryToggle(key, checked)}
                                                disabled={isUpdating}
                                            />
                                        </div>
                                    </div>

                                    {/* Task Email Event Sub-toggles */}
                                    {key === 'taskUpdates' && isOn && (
                                        <div className="ml-12 pl-3 border-l-2 border-blue-500/20 space-y-2 py-1 mb-1">
                                            <p className="text-xs text-muted-foreground mb-1">Configure task email events and recipients:</p>
                                            {(Object.entries(TASK_EMAIL_EVENTS) as [TaskEmailEventKey, typeof TASK_EMAIL_EVENTS[TaskEmailEventKey]][]).map(([eventKey, eventInfo]) => {
                                                const eventConfig = taskEmailEvents[eventKey] || DEFAULT_TASK_EMAIL_EVENTS[eventKey];
                                                return (
                                                    <div key={eventKey} className="rounded-lg bg-muted/20 p-2">
                                                        <div className="flex items-center justify-between py-1">
                                                            <div>
                                                                <span className="text-xs font-medium text-foreground">{eventInfo.label}</span>
                                                                <p className="text-[10px] text-muted-foreground">{eventInfo.description}</p>
                                                            </div>
                                                            <div className="flex items-center gap-2">
                                                                {updatingEvent === `${eventKey}-enabled` && <Loader2 className="h-3 w-3 animate-spin text-muted-foreground" />}
                                                                <Switch
                                                                    checked={eventConfig.enabled}
                                                                    onCheckedChange={(checked) => handleEventToggle(eventKey, 'enabled', checked)}
                                                                    disabled={!!updatingEvent}
                                                                    className="scale-[0.8]"
                                                                />
                                                            </div>
                                                        </div>
                                                        {eventConfig.enabled && (
                                                            <div className="ml-4 mt-1 space-y-1 border-l border-border pl-3">
                                                                <div className="flex items-center justify-between py-1">
                                                                    <span className="text-[11px] text-muted-foreground">Send to Assignee</span>
                                                                    <div className="flex items-center gap-2">
                                                                        {updatingEvent === `${eventKey}-notifyAssignee` && <Loader2 className="h-2.5 w-2.5 animate-spin text-muted-foreground" />}
                                                                        <Switch
                                                                            checked={eventConfig.notifyAssignee}
                                                                            onCheckedChange={(checked) => handleEventToggle(eventKey, 'notifyAssignee', checked)}
                                                                            disabled={!!updatingEvent}
                                                                            className="scale-[0.7]"
                                                                        />
                                                                    </div>
                                                                </div>
                                                                <div className="flex items-center justify-between py-1">
                                                                    <span className="text-[11px] text-muted-foreground">Send to Project Client</span>
                                                                    <div className="flex items-center gap-2">
                                                                        {updatingEvent === `${eventKey}-notifyClient` && <Loader2 className="h-2.5 w-2.5 animate-spin text-muted-foreground" />}
                                                                        <Switch
                                                                            checked={eventConfig.notifyClient}
                                                                            onCheckedChange={(checked) => handleEventToggle(eventKey, 'notifyClient', checked)}
                                                                            disabled={!!updatingEvent}
                                                                            className="scale-[0.7]"
                                                                        />
                                                                    </div>
                                                                </div>
                                                            </div>
                                                        )}
                                                    </div>
                                                );
                                            })}
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </CardContent>
                </Card>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect, useCallback } from 'react';
import { UserPermissions, DEFAULT_USER_PERMISSIONS } from '@/lib/types';
import type { User, Client } from '@/lib/types';
import { getUsers, getUserPermissions, updateUserPermissions, getClients } from '@/lib/actions';
import { motion, AnimatePresence } from 'framer-motion';
import { toast } from 'sonner';
import { Search, User as UserIcon, Building2, Trash2, Sparkles, FolderPlus, Loader2 } from 'lucide-react';
import Image from 'next/image';
import { Switch } from '@/components/ui/switch';

export default function PermissionSettings() {
    const [users, setUsers] = useState<User[]>([]);
    const [clients, setClients] = useState<Client[]>([]);
    const [permissionsMap, setPermissionsMap] = useState<Record<string, UserPermissions>>({});
    const [loading, setLoading] = useState(true);
    const [activeTab, setActiveTab] = useState<'employees' | 'clients'>('employees');
    const [searchQuery, setSearchQuery] = useState('');

    const loadData = useCallback(async () => {
        try {
            const [usersData, clientsData] = await Promise.all([getUsers(), getClients()]);
            const employees = usersData.filter((u: User) => u.role !== 'admin');
            setUsers(employees);
            setClients(clientsData);

            // Fetch permissions in PARALLEL instead of sequentially
            const allIds = [...employees.map((u: User) => u.id), ...clientsData.map((c: Client) => c.id)];
            const permResults = await Promise.all(
                allIds.map(async (id) => {
                    try {
                        const perm = await getUserPermissions(id);
                        return [id, perm] as [string, UserPermissions];
                    } catch {
                        return [id, { ...DEFAULT_USER_PERMISSIONS }] as [string, UserPermissions];
                    }
                })
            );
            const perms: Record<string, UserPermissions> = {};
            for (const [id, perm] of permResults) {
                perms[id] = perm;
            }
            setPermissionsMap(perms);
        } catch (error) {
            console.error("Failed to load permission data", error);
            toast.error("Failed to load permissions");
        } finally {
            setLoading(false);
        }
    }, []);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const handleUpdatePermission = async (
        userId: string,
        key: keyof UserPermissions,
        value: boolean | string
    ) => {
        const currentPerms = permissionsMap[userId] || { ...DEFAULT_USER_PERMISSIONS };
        const newPerms = { ...currentPerms, [key]: value };

        // Optimistic UI
        setPermissionsMap(prev => ({ ...prev, [userId]: newPerms }));

        try {
            await updateUserPermissions(userId, newPerms);
        } catch (error) {
            console.error("Failed to update permissions", error);
            toast.error("Failed to update permission");
            // Revert on error
            setPermissionsMap(prev => ({ ...prev, [userId]: currentPerms }));
        }
    };

    const filteredList = activeTab === 'employees'
        ? users.filter(u => u.name.toLowerCase().includes(searchQuery.toLowerCase()) || u.email.toLowerCase().includes(searchQuery.toLowerCase()))
        : clients.filter(c => c.name.toLowerCase().includes(searchQuery.toLowerCase()) || c.email.toLowerCase().includes(searchQuery.toLowerCase()));

    if (loading) return (
        <div className="p-8 flex items-center justify-center gap-2 text-muted-foreground">
            <Loader2 className="h-5 w-5 animate-spin" />
            <span>Loading permissions...</span>
        </div>
    );

    return (
        <div className="space-y-6">
            {/* Tabs & Search Toolbar */}
            <div className="flex flex-col md:flex-row items-center justify-between gap-4 border-b border-white/5 pb-2">
                <div className="flex gap-4">
                    <button
                        onClick={() => setActiveTab('employees')}
                        className={`pb-2 px-4 text-sm font-medium transition-colors relative ${activeTab === 'employees' ? 'text-yellow-400' : 'text-muted-foreground hover:text-foreground'}`}
                    >
                        <div className="flex items-center gap-2">
                            <UserIcon className="w-4 h-4" />
                            Employees
                        </div>
                        {activeTab === 'employees' && <motion.div layoutId="perm-tab-underline" className="absolute bottom-[-9px] left-0 right-0 h-0.5 bg-yellow-400" />}
                    </button>
                    <button
                        onClick={() => setActiveTab('clients')}
                        className={`pb-2 px-4 text-sm font-medium transition-colors relative ${activeTab === 'clients' ? 'text-yellow-400' : 'text-muted-foreground hover:text-foreground'}`}
                    >
                        <div className="flex items-center gap-2">
                            <Building2 className="w-4 h-4" />
                            Clients
                        </div>
                        {activeTab === 'clients' && <motion.div layoutId="perm-tab-underline" className="absolute bottom-[-9px] left-0 right-0 h-0.5 bg-yellow-400" />}
                    </button>
                </div>

                <div className="flex items-center gap-4 bg-secondary p-1 rounded-xl border border-border">
                    <div className="relative">
                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                        <input
                            type="text"
                            placeholder="Search users..."
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="bg-transparent border-none text-sm text-foreground pl-9 pr-4 py-1.5 focus:ring-0 focus:outline-none w-40 md:w-56"
                        />
                    </div>
                </div>
            </div>

            {/* Permission List */}
            <div className="grid gap-4">
                <AnimatePresence>
                    {filteredList.map((user) => {
                        const perms = permissionsMap[user.id] || { ...DEFAULT_USER_PERMISSIONS };

                        return (
                            <motion.div
                                key={user.id}
                                initial={{ opacity: 0, y: 10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, scale: 0.95 }}
                                className="bg-secondary backdrop-blur-sm border border-border rounded-xl p-4 md:p-6 flex flex-col md:flex-row items-start md:items-center justify-between gap-6 hover:border-primary/20 transition-all group"
                            >
                                {/* User Info */}
                                <div className="flex items-center gap-4 min-w-[200px]">
                                    <div className="w-10 h-10 rounded-full bg-muted flex items-center justify-center overflow-hidden border border-border group-hover:border-primary/50 transition-colors">
                                        {('avatar' in user && (user as any).avatar) || ('logo' in user && (user as any).logo) ? (
                                            <Image
                                                src={('avatar' in user && (user as any).avatar) ? (user as any).avatar : ('logo' in user ? (user as any).logo : '')}
                                                alt={user.name}
                                                width={40}
                                                height={40}
                                                className="w-full h-full object-cover"
                                                unoptimized
                                            />
                                        ) : (
                                            <UserIcon className="w-5 h-5 text-muted-foreground" />
                                        )}
                                    </div>
                                    <div>
                                        <h3 className="text-foreground font-medium">{user.name}</h3>
                                        <p className="text-xs text-muted-foreground">{user.email}</p>
                                    </div>
                                </div>

                                {/* Controls */}
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-4 md:gap-6 w-full md:w-auto">

                                    {/* Permission: Create Project */}
                                    <div className="flex items-center justify-between gap-3 min-w-[160px]">
                                        <div className="flex flex-col">
                                            <div className="flex items-center gap-1.5">
                                                <FolderPlus className="w-3 h-3 text-blue-400/70" />
                                                <span className="text-sm text-foreground font-medium">Create Projects</span>
                                            </div>
                                            <span className="text-[10px] text-muted-foreground">Can create new projects</span>
                                        </div>
                                        <Switch
                                            checked={perms.canCreateProject}
                                            onCheckedChange={(val) => handleUpdatePermission(user.id, 'canCreateProject', val)}
                                        />
                                    </div>

                                    {/* Permission: Manage Tasks */}
                                    <div className="flex items-center justify-between gap-3 min-w-[160px]">
                                        <div className="flex flex-col">
                                            <span className="text-sm text-foreground font-medium">Task Management</span>
                                            <span className="text-[10px] text-muted-foreground">Create, edit, move tasks</span>
                                        </div>
                                        <Switch
                                            checked={perms.canManageTasks}
                                            onCheckedChange={(val) => handleUpdatePermission(user.id, 'canManageTasks', val)}
                                        />
                                    </div>

                                    {/* Permission: Mark Done */}
                                    <div className="flex items-center justify-between gap-3 min-w-[160px]">
                                        <div className="flex flex-col">
                                            <span className="text-sm text-foreground font-medium">Completion Rights</span>
                                            <span className="text-[10px] text-muted-foreground">Move tasks to &quot;Done&quot;</span>
                                        </div>
                                        <Switch
                                            checked={perms.canMarkDone ?? true}
                                            onCheckedChange={(val) => handleUpdatePermission(user.id, 'canMarkDone', val)}
                                        />
                                    </div>

                                    {/* Permission: Use AI */}
                                    <div className="flex items-center justify-between gap-3 min-w-[160px]">
                                        <div className="flex flex-col">
                                            <div className="flex items-center gap-1.5">
                                                <Sparkles className="w-3 h-3 text-purple-400/70" />
                                                <span className="text-sm text-foreground font-medium">AI Access</span>
                                            </div>
                                            <span className="text-[10px] text-muted-foreground">Use Singularity AI</span>
                                        </div>
                                        <Switch
                                            checked={perms.canUseAI}
                                            onCheckedChange={(val) => handleUpdatePermission(user.id, 'canUseAI', val)}
                                        />
                                    </div>

                                    {/* Permission: Delete Access */}
                                    <div className="flex items-center justify-between gap-3 min-w-[160px]">
                                        <div className="flex flex-col">
                                            <div className="flex items-center gap-1.5">
                                                <Trash2 className="w-3 h-3 text-red-400/70" />
                                                <span className="text-sm text-foreground font-medium">Delete Access</span>
                                            </div>
                                            <span className="text-[10px] text-muted-foreground">
                                                {perms.deleteAccess === 'none' ? 'Cannot delete' :
                                                    perms.deleteAccess === 'own' ? 'Own tasks only' : 'Can delete any'}
                                            </span>
                                        </div>
                                        <div className="relative">
                                            <select
                                                value={perms.deleteAccess}
                                                onChange={(e) => handleUpdatePermission(user.id, 'deleteAccess', e.target.value)}
                                                className="bg-secondary border border-border text-xs text-foreground rounded-lg py-1.5 pl-2 pr-6 focus:ring-1 focus:ring-primary/50 outline-none appearance-none cursor-pointer hover:bg-muted transition-colors"
                                            >
                                                <option value="none">None</option>
                                                <option value="own">Own Only</option>
                                                <option value="any">Any Task</option>
                                            </select>
                                            <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none text-muted-foreground">
                                                <svg width="10" height="6" viewBox="0 0 10 6" fill="none" xmlns="http://www.w3.org/2000/svg">
                                                    <path d="M1 1L5 5L9 1" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
                                                </svg>
                                            </div>
                                        </div>
                                    </div>

                                </div>
                            </motion.div>
                        );
                    })}
                </AnimatePresence>

                {filteredList.length === 0 && (
                    <div className="text-center py-12 text-muted-foreground">
                        No users found matching your search.
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useState } from "react";
import { suspendAgency, activateAgency, deleteAgency, updateAgencyPlan, extendTrial } from "@/lib/actions/super-admin";
import { Ban, CheckCircle, Trash2, Edit, X, AlertTriangle, Shield, Lock, Eye, EyeOff, Clock } from "lucide-react";
import { useRouter } from "next/navigation";

type ModalType = "suspend" | "delete" | "plan" | "trial" | null;

export default function AgencyActions({ agency }: { agency: any }) {
    const router = useRouter();
    const [modal, setModal] = useState<ModalType>(null);
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [reason, setReason] = useState("");
    const [deleteConfirmText, setDeleteConfirmText] = useState("");
    const [selectedPlan, setSelectedPlan] = useState(agency.plan);
    const [selectedDuration, setSelectedDuration] = useState<string>(agency.planDuration || 'lifetime');
    const [trialDays, setTrialDays] = useState(7);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const resetModal = () => {
        setModal(null);
        setPassword("");
        setShowPassword(false);
        setReason("");
        setDeleteConfirmText("");
        setError("");
        setLoading(false);
        setTrialDays(7);
    };

    const handleSuspend = async () => {
        if (!password) { setError("Password is required"); return; }
        setLoading(true);
        setError("");
        try {
            await suspendAgency(agency.id, password, reason || undefined);
            router.refresh();
            resetModal();
        } catch (err: any) {
            setError(err.message || "Failed to suspend agency");
        } finally {
            setLoading(false);
        }
    };

    const handleActivate = async () => {
        setLoading(true);
        try {
            await activateAgency(agency.id);
            router.refresh();
            resetModal();
        } catch (err: any) {
            setError(err.message || "Failed to activate agency");
        } finally {
            setLoading(false);
        }
    };

    const handleDelete = async () => {
        if (deleteConfirmText !== "DELETE") { setError("Type DELETE to confirm"); return; }
        if (!password) { setError("Password is required"); return; }
        setLoading(true);
        setError("");
        try {
            await deleteAgency(agency.id, password);
            router.push("/super-admin/agencies");
        } catch (err: any) {
            setError(err.message || "Failed to delete agency");
            setLoading(false);
        }
    };

    const handleUpdatePlan = async () => {
        if (selectedPlan === agency.plan && selectedDuration === (agency.planDuration || 'lifetime')) { resetModal(); return; }
        setLoading(true);
        setError("");
        try {
            await updateAgencyPlan(agency.id, selectedPlan, selectedDuration as any);
            router.refresh();
            resetModal();
        } catch (err: any) {
            setError(err.message || "Failed to update plan");
            setLoading(false);
        }
    };

    const handleExtendTrial = async () => {
        if (!trialDays || trialDays < 1) { setError("Enter a valid number of days"); return; }
        setLoading(true);
        setError("");
        try {
            await extendTrial(agency.id, trialDays);
            router.refresh();
            resetModal();
        } catch (err: any) {
            setError(err.message || "Failed to extend trial");
            setLoading(false);
        }
    };

    return (
        <>
            <div className="flex items-center gap-2 flex-wrap">
                <button
                    onClick={() => { setSelectedPlan(agency.plan); setSelectedDuration(agency.planDuration || 'lifetime'); setModal("plan"); }}
                    className="flex items-center gap-2 px-3 sm:px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors text-sm"
                >
                    <Edit className="w-4 h-4" />
                    <span>Change Plan</span>
                </button>

                {agency.status === 'trial' && (
                    <button
                        onClick={() => setModal("trial")}
                        className="flex items-center gap-2 px-3 sm:px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors text-sm"
                    >
                        <Clock className="w-4 h-4" />
                        <span>Extend Trial</span>
                    </button>
                )}

                {agency.status === "active" || agency.status === 'trial' ? (
                    <button
                        onClick={() => setModal("suspend")}
                        className="flex items-center gap-2 px-3 sm:px-4 py-2 bg-amber-600 text-white rounded-lg hover:bg-amber-700 transition-colors text-sm"
                    >
                        <Ban className="w-4 h-4" />
                        <span>Suspend</span>
                    </button>
                ) : (
                    <button
                        onClick={handleActivate}
                        disabled={loading}
                        className="flex items-center gap-2 px-3 sm:px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors text-sm disabled:opacity-50"
                    >
                        <CheckCircle className="w-4 h-4" />
                        <span>{loading ? "Activating..." : "Activate"}</span>
                    </button>
                )}

                <button
                    onClick={() => setModal("delete")}
                    className="flex items-center gap-2 px-3 sm:px-4 py-2 bg-red-600/10 text-red-500 border border-red-500/20 rounded-lg hover:bg-red-600/20 transition-colors text-sm"
                >
                    <Trash2 className="w-4 h-4" />
                    <span>Delete</span>
                </button>
            </div>

            {/* ----------- MODALS OVERLAY ----------- */}
            {modal && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4" onClick={resetModal}>
                    <div className="bg-card rounded-xl border border-border shadow-2xl max-w-md w-full" onClick={(e) => e.stopPropagation()}>

                        {/* -- SUSPEND MODAL -- */}
                        {modal === "suspend" && (
                            <>
                                <div className="p-6 border-b border-border">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-amber-500/10 rounded-lg">
                                            <Ban className="w-5 h-5 text-amber-500" />
                                        </div>
                                        <div>
                                            <h3 className="text-lg font-bold text-foreground">Suspend Agency</h3>
                                            <p className="text-sm text-muted-foreground">This will disable access for all users</p>
                                        </div>
                                        <button onClick={resetModal} className="ml-auto p-1 hover:bg-muted rounded-lg">
                                            <X className="w-5 h-5 text-muted-foreground" />
                                        </button>
                                    </div>
                                </div>
                                <div className="p-6 space-y-4">
                                    <div className="bg-amber-500/5 border border-amber-500/20 rounded-lg p-3">
                                        <div className="flex gap-2">
                                            <AlertTriangle className="w-4 h-4 text-amber-500 mt-0.5 flex-shrink-0" />
                                            <p className="text-sm text-amber-400">
                                                Suspending <strong>{agency.name}</strong> will lock all users out immediately.
                                            </p>
                                        </div>
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-muted-foreground mb-1.5">Reason for suspension</label>
                                        <textarea
                                            value={reason}
                                            onChange={(e) => setReason(e.target.value)}
                                            className="w-full bg-muted/50 border border-border rounded-lg px-3 py-2.5 text-sm text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-amber-500/30 resize-none"
                                            rows={2}
                                            placeholder="e.g. Non-payment, TOS violation..."
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-muted-foreground mb-1.5">
                                            <Lock className="w-3.5 h-3.5 inline mr-1" />
                                            Super Admin Password
                                        </label>
                                        <div className="relative">
                                            <input
                                                type={showPassword ? "text" : "password"}
                                                value={password}
                                                onChange={(e) => { setPassword(e.target.value); setError(""); }}
                                                className="w-full bg-muted/50 border border-border rounded-lg px-3 py-2.5 pr-10 text-sm text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-amber-500/30"
                                                placeholder="Enter your password"
                                            />
                                            <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                                                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                            </button>
                                        </div>
                                    </div>

                                    {error && (
                                        <p className="text-sm text-red-500 bg-red-500/10 border border-red-500/20 rounded-lg px-3 py-2">{error}</p>
                                    )}
                                </div>
                                <div className="p-6 pt-0 flex gap-3">
                                    <button
                                        onClick={handleSuspend}
                                        disabled={loading || !password}
                                        className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 bg-amber-600 text-white rounded-lg hover:bg-amber-700 transition-colors text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed"
                                    >
                                        {loading ? "Suspending..." : "Confirm Suspension"}
                                    </button>
                                    <button onClick={resetModal} className="px-4 py-2.5 bg-secondary text-secondary-foreground rounded-lg hover:bg-secondary/80 transition-colors text-sm">
                                        Cancel
                                    </button>
                                </div>
                            </>
                        )}

                        {/* -- DELETE MODAL -- */}
                        {modal === "delete" && (
                            <>
                                <div className="p-6 border-b border-border">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-red-500/10 rounded-lg">
                                            <Trash2 className="w-5 h-5 text-red-500" />
                                        </div>
                                        <div>
                                            <h3 className="text-lg font-bold text-foreground">Delete Agency</h3>
                                            <p className="text-sm text-red-400">This action is permanent and irreversible</p>
                                        </div>
                                        <button onClick={resetModal} className="ml-auto p-1 hover:bg-muted rounded-lg">
                                            <X className="w-5 h-5 text-muted-foreground" />
                                        </button>
                                    </div>
                                </div>
                                <div className="p-6 space-y-4">
                                    <div className="bg-red-500/5 border border-red-500/20 rounded-lg p-4">
                                        <div className="flex gap-2.5">
                                            <AlertTriangle className="w-5 h-5 text-red-500 mt-0.5 flex-shrink-0" />
                                            <div className="text-sm text-red-300 space-y-2">
                                                <p className="font-semibold">This will PERMANENTLY delete:</p>
                                                <ul className="list-disc list-inside space-y-0.5 text-red-400/80">
                                                    <li><strong>{agency.name}</strong> and all settings</li>
                                                    <li>All users, clients, and their data</li>
                                                    <li>All projects, tasks, and assets</li>
                                                    <li>All invoices, transactions, and financial records</li>
                                                    <li>All AI chat history and notifications</li>
                                                </ul>
                                            </div>
                                        </div>
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-muted-foreground mb-1.5">
                                            Type <span className="font-mono text-red-500">DELETE</span> to confirm
                                        </label>
                                        <input
                                            type="text"
                                            value={deleteConfirmText}
                                            onChange={(e) => { setDeleteConfirmText(e.target.value.toUpperCase()); setError(""); }}
                                            className="w-full bg-muted/50 border border-border rounded-lg px-3 py-2.5 text-sm text-foreground font-mono tracking-wider placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-red-500/30"
                                            placeholder="DELETE"
                                        />
                                    </div>

                                    <div>
                                        <label className="block text-sm font-medium text-muted-foreground mb-1.5">
                                            <Lock className="w-3.5 h-3.5 inline mr-1" />
                                            Super Admin Password
                                        </label>
                                        <div className="relative">
                                            <input
                                                type={showPassword ? "text" : "password"}
                                                value={password}
                                                onChange={(e) => { setPassword(e.target.value); setError(""); }}
                                                className="w-full bg-muted/50 border border-border rounded-lg px-3 py-2.5 pr-10 text-sm text-foreground placeholder-muted-foreground focus:outline-none focus:ring-2 focus:ring-red-500/30"
                                                placeholder="Enter your password"
                                            />
                                            <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                                                {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                                            </button>
                                        </div>
                                    </div>

                                    {error && (
                                        <p className="text-sm text-red-500 bg-red-500/10 border border-red-500/20 rounded-lg px-3 py-2">{error}</p>
                                    )}
                                </div>
                                <div className="p-6 pt-0 flex gap-3">
                                    <button
                                        onClick={handleDelete}
                                        disabled={loading || deleteConfirmText !== "DELETE" || !password}
                                        className="flex-1 flex items-center justify-center gap-2 px-4 py-2.5 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                        {loading ? "Deleting Everything..." : "Permanently Delete Agency"}
                                    </button>
                                    <button onClick={resetModal} className="px-4 py-2.5 bg-secondary text-secondary-foreground rounded-lg hover:bg-secondary/80 transition-colors text-sm">
                                        Cancel
                                    </button>
                                </div>
                            </>
                        )}

                        {/* -- PLAN MODAL -- */}
                        {modal === "plan" && (
                            <>
                                <div className="p-6 border-b border-border">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-blue-500/10 rounded-lg">
                                            <Shield className="w-5 h-5 text-blue-500" />
                                        </div>
                                        <div>
                                            <h3 className="text-lg font-bold text-foreground">Change Plan</h3>
                                            <p className="text-sm text-muted-foreground">Update plan for {agency.name}</p>
                                        </div>
                                        <button onClick={resetModal} className="ml-auto p-1 hover:bg-muted rounded-lg">
                                            <X className="w-5 h-5 text-muted-foreground" />
                                        </button>
                                    </div>
                                </div>
                                <div className="p-6 space-y-3">
                                    {[
                                        { value: "free", label: "Free", desc: "3 users, 5 projects", color: "border-muted-foreground/20" },
                                        { value: "starter", label: "Starter", desc: "10 users, 50 projects", color: "border-emerald-500/30" },
                                        { value: "pro", label: "Pro", desc: "50 users, 500 projects", color: "border-blue-500/30" },
                                        { value: "enterprise", label: "Enterprise", desc: "Unlimited everything", color: "border-purple-500/30" },
                                    ].map((plan) => (
                                        <label
                                            key={plan.value}
                                            className={`flex items-center gap-3 p-3.5 border rounded-lg cursor-pointer transition-all ${selectedPlan === plan.value
                                                    ? `${plan.color} bg-muted/50 ring-1 ring-current`
                                                    : "border-border hover:bg-muted/30"
                                                }`}
                                        >
                                            <input
                                                type="radio"
                                                name="plan"
                                                value={plan.value}
                                                checked={selectedPlan === plan.value}
                                                onChange={(e) => setSelectedPlan(e.target.value)}
                                                className="w-4 h-4 accent-blue-500"
                                            />
                                            <div>
                                                <p className="font-medium text-foreground">{plan.label}</p>
                                                <p className="text-sm text-muted-foreground">{plan.desc}</p>
                                            </div>
                                            {agency.plan === plan.value && (
                                                <span className="ml-auto text-xs bg-muted text-muted-foreground px-2 py-0.5 rounded-full">Current</span>
                                            )}
                                        </label>
                                    ))}

                                    {error && (
                                        <p className="text-sm text-red-500 bg-red-500/10 border border-red-500/20 rounded-lg px-3 py-2">{error}</p>
                                    )}

                                    {/* Duration Selector */}
                                    <div className="mt-1">
                                        <label className="block text-sm font-medium text-muted-foreground mb-2">Subscription Duration</label>
                                        <div className="grid grid-cols-2 gap-2">
                                            {[
                                                { value: 'monthly', label: '1 Month' },
                                                { value: '3months', label: '3 Months' },
                                                { value: '6months', label: '6 Months' },
                                                { value: 'yearly', label: '1 Year' },
                                                { value: 'lifetime', label: 'Lifetime' },
                                            ].map((d) => (
                                                <button
                                                    key={d.value}
                                                    type="button"
                                                    onClick={() => setSelectedDuration(d.value)}
                                                    className={`px-3 py-2 text-sm rounded-lg border transition-all font-medium ${
                                                        selectedDuration === d.value
                                                            ? 'border-blue-500 bg-blue-500/10 text-blue-500 ring-1 ring-blue-500/30'
                                                            : 'border-border text-muted-foreground hover:bg-muted/30'
                                                    } ${d.value === 'lifetime' ? 'col-span-2' : ''}`}
                                                >
                                                    {d.label}
                                                </button>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                                <div className="p-6 pt-0 flex gap-3">
                                    <button
                                        onClick={handleUpdatePlan}
                                        disabled={loading || (selectedPlan === agency.plan && selectedDuration === (agency.planDuration || 'lifetime'))}
                                        className="flex-1 px-4 py-2.5 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed"
                                    >
                                        {loading ? "Updating..." : "Update Plan"}
                                    </button>
                                    <button onClick={resetModal} className="px-4 py-2.5 bg-secondary text-secondary-foreground rounded-lg hover:bg-secondary/80 transition-colors text-sm">
                                        Cancel
                                    </button>
                                </div>
                            </>
                        )}

                        {/* -- TRIAL EXTENSION MODAL -- */}
                        {modal === "trial" && (
                            <>
                                <div className="p-6 border-b border-border">
                                    <div className="flex items-center gap-3">
                                        <div className="p-2 bg-indigo-500/10 rounded-lg">
                                            <Clock className="w-5 h-5 text-indigo-500" />
                                        </div>
                                        <div>
                                            <h3 className="text-lg font-bold text-foreground">Extend Trial</h3>
                                            <p className="text-sm text-muted-foreground">Extend trial for {agency.name}</p>
                                        </div>
                                        <button onClick={resetModal} className="ml-auto p-1 hover:bg-muted rounded-lg">
                                            <X className="w-5 h-5 text-muted-foreground" />
                                        </button>
                                    </div>
                                </div>
                                <div className="p-6 space-y-4">
                                    {agency.trialEndsAt && (
                                        <div className="bg-muted/50 rounded-lg p-3 text-sm">
                                            <p className="text-muted-foreground">
                                                Current trial ends: <span className="text-foreground font-medium">{new Date(agency.trialEndsAt).toLocaleDateString()}</span>
                                                {new Date(agency.trialEndsAt) < new Date() && (
                                                    <span className="text-red-500 ml-2">(expired)</span>
                                                )}
                                            </p>
                                        </div>
                                    )}

                                    <div>
                                        <label className="block text-sm font-medium text-muted-foreground mb-1.5">Extend by (days)</label>
                                        <div className="flex gap-2">
                                            {[7, 14, 30].map((d) => (
                                                <button
                                                    key={d}
                                                    type="button"
                                                    onClick={() => setTrialDays(d)}
                                                    className={`px-4 py-2 rounded-lg border text-sm font-medium transition-all ${
                                                        trialDays === d
                                                            ? 'border-indigo-500 bg-indigo-500/10 text-indigo-500'
                                                            : 'border-border text-muted-foreground hover:bg-muted/30'
                                                    }`}
                                                >
                                                    {d} days
                                                </button>
                                            ))}
                                            <input
                                                type="number"
                                                min={1}
                                                max={365}
                                                value={trialDays}
                                                onChange={(e) => setTrialDays(parseInt(e.target.value) || 0)}
                                                className="w-20 bg-muted/50 border border-border rounded-lg px-3 py-2 text-sm text-foreground text-center focus:outline-none focus:ring-2 focus:ring-indigo-500/30"
                                            />
                                        </div>
                                    </div>

                                    {error && (
                                        <p className="text-sm text-red-500 bg-red-500/10 border border-red-500/20 rounded-lg px-3 py-2">{error}</p>
                                    )}
                                </div>
                                <div className="p-6 pt-0 flex gap-3">
                                    <button
                                        onClick={handleExtendTrial}
                                        disabled={loading || !trialDays || trialDays < 1}
                                        className="flex-1 px-4 py-2.5 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors text-sm font-medium disabled:opacity-50 disabled:cursor-not-allowed"
                                    >
                                        {loading ? "Extending..." : `Extend by ${trialDays} Days`}
                                    </button>
                                    <button onClick={resetModal} className="px-4 py-2.5 bg-secondary text-secondary-foreground rounded-lg hover:bg-secondary/80 transition-colors text-sm">
                                        Cancel
                                    </button>
                                </div>
                            </>
                        )}
                    </div>
                </div>
            )}
        </>
    );
}

"use client";

import Link from "next/link";
import { Eye, Ban, CheckCircle, Trash2, Loader2 } from "lucide-react";
import { suspendAgency, activateAgency, deleteAgency } from "@/lib/actions/super-admin";
import { useState, useRef } from "react";
import { useRouter } from "next/navigation";
import { useProgressiveList } from "@/hooks/use-infinite-scroll";
import { useDateFormat } from "@/context/TimezoneContext";
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
    DialogDescription,
    DialogFooter,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";

export default function AgencyTable({ agencies }: { agencies: any[] }) {
    const fmt = useDateFormat();
    const router = useRouter();
    const [filter, setFilter] = useState<string>("all");
    const [search, setSearch] = useState("");
    const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
    const [deleteTargetId, setDeleteTargetId] = useState<string | null>(null);
    const [deletePassword, setDeletePassword] = useState("");
    const [deleteError, setDeleteError] = useState("");
    const [deleting, setDeleting] = useState(false);
    const [suspendDialogOpen, setSuspendDialogOpen] = useState(false);
    const [suspendTargetId, setSuspendTargetId] = useState<string | null>(null);
    const [suspendPassword, setSuspendPassword] = useState("");
    const [suspendReason, setSuspendReason] = useState("");
    const [suspendError, setSuspendError] = useState("");
    const [suspending, setSuspending] = useState(false);
    const [activatingId, setActivatingId] = useState<string | null>(null);
    const passwordRef = useRef<HTMLInputElement>(null);
    const suspendPasswordRef = useRef<HTMLInputElement>(null);

    const filteredAgencies = agencies.filter((agency) => {
        const matchesFilter = filter === "all" || agency.status === filter || agency.plan === filter;
        const q = search.toLowerCase();
        const matchesSearch = !q || agency.name.toLowerCase().includes(q)
            || (agency.slug || '').toLowerCase().includes(q)
            || (agency.billing?.billingEmail || '').toLowerCase().includes(q);
        return matchesFilter && matchesSearch;
    });

    const { visibleCount, sentinelRef, hasMore } = useProgressiveList(filteredAgencies.length, 20, [filter, search]);

    const handleSuspend = (agencyId: string) => {
        setSuspendTargetId(agencyId);
        setSuspendPassword("");
        setSuspendReason("");
        setSuspendError("");
        setSuspendDialogOpen(true);
        setTimeout(() => suspendPasswordRef.current?.focus(), 100);
    };

    const handleSuspendConfirm = async () => {
        if (!suspendTargetId || !suspendPassword) return;
        setSuspending(true);
        setSuspendError("");
        try {
            await suspendAgency(suspendTargetId, suspendPassword, suspendReason || "Suspended by super admin");
            setSuspendDialogOpen(false);
            router.refresh();
        } catch (err: any) {
            setSuspendError(err.message || 'Failed to suspend agency');
        } finally {
            setSuspending(false);
        }
    };

    const handleActivate = async (agencyId: string) => {
        if (activatingId) return;
        setActivatingId(agencyId);
        try {
            await activateAgency(agencyId);
            router.refresh();
        } catch {
            // handled by server
        } finally {
            setActivatingId(null);
        }
    };

    const handleDelete = (agencyId: string) => {
        setDeleteTargetId(agencyId);
        setDeletePassword("");
        setDeleteError("");
        setDeleteDialogOpen(true);
        setTimeout(() => passwordRef.current?.focus(), 100);
    };

    const handleDeleteConfirm = async () => {
        if (!deleteTargetId || !deletePassword) return;
        setDeleting(true);
        setDeleteError("");
        try {
            await deleteAgency(deleteTargetId, deletePassword);
            setDeleteDialogOpen(false);
            router.refresh();
        } catch (err: any) {
            setDeleteError(err.message || 'Failed to delete agency');
        } finally {
            setDeleting(false);
        }
    };

    const statusBadge = (status: string) => {
        const map: Record<string, string> = {
            active: 'bg-green-500/10 text-green-500',
            trial: 'bg-blue-500/10 text-blue-500',
            suspended: 'bg-red-500/10 text-red-500',
            cancelled: 'bg-muted text-muted-foreground',
        };
        return map[status] || 'bg-muted text-muted-foreground';
    };

    const filters = [
        { value: 'all', label: 'All' },
        { value: 'active', label: 'Active' },
        { value: 'trial', label: 'Trial' },
        { value: 'suspended', label: 'Suspended' },
        { value: 'cancelled', label: 'Cancelled' },
        { value: 'free', label: 'Free' },
        { value: 'starter', label: 'Starter' },
        { value: 'pro', label: 'Pro' },
        { value: 'enterprise', label: 'Enterprise' },
    ];

    return (
        <div className="bg-card rounded-lg shadow border border-border">
            <div className="p-4 sm:p-6 border-b border-border space-y-3">
                <input
                    type="text"
                    placeholder="Search by name, slug, or email..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="w-full px-4 py-2 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent placeholder:text-muted-foreground"
                />
                <div className="flex flex-wrap gap-1.5">
                    {filters.map((f) => (
                        <button
                            key={f.value}
                            onClick={() => setFilter(f.value)}
                            className={`px-3 py-1 text-xs font-medium rounded-full transition-colors ${filter === f.value
                                ? 'bg-primary text-primary-foreground'
                                : 'bg-muted text-muted-foreground hover:bg-muted/80'
                            }`}
                        >
                            {f.label}
                            {f.value !== 'all' && (
                                <span className="ml-1 opacity-60">
                                    {agencies.filter(a => a.status === f.value || a.plan === f.value).length}
                                </span>
                            )}
                        </button>
                    ))}
                </div>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full">
                    <thead className="bg-muted border-b border-border">
                        <tr>
                            <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">Agency</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">Plan</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">Status</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">Users</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">Projects</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">Clients</th>
                            <th className="px-6 py-3 text-left text-xs font-medium text-muted-foreground uppercase tracking-wider">Created</th>
                            <th className="px-6 py-3 text-right text-xs font-medium text-muted-foreground uppercase tracking-wider">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="bg-card divide-y divide-border">
                        {filteredAgencies.slice(0, visibleCount).map((agency) => (
                            <tr
                                key={agency.id}
                                className="hover:bg-muted/50 cursor-pointer"
                                onClick={() => router.push(`/super-admin/agencies/${agency.id}`)}
                                onKeyDown={(e) => {
                                    if (e.key === "Enter" || e.key === " ") {
                                        e.preventDefault();
                                        router.push(`/super-admin/agencies/${agency.id}`);
                                    }
                                }}
                                tabIndex={0}
                            >
                                <td className="px-6 py-4 whitespace-nowrap">
                                    <div>
                                        <div className="font-medium text-foreground">{agency.name}</div>
                                        <div className="text-sm text-muted-foreground">{agency.slug}</div>
                                    </div>
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap">
                                    <span className={`px-2 py-1 text-xs font-medium rounded-full ${agency.plan === 'enterprise' ? 'bg-purple-500/10 text-purple-500' :
                                        agency.plan === 'pro' ? 'bg-blue-500/10 text-blue-500' :
                                            agency.plan === 'starter' ? 'bg-emerald-500/10 text-emerald-500' :
                                                'bg-muted text-muted-foreground'
                                        }`}>
                                        {agency.plan.toUpperCase()}
                                    </span>
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap">
                                    <span className={`px-2 py-1 text-xs font-medium rounded-full ${statusBadge(agency.status)}`}>
                                        {agency.status}
                                    </span>
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-foreground">
                                    {agency.stats?.users || 0}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-foreground">
                                    {agency.stats?.projects || 0}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-foreground">
                                    {agency.stats?.clients || 0}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-sm text-muted-foreground">
                                    {fmt.date(agency.createdAt)}
                                </td>
                                <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium" onClick={(e) => e.stopPropagation()}>
                                    <div className="flex items-center justify-end gap-2">
                                        <Link
                                            href={`/super-admin/agencies/${agency.id}`}
                                            className="text-blue-500 hover:text-blue-400"
                                            title="View Details"
                                        >
                                            <Eye className="w-4 h-4" />
                                        </Link>
                                        {agency.status === 'active' || agency.status === 'trial' ? (
                                            <button
                                                onClick={() => handleSuspend(agency.id)}
                                                className="text-amber-500 hover:text-amber-400"
                                                title="Suspend"
                                            >
                                                <Ban className="w-4 h-4" />
                                            </button>
                                        ) : (
                                            <button
                                                onClick={() => handleActivate(agency.id)}
                                                disabled={activatingId === agency.id}
                                                className="text-green-500 hover:text-green-400 disabled:opacity-50"
                                                title="Activate"
                                            >
                                                {activatingId === agency.id ? (
                                                    <Loader2 className="w-4 h-4 animate-spin" />
                                                ) : (
                                                    <CheckCircle className="w-4 h-4" />
                                                )}
                                            </button>
                                        )}
                                        <button
                                            onClick={() => handleDelete(agency.id)}
                                            className="text-red-500 hover:text-red-400"
                                            title="Delete"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>

            {hasMore && (
                <div ref={sentinelRef} className="flex justify-center py-4">
                    <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                </div>
            )}

            {filteredAgencies.length === 0 && (
                <div className="text-center py-12">
                    <p className="text-muted-foreground">No agencies found</p>
                </div>
            )}

            {/* Suspend Dialog */}
            <Dialog open={suspendDialogOpen} onOpenChange={setSuspendDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Suspend Agency</DialogTitle>
                        <DialogDescription>
                            This will disable access for all users in this agency.
                        </DialogDescription>
                    </DialogHeader>
                    <form onSubmit={(e) => { e.preventDefault(); handleSuspendConfirm(); }} className="space-y-3">
                        <div>
                            <label className="text-sm text-muted-foreground mb-1 block">Reason (optional)</label>
                            <Input
                                placeholder="e.g. Non-payment, TOS violation..."
                                value={suspendReason}
                                onChange={(e) => setSuspendReason(e.target.value)}
                            />
                        </div>
                        <div>
                            <label className="text-sm text-muted-foreground mb-1 block">Super-admin password *</label>
                            <Input
                                ref={suspendPasswordRef}
                                type="password"
                                placeholder="Enter your password"
                                value={suspendPassword}
                                onChange={(e) => setSuspendPassword(e.target.value)}
                                autoComplete="current-password"
                            />
                        </div>
                        {suspendError && (
                            <p className="text-sm text-red-500">{suspendError}</p>
                        )}
                        <DialogFooter className="mt-4">
                            <button
                                type="button"
                                onClick={() => setSuspendDialogOpen(false)}
                                className="px-4 py-2 text-sm border border-border rounded-md hover:bg-muted"
                            >
                                Cancel
                            </button>
                            <button
                                type="submit"
                                disabled={!suspendPassword || suspending}
                                className="px-4 py-2 text-sm bg-amber-600 text-white rounded-md hover:bg-amber-700 disabled:opacity-50"
                            >
                                {suspending ? 'Suspending...' : 'Suspend Agency'}
                            </button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>

            {/* Delete Dialog */}
            <Dialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Delete Agency</DialogTitle>
                        <DialogDescription>
                            This action is permanent. All agency data will be deleted.
                        </DialogDescription>
                    </DialogHeader>
                    <form onSubmit={(e) => { e.preventDefault(); handleDeleteConfirm(); }} className="space-y-3">
                        <div>
                            <label className="text-sm text-muted-foreground mb-1 block">Super-admin password *</label>
                            <Input
                                ref={passwordRef}
                                type="password"
                                placeholder="Enter your password"
                                value={deletePassword}
                                onChange={(e) => setDeletePassword(e.target.value)}
                                autoComplete="current-password"
                            />
                        </div>
                        {deleteError && (
                            <p className="text-sm text-red-500">{deleteError}</p>
                        )}
                        <DialogFooter className="mt-4">
                            <button
                                type="button"
                                onClick={() => setDeleteDialogOpen(false)}
                                className="px-4 py-2 text-sm border border-border rounded-md hover:bg-muted"
                            >
                                Cancel
                            </button>
                            <button
                                type="submit"
                                disabled={!deletePassword || deleting}
                                className="px-4 py-2 text-sm bg-red-600 text-white rounded-md hover:bg-red-700 disabled:opacity-50"
                            >
                                {deleting ? 'Deleting...' : 'Delete Agency'}
                            </button>
                        </DialogFooter>
                    </form>
                </DialogContent>
            </Dialog>
        </div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { createAgency, getPublicSecuritySettings } from "@/lib/actions/super-admin";
import { useRouter } from "next/navigation";
import { Eye, EyeOff, Upload, X, CheckCircle, XCircle } from "lucide-react";

export default function CreateAgencyForm() {
    const router = useRouter();
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [enforceStrong, setEnforceStrong] = useState(true);
    const [showPassword, setShowPassword] = useState(false);
    const [logoPreview, setLogoPreview] = useState<string>("");
    const fileRef = useRef<HTMLInputElement>(null);

    const [formData, setFormData] = useState({
        name: "",
        ownerName: "",
        ownerEmail: "",
        ownerPassword: "",
        confirmPassword: "",
        ownerPhone: "",
        plan: "free" as "free" | "starter" | "pro" | "enterprise",
        logo: "" as string,
        createdAt: new Date().toISOString().split('T')[0], // Default today, can backdate
    });

    useEffect(() => {
        getPublicSecuritySettings().then((s) => setEnforceStrong(s.enforceStrongPasswords));
    }, []);

    // Password strength checks
    const pw = formData.ownerPassword;
    const pwChecks = enforceStrong ? {
        length: pw.length >= 10,
        upper: /[A-Z]/.test(pw),
        lower: /[a-z]/.test(pw),
        number: /\d/.test(pw),
        special: /[^A-Za-z0-9]/.test(pw),
    } : {
        length: pw.length >= 6,
        hasLetterAndNumber: /[a-zA-Z]/.test(pw) && /\d/.test(pw),
    };
    const pwValid = Object.values(pwChecks).every(Boolean);
    const passwordsMatch = pw && formData.confirmPassword && pw === formData.confirmPassword;

    const handleLogoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;
        if (file.size > 2 * 1024 * 1024) {
            setError("Logo file is too large. Max 2MB.");
            return;
        }
        // Only allow safe raster image types — block SVG (can contain scripts)
        const allowedTypes = ["image/png", "image/jpeg", "image/jpg", "image/gif", "image/webp"];
        if (!allowedTypes.includes(file.type)) {
            setError("Unsupported format. Please use PNG, JPG, GIF, or WebP.");
            return;
        }
        const reader = new FileReader();
        reader.onload = () => {
            const result = reader.result as string;
            setFormData((prev) => ({ ...prev, logo: result }));
            setLogoPreview(result);
        };
        reader.readAsDataURL(file);
    };

    const removeLogo = () => {
        setFormData((prev) => ({ ...prev, logo: "" }));
        setLogoPreview("");
        if (fileRef.current) fileRef.current.value = "";
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setError("");

        if (!formData.name.trim()) { setError("Agency name is required"); return; }
        if (!formData.ownerName.trim()) { setError("Owner name is required"); return; }
        if (!formData.ownerEmail.trim()) { setError("Owner email is required"); return; }
        if (!pwValid) { setError("Password does not meet requirements"); return; }
        if (pw !== formData.confirmPassword) { setError("Passwords do not match"); return; }

        setLoading(true);
        try {
            await createAgency({
                name: formData.name,
                ownerName: formData.ownerName,
                ownerEmail: formData.ownerEmail,
                ownerPassword: formData.ownerPassword,
                ownerPhone: formData.ownerPhone || undefined,
                plan: formData.plan,
                logo: formData.logo || undefined,
                createdAt: formData.createdAt || undefined,
            });
            router.push("/super-admin/agencies");
        } catch (err: any) {
            setError(err.message || "Failed to create agency");
        } finally {
            setLoading(false);
        }
    };

    const Check = ({ ok }: { ok: boolean }) =>
        ok ? <CheckCircle className="w-3.5 h-3.5 text-green-500" /> : <XCircle className="w-3.5 h-3.5 text-muted-foreground/40" />;

    return (
        <form onSubmit={handleSubmit} className="bg-card rounded-lg shadow border border-border p-6 space-y-6">
            {error && (
                <div className="bg-red-500/10 border border-red-500/20 text-red-500 px-4 py-3 rounded-lg text-sm">
                    {error}
                </div>
            )}

            {/* -- Agency Info -- */}
            <div className="space-y-1">
                <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Agency Info</h3>
                <div className="h-px bg-border" />
            </div>

            <div>
                <label className="block text-sm font-medium text-foreground mb-2">Agency Name *</label>
                <input
                    type="text"
                    required
                    maxLength={200}
                    value={formData.name}
                    onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                    className="w-full px-4 py-2 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent placeholder:text-muted-foreground"
                    placeholder="Your Agency Name"
                />
            </div>

            {/* Logo Upload */}
            <div>
                <label className="block text-sm font-medium text-foreground mb-2">Agency Logo</label>
                {logoPreview ? (
                    <div className="flex items-center gap-4">
                        <img src={logoPreview} alt="Logo preview" className="w-16 h-16 rounded-lg object-contain border border-border bg-muted/30" />
                        <button
                            type="button"
                            onClick={removeLogo}
                            className="flex items-center gap-1.5 text-sm text-red-500 hover:text-red-400"
                        >
                            <X className="w-4 h-4" /> Remove
                        </button>
                    </div>
                ) : (
                    <div
                        onClick={() => fileRef.current?.click()}
                        className="flex flex-col items-center justify-center border-2 border-dashed border-border rounded-lg p-6 cursor-pointer hover:border-primary/50 hover:bg-muted/20 transition-colors"
                    >
                        <Upload className="w-8 h-8 text-muted-foreground mb-2" />
                        <p className="text-sm text-muted-foreground">Click to upload logo</p>
                        <p className="text-xs text-muted-foreground/60 mt-1">PNG, JPG, GIF, or WebP — max 2MB</p>
                    </div>
                )}
                <input ref={fileRef} type="file" accept="image/png,image/jpeg,image/gif,image/webp" onChange={handleLogoChange} className="hidden" />
            </div>

            <div>
                <label className="block text-sm font-medium text-foreground mb-2">Plan *</label>
                <select
                    value={formData.plan}
                    onChange={(e) => setFormData({ ...formData, plan: e.target.value as any })}
                    className="w-full px-4 py-2 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent"
                >
                    <option value="free">Free (3 users, 5 projects)</option>
                    <option value="starter">Starter (10 users, 50 projects)</option>
                    <option value="pro">Pro (50 users, 500 projects)</option>
                    <option value="enterprise">Enterprise (Unlimited)</option>
                </select>
            </div>

            <div>
                <label className="block text-sm font-medium text-foreground mb-2">Created Date</label>
                <input
                    type="date"
                    value={formData.createdAt}
                    onChange={(e) => setFormData({ ...formData, createdAt: e.target.value })}
                    max={new Date().toISOString().split('T')[0]}
                    className="w-full px-4 py-2 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent"
                />
                <p className="text-xs text-muted-foreground mt-1">Leave as today or set a past date for backdating</p>
            </div>

            {/* -- Owner Account -- */}
            <div className="space-y-1 pt-2">
                <h3 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider">Owner Account</h3>
                <div className="h-px bg-border" />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-foreground mb-2">Owner Name *</label>
                    <input
                        type="text"
                        required
                        maxLength={200}
                        value={formData.ownerName}
                        onChange={(e) => setFormData({ ...formData, ownerName: e.target.value })}
                        className="w-full px-4 py-2 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent placeholder:text-muted-foreground"
                        placeholder="Admin / Owner Name"
                    />
                </div>
                <div>
                    <label className="block text-sm font-medium text-foreground mb-2">Phone Number</label>
                    <input
                        type="tel"
                        value={formData.ownerPhone}
                        onChange={(e) => setFormData({ ...formData, ownerPhone: e.target.value })}
                        className="w-full px-4 py-2 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent placeholder:text-muted-foreground"
                        placeholder="+91 98765 43210"
                    />
                </div>
            </div>

            <div>
                <label className="block text-sm font-medium text-foreground mb-2">Owner Email *</label>
                <input
                    type="email"
                    required
                    value={formData.ownerEmail}
                    onChange={(e) => setFormData({ ...formData, ownerEmail: e.target.value })}
                    className="w-full px-4 py-2 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent placeholder:text-muted-foreground"
                    placeholder="owner@company.com"
                />
                <p className="text-xs text-muted-foreground mt-1">This will be the admin login email for the agency</p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-medium text-foreground mb-2">Password *</label>
                    <div className="relative">
                        <input
                            type={showPassword ? "text" : "password"}
                            required
                            value={formData.ownerPassword}
                            onChange={(e) => setFormData({ ...formData, ownerPassword: e.target.value })}
                            className="w-full px-4 py-2 pr-10 border border-border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent placeholder:text-muted-foreground"
                            placeholder="••••••••"
                        />
                        <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground">
                            {showPassword ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                        </button>
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-medium text-foreground mb-2">Confirm Password *</label>
                    <input
                        type={showPassword ? "text" : "password"}
                        required
                        value={formData.confirmPassword}
                        onChange={(e) => setFormData({ ...formData, confirmPassword: e.target.value })}
                        className={`w-full px-4 py-2 border rounded-lg bg-background text-foreground focus:ring-2 focus:ring-primary focus:border-transparent placeholder:text-muted-foreground ${
                            formData.confirmPassword
                                ? passwordsMatch ? "border-green-500/50" : "border-red-500/50"
                                : "border-border"
                        }`}
                        placeholder="Re-enter password"
                    />
                </div>
            </div>

            {/* Password requirements */}
            {pw && (
                <div className="bg-muted/30 rounded-lg p-3 space-y-1.5">
                    <p className="text-xs font-medium text-muted-foreground mb-1">Password requirements:</p>
                    {enforceStrong ? (
                        <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                            <div className="flex items-center gap-1.5 text-xs"><Check ok={(pwChecks as any).length} /> <span>10+ characters</span></div>
                            <div className="flex items-center gap-1.5 text-xs"><Check ok={(pwChecks as any).upper} /> <span>Uppercase letter</span></div>
                            <div className="flex items-center gap-1.5 text-xs"><Check ok={(pwChecks as any).lower} /> <span>Lowercase letter</span></div>
                            <div className="flex items-center gap-1.5 text-xs"><Check ok={(pwChecks as any).number} /> <span>Number</span></div>
                            <div className="flex items-center gap-1.5 text-xs"><Check ok={(pwChecks as any).special} /> <span>Special character</span></div>
                        </div>
                    ) : (
                        <div className="space-y-1">
                            <div className="flex items-center gap-1.5 text-xs"><Check ok={(pwChecks as any).length} /> <span>6+ characters</span></div>
                            <div className="flex items-center gap-1.5 text-xs"><Check ok={(pwChecks as any).hasLetterAndNumber} /> <span>Letter + number</span></div>
                        </div>
                    )}
                    {formData.confirmPassword && (
                        <div className="flex items-center gap-1.5 text-xs pt-1 border-t border-border/50 mt-1">
                            <Check ok={!!passwordsMatch} /> <span>Passwords match</span>
                        </div>
                    )}
                </div>
            )}

            <div className="flex items-center gap-4 pt-4 border-t border-border">
                <button
                    type="submit"
                    disabled={loading}
                    className="px-6 py-2.5 bg-primary text-primary-foreground rounded-lg hover:bg-primary/90 transition-colors disabled:opacity-50 disabled:cursor-not-allowed font-medium"
                >
                    {loading ? "Creating Agency..." : "Create Agency"}
                </button>
                <button
                    type="button"
                    onClick={() => router.back()}
                    className="px-6 py-2.5 bg-secondary text-secondary-foreground rounded-lg hover:bg-secondary/80 transition-colors"
                >
                    Cancel
                </button>
            </div>
        </form>
    );
}

"use client";

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { Building2, ChevronDown, Menu } from "lucide-react";
import { getAllAgencies, switchAgency, clearAgencySelection } from "@/lib/agency-context";
import Cookies from "js-cookie";

interface SuperAdminTopbarProps {
    onMenuClick?: () => void;
}

export default function SuperAdminTopbar({ onMenuClick }: SuperAdminTopbarProps) {
    const router = useRouter();
    const [agencies, setAgencies] = useState<any[]>([]);
    const [selectedAgency, setSelectedAgency] = useState<string | null>(null);
    const [isOpen, setIsOpen] = useState(false);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        loadAgencies();
        const selected = Cookies.get('selectedAgencyId');
        if (selected) {
            setSelectedAgency(selected);
        }
    }, []);

    const loadAgencies = async () => {
        try {
            const data = await getAllAgencies();
            setAgencies(data);
        } catch (error) {
            console.error('Error loading agencies:', error);
        } finally {
            setLoading(false);
        }
    };

    const handleSwitch = async (agencyId: string | null) => {
        try {
            if (agencyId) {
                await switchAgency(agencyId);
                setSelectedAgency(agencyId);
            } else {
                await clearAgencySelection();
                setSelectedAgency(null);
            }
            setIsOpen(false);
            router.refresh();
        } catch (error) {
            console.error('Error switching agency:', error);
        }
    };

    const currentAgency = agencies.find(a => a.id === selectedAgency);

    return (
        <div className="bg-card border-b border-border px-3 sm:px-6 py-3 sm:py-4">
            <div className="flex items-center justify-between gap-3">
                <div className="flex items-center gap-3 sm:gap-4 min-w-0">
                    {/* Hamburger menu for mobile */}
                    <button
                        onClick={onMenuClick}
                        className="lg:hidden p-2 rounded-lg text-muted-foreground hover:bg-muted hover:text-foreground transition-colors shrink-0"
                    >
                        <Menu className="w-5 h-5" />
                    </button>

                    <h2 className="text-base sm:text-lg font-semibold text-foreground hidden sm:block">Agency View</h2>

                    {/* Agency Switcher */}
                    <div className="relative">
                        <button
                            onClick={() => setIsOpen(!isOpen)}
                            className="flex items-center gap-2 px-3 sm:px-4 py-2 bg-muted hover:bg-muted/80 rounded-lg transition-colors"
                        >
                            <Building2 className="w-4 h-4 text-muted-foreground shrink-0" />
                            <span className="text-sm font-medium text-foreground truncate max-w-[120px] sm:max-w-none">
                                {currentAgency ? currentAgency.name : "All Agencies"}
                            </span>
                            <ChevronDown className="w-4 h-4 text-muted-foreground shrink-0" />
                        </button>

                        {isOpen && (
                            <>
                                <div
                                    className="fixed inset-0 z-10"
                                    onClick={() => setIsOpen(false)}
                                />
                                <div className="absolute top-full left-0 mt-2 w-64 bg-card rounded-lg shadow-lg border border-border z-20 max-h-96 overflow-y-auto">
                                    <div className="p-2">
                                        <button
                                            onClick={() => handleSwitch(null)}
                                            className={`w-full text-left px-3 py-2 rounded-lg transition-colors ${!selectedAgency
                                                ? "bg-primary/10 text-primary"
                                                : "hover:bg-muted text-foreground"
                                                }`}
                                        >
                                            <div className="flex items-center gap-2">
                                                <Building2 className="w-4 h-4" />
                                                <span className="font-medium">All Agencies</span>
                                            </div>
                                        </button>

                                        <div className="border-t border-border my-2" />

                                        {loading ? (
                                            <div className="px-3 py-2 text-sm text-muted-foreground">Loading...</div>
                                        ) : (
                                            agencies.map((agency) => (
                                                <button
                                                    key={agency.id}
                                                    onClick={() => handleSwitch(agency.id)}
                                                    className={`w-full text-left px-3 py-2 rounded-lg transition-colors ${selectedAgency === agency.id
                                                        ? "bg-primary/10 text-primary"
                                                        : "hover:bg-muted text-foreground"
                                                        }`}
                                                >
                                                    <div className="flex items-center justify-between">
                                                        <span className="font-medium">{agency.name}</span>
                                                        <span className={`text-xs px-2 py-1 rounded ${agency.plan === 'enterprise' ? 'bg-purple-500/10 text-purple-500' :
                                                            agency.plan === 'pro' ? 'bg-blue-500/10 text-blue-500' :
                                                                'bg-muted text-muted-foreground'
                                                            }`}>
                                                            {agency.plan}
                                                        </span>
                                                    </div>
                                                </button>
                                            ))
                                        )}
                                    </div>
                                </div>
                            </>
                        )}
                    </div>
                </div>

                <div className="flex items-center gap-4 shrink-0">
                    <div className="text-right">
                        <p className="text-sm font-medium text-foreground">Super Admin</p>
                        <p className="text-xs text-muted-foreground hidden sm:block">Full System Access</p>
                    </div>
                </div>
            </div>
        </div>
    );
}

"use client";

import React, { useMemo } from 'react';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import { useDateFormat } from "@/context/TimezoneContext";

export type DailyStats = {
    date: string; // YYYY-MM-DD
    count: number;
};

interface ContributionHeatmapProps {
    data: Record<string, DailyStats>;
    leaveDates?: string[]; // Array of YYYY-MM-DD
    className?: string;
    tooltipLabel?: string;
}

const COLORS = {
    empty: "bg-muted", // Empty
    level1: "bg-green-900",  // Dark Green (1 task)
    level2: "bg-green-700",  // Medium Green (2 tasks)
    level3: "bg-green-500",  // Light Green (3 tasks)
    level4: "bg-green-400",  // Bright Green (4+ tasks)
    leave: "bg-red-500",     // RED for Leave
};

export function ContributionHeatmap({ data, className, leaveDates = [], tooltipLabel = "completed", year = new Date().getFullYear() }: ContributionHeatmapProps & { year?: number }) {
    const fmt = useDateFormat();
    // 1. Generate Calendar Grid (Fixed Year)
    const calendarData = useMemo(() => {
        const dates: Date[] = [];
        const startDate = new Date(year, 0, 1);
        const endDate = new Date(year, 11, 31);

        // Adjust to start of the week (Sunday)
        const dayOfWeek = startDate.getDay(); // 0 is Sun
        const startOffset = dayOfWeek; // Days to go back to reach Sunday
        const gridStartDate = new Date(startDate);
        gridStartDate.setDate(gridStartDate.getDate() - startOffset);

        // We need enough days to cover the whole year up to the last week
        // Loop until we reach a date > endDate AND it's the end of a week (Saturday)

        const currentDate = new Date(gridStartDate);

        // Safety break
        let count = 0;
        while (count < 400) { // 53 weeks * 7 = 371
            dates.push(new Date(currentDate));

            // Stop if we are past Dec 31 AND we just finished a week (current is Saturday)
            if (currentDate > endDate && currentDate.getDay() === 6) {
                break;
            }

            currentDate.setDate(currentDate.getDate() + 1);
            count++;
        }

        return dates;
    }, [year]);

    // Helper: Determine Color for a Day
    const getCellProps = (date: Date) => {
        const dateStr = date.toISOString().split('T')[0];

        // If date is outside the selected year, perform visual rendering but maybe dimmed or empty?
        // Typically Github shows them as empty or invisible.
        // Let's filter: if year matches, show data. Else empty.

        const isCurrentYear = date.getFullYear() === year;

        const stats = data[dateStr];
        const count = stats?.count || 0;
        const isLeave = leaveDates.includes(dateStr);

        let colorClass = COLORS.empty;

        if (isCurrentYear) {
            if (isLeave) colorClass = COLORS.leave;
            else if (count === 0) colorClass = COLORS.empty;
            else if (count === 1) colorClass = COLORS.level1;
            else if (count === 2) colorClass = COLORS.level2;
            else if (count === 3) colorClass = COLORS.level3;
            else colorClass = COLORS.level4; // 4+
        } else {
            // Days from prev/next year used for padding
            colorClass = "bg-transparent ring-0 hover:ring-0 cursor-default";
        }

        return { colorClass, count, dateStr, isLeave, isCurrentYear };
    };

    // Group by Weeks for Grid Layout (Columns = Weeks)
    const weeks = useMemo(() => {
        const weeksArray: Date[][] = [];
        let currentWeek: Date[] = [];

        calendarData.forEach((date) => {
            currentWeek.push(date);
            if (currentWeek.length === 7) {
                weeksArray.push(currentWeek);
                currentWeek = [];
            }
        });

        // Push remaining if any (shouldn't be based on logic above, but safety)
        if (currentWeek.length > 0) weeksArray.push(currentWeek);

        return weeksArray;
    }, [calendarData]);

    const months = useMemo(() => {
        const monthLabels: { label: string, index: number }[] = [];
        weeks.forEach((week, index) => {
            // Logic to place month label at the start of the month
            // If the week contains the 1st of a month, label it.
            const hasFirstOfMonth = week.some(d => d.getDate() === 1 && d.getFullYear() === year);

            if (hasFirstOfMonth) {
                const d = week.find(d => d.getDate() === 1)!;
                monthLabels.push({ label: fmt.monthShort(d), index });
            }
        });
        return monthLabels;
    }, [weeks, year]);


    return (
        <div className={cn("w-full overflow-hidden", className)}> {/* Hid overflow to remove scroller */}
            <div className="flex flex-col gap-2"> {/* Removed min-w constraint */}

                {/* Month Labels */}
                <div className="flex text-xs text-muted-foreground mb-1 relative h-6 w-full">
                    {months.map((m, i) => (
                        <span key={i} style={{ left: `${(m.index / weeks.length) * 100}%`, position: 'absolute' }}>{m.label}</span>
                    ))}
                </div>

                <div className="flex justify-between w-full h-full gap-1 sm:gap-1">
                    {weeks.map((week, wIndex) => (
                        <div key={wIndex} className="flex flex-col gap-1 sm:gap-1 flex-1 min-w-0">
                            {week.map((day, dIndex) => {
                                const { colorClass, count, isLeave, isCurrentYear } = getCellProps(day);
                                const niceDate = fmt.dateWithDay(day);

                                if (!isCurrentYear) {
                                    // Render invisible placeholder - scale with flex
                                    return <div key={dIndex} className="w-full aspect-square" />
                                }

                                return (
                                    <TooltipProvider key={dIndex}>
                                        <Tooltip delayDuration={0}>
                                            <TooltipTrigger asChild>
                                                <div
                                                    className={cn(
                                                        "w-full aspect-square rounded-[1px] sm:rounded-[2px] transition-all hover:ring-1 hover:ring-white/50 z-0 hover:z-10 cursor-pointer", // Fluid sizing
                                                        colorClass
                                                    )}
                                                    aria-label={`${count} completed tasks on ${niceDate}`}
                                                />
                                            </TooltipTrigger>
                                            <TooltipContent className="bg-card border-border text-foreground p-2 text-xs shadow-xl z-50">
                                                <p className="font-semibold mb-1">{niceDate}</p>
                                                <p className="text-muted-foreground">
                                                    {isLeave ? "On Leave" : (count === 0 ? `No tasks ${tooltipLabel}` : `${count} task${count === 1 ? '' : 's'} ${tooltipLabel}`)}
                                                </p>
                                            </TooltipContent>
                                        </Tooltip>
                                    </TooltipProvider>
                                );
                            })}
                        </div>
                    ))}
                </div>

                <div className="flex items-center justify-end text-[10px] text-muted-foreground mt-2 gap-2">
                    <span>Less</span>
                    <div className="flex gap-[2px]">
                        <div className="w-3 h-3 rounded-[2px] bg-muted" title="0 tasks"></div>
                        <div className="w-3 h-3 rounded-[2px] bg-green-900" title="1 task"></div>
                        <div className="w-3 h-3 rounded-[2px] bg-green-700" title="2 tasks"></div>
                        <div className="w-3 h-3 rounded-[2px] bg-green-500" title="3 tasks"></div>
                        <div className="w-3 h-3 rounded-[2px] bg-green-400" title="4+ tasks"></div>
                    </div>
                    <span>More</span>
                </div>
            </div>

            {/* Contribution Stats Row */}
            <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-6 border-t border-border pt-6">
                {(() => {
                    // Calculate Stats
                    const values = Object.values(data);
                    const totalTasks = values.reduce((acc, curr) => acc + curr.count, 0);
                    const activeDays = values.filter(d => d.count > 0).length;

                    // Streaks
                    let maxStreak = 0;
                    let currentStreak = 0;
                    let tempStreak = 0;

                    // Sort dates to ensure streak calculation is correct
                    const sortedDates = Object.keys(data).sort();
                    sortedDates.forEach((dateStr) => {
                        if (data[dateStr].count > 0) {
                            tempStreak++;
                            maxStreak = Math.max(maxStreak, tempStreak);
                        } else {
                            tempStreak = 0;
                        }
                    });

                    // Check current streak (working backwards from today)
                    // Simple check: if today has data, start count, else 0 (or check yesterday if today is empty?)
                    // For simplicity, we check contiguous active days ending today or yesterday.
                    const checkDate = new Date();
                    while (true) {
                        const dStr = checkDate.toISOString().split('T')[0];
                        if (data[dStr] && data[dStr].count > 0) {
                            currentStreak++;
                            checkDate.setDate(checkDate.getDate() - 1);
                        } else {
                            // If today is empty, maybe they haven't worked YET today. Check yesterday.
                            const isToday = dStr === new Date().toISOString().split('T')[0];
                            if (isToday && currentStreak === 0) {
                                checkDate.setDate(checkDate.getDate() - 1);
                                continue;
                            }
                            break;
                        }
                    }

                    return (
                        <>
                            <div className="flex flex-col">
                                <span className="text-xs text-muted-foreground">Total Completed</span>
                                <span className="text-base font-bold text-foreground">{totalTasks}</span>
                            </div>
                            <div className="flex flex-col">
                                <span className="text-xs text-muted-foreground">Max Streak</span>
                                <span className="text-base font-bold text-foreground">{maxStreak} Days</span>
                            </div>
                            <div className="flex flex-col">
                                <span className="text-xs text-muted-foreground">Current Streak</span>
                                <span className="text-base font-bold text-foreground">{currentStreak} Days</span>
                            </div>
                            <div className="flex flex-col">
                                <span className="text-xs text-muted-foreground">Active Days</span>
                                <span className="text-base font-bold text-foreground">{activeDays}</span>
                            </div>
                        </>
                    );
                })()}
            </div>
        </div>
    );
}

import { useState, useCallback } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from "@/components/ui/dialog";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { User, Client } from "@/lib/types";
import { approveDocumentUpdate, updateUser } from "@/lib/actions";
import { AlertCircle, FileText, Clock, Eye, Upload, ShieldAlert, X, Loader2 } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { toast } from "sonner";

const MAX_FILE_SIZE = 2 * 1024 * 1024; // 2MB

interface DocumentManagerProps {
    user: User | Client;
    open: boolean;
    onOpenChange: (open: boolean) => void;
    isAdmin: boolean;
    onSuccess?: () => void;
}

export function DocumentManager({ user, open, onOpenChange, isAdmin, onSuccess }: DocumentManagerProps) {
    const [activeTab, setActiveTab] = useState("identity");
    const [previewImage, setPreviewImage] = useState<string | null>(null);
    const [actionLoading, setActionLoading] = useState<string | null>(null);

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>, type: 'adhar' | 'pan' | 'contracts' | 'other' | 'contracts_add' | 'other_add') => {
        const file = e.target.files?.[0];
        if (!file) return;

        if (file.size > MAX_FILE_SIZE) {
            toast.error("File size must be under 2MB.");
            e.target.value = '';
            return;
        }

        const reader = new FileReader();
        reader.onloadend = async () => {
            const result = reader.result as string;

            try {
                if (type === 'adhar') {
                    await updateUser(user.id, { adharCardImage: result });
                } else if (type === 'pan') {
                    await updateUser(user.id, { panCardImage: result });
                } else if (type === 'contracts_add') {
                    const currentList = user.contracts || [];
                    const newList = [...currentList, result];
                    await updateUser(user.id, { contracts: newList });
                } else if (type === 'other_add') {
                    const currentList = user.otherDocuments || [];
                    const newList = [...currentList, result];
                    await updateUser(user.id, { otherDocuments: newList });
                }
                if (onSuccess) onSuccess();
            } catch (error) {
                console.error("Upload failed", error);
                toast.error("Failed to upload document");
            }
        };
        reader.readAsDataURL(file);
    };

    const handleDelete = async (index: number, type: 'contracts' | 'other') => {
        const key = `delete-${type}-${index}`;
        if (actionLoading) return;
        setActionLoading(key);
        try {
            if (type === 'contracts') {
                const currentList = user.contracts || [];
                const newList = currentList.filter((_, i) => i !== index);
                await updateUser(user.id, { contracts: newList });
            } else {
                const currentList = user.otherDocuments || [];
                const newList = currentList.filter((_, i) => i !== index);
                await updateUser(user.id, { otherDocuments: newList });
            }
            if (onSuccess) onSuccess();
        } catch (error) {
            console.error("Delete failed", error);
            toast.error("Failed to delete document");
        } finally {
            setActionLoading(null);
        }
    };

    const handleApproveReject = useCallback(async (type: 'adhar' | 'pan' | 'contracts' | 'other' | 'both', approve: boolean) => {
        const key = `${approve ? 'approve' : 'reject'}-${type}`;
        if (actionLoading) return;
        setActionLoading(key);
        try {
            await approveDocumentUpdate(user.id, type, approve);
            if (onSuccess) onSuccess();
        } catch (error) {
            console.error(`${approve ? 'Approve' : 'Reject'} failed`, error);
            toast.error(`Failed to ${approve ? 'approve' : 'reject'} documents`);
        } finally {
            setActionLoading(null);
        }
    }, [actionLoading, user.id, onSuccess]);

    const PendingBanner = ({ type, pendingList }: { type: 'contracts' | 'other', pendingList: string[] }) => {
        if (!pendingList) return null;
        return (
            <div className="bg-yellow-500/10 border border-yellow-500/20 rounded-lg p-4 mb-4">
                <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                        <Clock className="w-5 h-5 text-yellow-600 dark:text-yellow-500" />
                        <div>
                            <h4 className="font-medium text-yellow-700 dark:text-yellow-500">Pending Changes</h4>
                            <p className="text-xs text-yellow-600/80 dark:text-yellow-500/80">
                                {isAdmin ? "User has proposed changes to this list." : "Your changes are awaiting approval."}
                            </p>
                        </div>
                    </div>
                    {isAdmin && (
                        <div className="flex gap-2">
                            <button
                                onClick={() => handleApproveReject(type, true)}
                                disabled={!!actionLoading}
                                className="px-3 py-1.5 bg-green-500/10 text-green-600 dark:text-green-500 hover:bg-green-500/20 rounded-md text-sm font-medium transition-colors disabled:opacity-50 flex items-center gap-1.5"
                            >
                                {actionLoading === `approve-${type}` && <Loader2 className="w-3 h-3 animate-spin" />}
                                Approve All
                            </button>
                            <button
                                onClick={() => handleApproveReject(type, false)}
                                disabled={!!actionLoading}
                                className="px-3 py-1.5 bg-red-500/10 text-red-600 dark:text-red-500 hover:bg-red-500/20 rounded-md text-sm font-medium transition-colors disabled:opacity-50 flex items-center gap-1.5"
                            >
                                {actionLoading === `reject-${type}` && <Loader2 className="w-3 h-3 animate-spin" />}
                                Reject
                            </button>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    return (
        <>
            <Dialog open={open} onOpenChange={onOpenChange}>
                <DialogContent className="max-w-4xl max-h-[85vh] overflow-hidden flex flex-col bg-card border-border p-0 gap-0">
                    <div className="p-6 border-b border-border bg-muted/10">
                        <DialogHeader>
                            <DialogTitle className="text-xl">Document Manager</DialogTitle>
                            <DialogDescription>
                                Manage legal and identity documents for {user.name}.
                            </DialogDescription>
                        </DialogHeader>
                    </div>

                    <div className="flex-1 overflow-hidden flex">
                        <Tabs value={activeTab} onValueChange={setActiveTab} className="flex-1 flex flex-col">
                            <div className="px-6 pt-4">
                                <TabsList className="grid w-full grid-cols-3">
                                    <TabsTrigger value="identity">Identity Verification</TabsTrigger>
                                    <TabsTrigger value="contracts">Contracts & Agreements</TabsTrigger>
                                    <TabsTrigger value="other">Other Documents</TabsTrigger>
                                </TabsList>
                            </div>

                            <div className="flex-1 overflow-y-auto p-6">
                                <TabsContent value="identity" className="mt-0 space-y-6">
                                    <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                                        {/* Aadhar Section */}
                                        <IdentityCard
                                            title="Aadhar Card"
                                            image={user.adharCardImage}
                                            pendingImage={user.pendingAdharCardImage}
                                            isRequired={!user.adharCardImage && !user.pendingAdharCardImage}
                                            isAdmin={isAdmin}
                                            onApprove={() => handleApproveReject('adhar', true)}
                                            onReject={() => handleApproveReject('adhar', false)}
                                            actionLoading={actionLoading}
                                            onUpload={(e) => handleFileUpload(e, 'adhar')}
                                            onPreview={setPreviewImage}
                                        />

                                        {/* PAN Section */}
                                        <IdentityCard
                                            title="PAN Card"
                                            image={user.panCardImage}
                                            pendingImage={user.pendingPanCardImage}
                                            isRequired={!user.panCardImage && !user.pendingPanCardImage}
                                            isAdmin={isAdmin}
                                            onApprove={() => handleApproveReject('pan', true)}
                                            onReject={() => handleApproveReject('pan', false)}
                                            actionLoading={actionLoading}
                                            onUpload={(e) => handleFileUpload(e, 'pan')}
                                            onPreview={setPreviewImage}
                                        />
                                    </div>
                                </TabsContent>

                                <TabsContent value="contracts" className="mt-0">
                                    <PendingBanner type="contracts" pendingList={user.pendingContracts!} />
                                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                        {(user.pendingContracts || user.contracts || []).map((doc, idx) => (
                                            <DocumentCard
                                                key={idx}
                                                url={doc}
                                                index={idx}
                                                type="contracts"
                                                label={`Contract ${idx + 1}`}
                                                isPending={!!user.pendingContracts}
                                                onPreview={setPreviewImage}
                                                onDelete={handleDelete}
                                                isDeleting={actionLoading === `delete-contracts-${idx}`}
                                            />
                                        ))}
                                        <UploadCard label="Add Contract" onChange={(e) => handleFileUpload(e, 'contracts_add')} />
                                    </div>
                                </TabsContent>

                                <TabsContent value="other" className="mt-0">
                                    <PendingBanner type="other" pendingList={user.pendingOtherDocuments!} />
                                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                                        {(user.pendingOtherDocuments || user.otherDocuments || []).map((doc, idx) => (
                                            <DocumentCard
                                                key={idx}
                                                url={doc}
                                                index={idx}
                                                type="other"
                                                label={`Document ${idx + 1}`}
                                                isPending={!!user.pendingOtherDocuments}
                                                onPreview={setPreviewImage}
                                                onDelete={handleDelete}
                                                isDeleting={actionLoading === `delete-other-${idx}`}
                                            />
                                        ))}
                                        <UploadCard label="Add Document" onChange={(e) => handleFileUpload(e, 'other_add')} />
                                    </div>
                                </TabsContent>
                            </div>
                        </Tabs>
                    </div>
                </DialogContent>
            </Dialog>

            {previewImage && (
                <Dialog open={!!previewImage} onOpenChange={() => setPreviewImage(null)}>
                    <DialogContent className="max-w-[95vw] md:max-w-[90vw] h-[95vh] p-0 overflow-hidden bg-black/95 border-none">
                        <DialogTitle className="sr-only">Document Preview</DialogTitle>
                        <div className="relative w-full h-full flex items-center justify-center">
                            <button onClick={() => setPreviewImage(null)} className="absolute top-4 right-4 p-2 bg-white/10 hover:bg-white/20 text-white rounded-full z-50">
                                <X className="w-6 h-6" />
                            </button>
                            <img src={previewImage} alt="Document preview" className="max-w-full max-h-full object-contain" />
                        </div>
                    </DialogContent>
                </Dialog>
            )}
        </>
    );
}

function DocumentCard({ url, index, type, label, isPending, onPreview, onDelete, isDeleting }: { url: string, index: number, type: 'contracts' | 'other', label: string, isPending: boolean, onPreview: (url: string) => void, onDelete: (index: number, type: 'contracts' | 'other') => void, isDeleting?: boolean }) {
    return (
        <div className={`group relative flex flex-col rounded-lg border bg-card overflow-hidden transition-all hover:shadow-md ${isPending ? 'border-yellow-500/50' : 'border-border'}`}>
            <div className="aspect-[4/3] bg-muted relative overflow-hidden">
                <img
                    src={url}
                    className="w-full h-full object-cover object-top transition-transform duration-500 group-hover:scale-105"
                    alt={label}
                />

                {/* Hover Overlay */}
                <div className="absolute inset-0 bg-black/60 opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-2 p-2">
                    <button
                        onClick={() => onPreview(url)}
                        className="px-3 py-1.5 bg-white text-black rounded-md text-xs font-bold hover:bg-gray-200 transition-colors w-24"
                    >
                        View
                    </button>
                    <button
                        onClick={() => onDelete(index, type)}
                        disabled={isDeleting}
                        className="px-3 py-1.5 bg-red-600 text-white rounded-md text-xs font-bold hover:bg-red-700 transition-colors w-24 disabled:opacity-50 flex items-center justify-center gap-1"
                    >
                        {isDeleting ? <><Loader2 className="w-3 h-3 animate-spin" /> Deleting</> : 'Delete'}
                    </button>
                </div>
            </div>

            <div className="p-3 border-t border-border bg-card">
                <div className="flex items-center gap-2">
                    <FileText className={`w-4 h-4 ${type === 'contracts' ? 'text-primary' : 'text-purple-500'}`} />
                    <span className="text-sm font-medium truncate" title={label}>{label}</span>
                </div>
            </div>
        </div>
    );
}

function UploadCard({ label, onChange }: { label: string, onChange: (e: React.ChangeEvent<HTMLInputElement>) => void }) {
    return (
        <label className="flex flex-col aspect-[4/3] md:aspect-auto md:h-full min-h-[140px] rounded-lg border-2 border-dashed border-muted-foreground/20 hover:border-primary/50 hover:bg-accent/5 transition-all cursor-pointer items-center justify-center gap-2 text-muted-foreground hover:text-primary">
            <div className="p-3 rounded-full bg-muted/50 group-hover:bg-primary/10 transition-colors">
                <Upload className="w-6 h-6" />
            </div>
            <span className="text-sm font-medium">{label}</span>
            <input type="file" accept="image/*" className="hidden" onChange={onChange} />
        </label>
    );
}

// Identity Card Helper
interface IdentityCardProps {
    title: string;
    image?: string;
    pendingImage?: string;
    isRequired: boolean;
    isAdmin: boolean;
    onApprove: () => void;
    onReject: () => void;
    onUpload: (e: React.ChangeEvent<HTMLInputElement>) => void;
    onPreview: (url: string) => void;
    actionLoading?: string | null;
}

function IdentityCard({ title, image, pendingImage, isRequired, isAdmin, onApprove, onReject, onUpload, onPreview, actionLoading }: IdentityCardProps) {
    const hasPending = !!pendingImage;

    return (
        <div className="space-y-3">
            <div className="flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <h3 className="font-medium">{title}</h3>
                    {isRequired && (
                        <Badge variant="destructive" className="flex items-center gap-1 text-[10px] px-1.5 py-0 h-5">
                            <AlertCircle className="w-3 h-3" /> Required
                        </Badge>
                    )}
                </div>
                {/* Status Badges */}
                {isAdmin && hasPending && (
                    <div className="flex gap-2 items-center">
                        <Badge variant="outline" className="border-yellow-500 text-yellow-500 bg-yellow-500/10">Pending Approval</Badge>
                        <button onClick={onApprove} disabled={!!actionLoading} className="text-xs text-green-500 font-medium hover:underline disabled:opacity-50 flex items-center gap-1">
                            {actionLoading?.startsWith('approve') && <Loader2 className="w-3 h-3 animate-spin" />}
                            Approve
                        </button>
                        <button onClick={onReject} disabled={!!actionLoading} className="text-xs text-red-500 font-medium hover:underline disabled:opacity-50 flex items-center gap-1">
                            {actionLoading?.startsWith('reject') && <Loader2 className="w-3 h-3 animate-spin" />}
                            Reject
                        </button>
                    </div>
                )}
                {!isAdmin && hasPending && (
                    <Badge variant="secondary" className="text-yellow-500 bg-yellow-500/10">Verification Pending</Badge>
                )}
            </div>

            <div className="flex gap-4">
                {/* Current Image */}
                <div className="flex-1">
                    <div className="aspect-[4/3] relative rounded-lg border-2 border-dashed border-muted-foreground/20 bg-muted/5 flex items-center justify-center overflow-hidden group">
                        {image ? (
                            <>
                                <img src={image} alt={title} className="w-full h-full object-cover object-top transition-transform group-hover:scale-105" />
                                <div className="absolute inset-0 bg-black/40 opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2">
                                    <button
                                        onClick={() => onPreview(image)}
                                        aria-label={`Preview ${title}`}
                                        className="p-2 bg-background/20 backdrop-blur text-white rounded-full hover:bg-background/40"
                                    >
                                        <Eye className="w-5 h-5" />
                                    </button>
                                </div>
                            </>
                        ) : (
                            <div className="flex flex-col items-center gap-2 text-muted-foreground">
                                <ShieldAlert className="w-8 h-8 opacity-50" />
                                <span className="text-sm">No Document</span>
                            </div>
                        )}
                    </div>
                    <label className="mt-2 block">
                        <span className="sr-only">Upload {title}</span>
                        <input type="file" accept="image/*" className="hidden" onChange={onUpload} />
                        <div className="text-xs text-center text-primary cursor-pointer hover:underline">
                            {image ? "Replace Document" : "Upload Document"}
                        </div>
                    </label>
                </div>

                {/* Pending Image (Side by Side if exists) */}
                {hasPending && (
                    <div className="flex-1 opacity-80 relative">
                        <div className="absolute -top-3 left-0 bg-yellow-500 text-white text-[10px] px-2 py-0.5 rounded-full font-bold z-10">
                            PENDING
                        </div>
                        <div className="group aspect-[4/3] relative rounded-lg border-2 border-yellow-500/30 bg-yellow-500/5 flex items-center justify-center overflow-hidden">
                            <img src={pendingImage} alt={`Pending ${title}`} className="w-full h-full object-cover object-top" />
                            <div className="absolute inset-0 flex items-center justify-center opacity-100 md:opacity-0 md:group-hover:opacity-100 transition-opacity">
                                <button
                                    onClick={() => onPreview(pendingImage!)}
                                    aria-label={`Preview pending ${title}`}
                                    className="p-2 bg-black/40 text-white rounded-full"
                                >
                                    <Eye className="w-5 h-5" />
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

"use client";

import { useRef } from "react";
import { Calendar } from "lucide-react";
import { cn } from "@/lib/utils";

interface DateTimeInputProps {
    type?: "datetime-local" | "date" | "time";
    value: string;
    onChange: (e: React.ChangeEvent<HTMLInputElement>) => void;
    className?: string;
    disabled?: boolean;
    min?: string;
    max?: string;
    placeholder?: string;
    required?: boolean;
}

/**
 * A theme-aware date/datetime input that shows a visible Lucide
 * Calendar icon regardless of the browser's color-scheme quirks.
 * Clicking the icon programmatically opens the native picker.
 */
export function DateTimeInput({
    type = "datetime-local",
    value,
    onChange,
    className,
    disabled,
    min,
    max,
    required,
}: DateTimeInputProps) {
    const inputRef = useRef<HTMLInputElement>(null);

    const handleIconClick = () => {
        if (disabled || !inputRef.current) return;
        try {
            (inputRef.current as any).showPicker?.();
        } catch {
            inputRef.current.focus();
        }
    };

    return (
        <div className="relative flex items-center">
            <input
                ref={inputRef}
                type={type}
                value={value}
                onChange={onChange}
                disabled={disabled}
                min={min}
                max={max}
                required={required}
                className={cn(
