    const currentUserId = await getSessionId();
    if (currentUserId) {
        const currentUser = await getCurrentUser();
        if (currentUser?.role === 'client') {
            const clientProjectIds = await ProjectModel.distinct('id', { clientId: currentUserId, ...agencyFilter });
