/**
 * Generate content using the configured AI provider.
 * Returns { text, tokens } where tokens may be undefined for Live API models.
 */
export async function generateContent(
    config: AIConfig,
    prompt: string,
    systemInstruction?: string
): Promise<{ text: string; tokens?: TokenUsage }> {
    if (config.provider === "gemini") {
        const modelId = resolveModel(config);
        if (isLiveModel(modelId)) {
            return { text: await liveGenerateContent(config, prompt, systemInstruction) };
        }
        return geminiGenerateContent(config, prompt, systemInstruction);
    }
    return openaiCompatGenerateContent(config, prompt, systemInstruction);
}

/**
 * Generate content with multimodal parts (text + images).
 * Returns { text, tokens } where tokens may be undefined for Live/OpenAI providers.
 */
export async function generateContentWithParts(
    config: AIConfig,
    parts: any[],
    systemInstruction?: string
): Promise<{ text: string; tokens?: TokenUsage }> {
    if (config.provider === "gemini") {
        const modelId = resolveModel(config);
        if (isLiveModel(modelId)) {
            const textContent = parts
                .filter((p: any) => typeof p === 'string' || p.text)
                .map((p: any) => (typeof p === 'string' ? p : p.text))
                .join('\n');
            return { text: await liveGenerateContent(config, textContent, systemInstruction) };
        }
        return geminiGenerateContentWithParts(config, parts, systemInstruction);
    }
    const textParts = parts
        .filter((p: any) => typeof p === "string" || p.text)
        .map((p: any) => (typeof p === "string" ? p : p.text))
        .join("\n");
    return openaiCompatGenerateContent(config, textParts, systemInstruction);
}

/**
 * Chat with AI using conversation history.
 * Returns { text, tokens } where tokens may be undefined for Live API models.
 */
export async function generateContentWithChat(
    config: AIConfig,
    history: ChatMessage[],
    systemInstruction: string,
    userMessage: string
): Promise<{ text: string; tokens?: TokenUsage }> {
    if (config.provider === "gemini") {
        const modelId = resolveModel(config);
        if (isLiveModel(modelId)) {
            return { text: await liveChat(config, history, systemInstruction, userMessage) };
        }
        return geminiChat(config, history, systemInstruction, userMessage);
    }
    return openaiCompatChat(config, history, systemInstruction, userMessage);
}

"use server";

import { cookies } from "next/headers";
import { SuperAdminModel, UserModel, ClientModel, connectDB, RateLimitModel, SystemSettingsModel } from "./mongodb";
import bcrypt from "bcryptjs";
import { signToken, verifyToken, AuthSession } from "./auth-utils";
import { validatePassword, validateStrongPassword } from "./validation";

import { validateEmail } from "./validation";

// --- Rate limiting for login (MongoDB-backed) ---
const MAX_LOGIN_ATTEMPTS = 10;
const LOGIN_WINDOW_MS = 15 * 60 * 1000; // 15 minutes

async function checkLoginRateLimit(email: string): Promise<void> {
    const key = `login:${email.toLowerCase().trim()}`;
    const now = new Date();
    const record = await RateLimitModel.findOne({ key, expiresAt: { $gt: now } }).lean();
    if (record) {
        if ((record as any).count >= MAX_LOGIN_ATTEMPTS) {
            throw new Error('Too many login attempts. Please try again later.');
        }
        await RateLimitModel.updateOne({ key }, { $inc: { count: 1 } });
    } else {
        await RateLimitModel.findOneAndUpdate(
            { key },
            { count: 1, expiresAt: new Date(now.getTime() + LOGIN_WINDOW_MS) },
            { upsert: true }
        );
    }
}

async function resetLoginRateLimit(email: string): Promise<void> {
    await RateLimitModel.deleteOne({ key: `login:${email.toLowerCase().trim()}` });
}

// --- Password Utilities ---

export async function hashPassword(password: string): Promise<string> {
    const salt = await bcrypt.genSalt(12);
    return bcrypt.hash(password, salt);
}

export async function comparePassword(plain: string, stored: string): Promise<boolean> {
    // Only compare against properly hashed passwords
    if (stored.startsWith('$2a$') || stored.startsWith('$2b$') || stored.startsWith('$2y$')) {
        return bcrypt.compare(plain, stored);
    }
    // Reject login if password is not hashed — run migrate-passwords script to fix
    return false;
}

// --- Session Management ---

export async function getSessionId() {
    const cookieStore = await cookies();
    // Only accept JWT — legacy cookie fallback removed for security
    const token = cookieStore.get("auth_token")?.value;
    if (token) {
        const session = await verifyToken(token);
        if (session) return session.userId;
    }
    return undefined;
}

export async function login(userId: string, role: string, agencyId?: string): Promise<void> {
    const token = await signToken({ userId, role, agencyId });
    const cookieStore = await cookies();

    // Set secure HTTP-only cookie
    cookieStore.set("auth_token", token, {
        httpOnly: true,
        secure: process.env.NODE_ENV === "production",
        sameSite: "lax",
        path: "/",
        maxAge: 60 * 60 * 24 // 24 hours
    });

    // Client-readable indicator (NOT the token itself) so Navigation can show Dashboard vs Login
    cookieStore.set("logged_in", "1", { httpOnly: false, secure: process.env.NODE_ENV === "production", sameSite: "lax", path: "/", maxAge: 60 * 60 * 24 });
}

export async function logout() {
    const cookieStore = await cookies();
    cookieStore.delete("auth_token");
    cookieStore.delete("selectedAgencyId");
    cookieStore.delete("logged_in");
    // Also clean up any remaining legacy cookies
    cookieStore.delete("userId");
    cookieStore.delete("userRole");
}

/**
 * Check if current user is a super admin
 */
export async function isSuperAdmin(): Promise<boolean> {
    const session = await getSessionUser();
    return session?.role === 'superadmin';
}

/**
 * Get current session user with role
 */
export async function getSessionUser(): Promise<AuthSession | null> {
    const cookieStore = await cookies();
    const token = cookieStore.get("auth_token")?.value;

    if (token) {
        return verifyToken(token);
    }

    // No JWT token = not authenticated (legacy fallback removed for security)
    return null;
}

export type LoginResult = {
    success: boolean;
    error?: string;
    redirectTo?: string;
};

export async function authenticateUser(email: string, password: string): Promise<LoginResult> {
    // Validate email format and normalize to lowercase before DB queries
    try {
        email = validateEmail(email);
    } catch {
        return { success: false, error: "Invalid email or password" };
    }

    try {
        await connectDB();
        // Rate limiting check
        await checkLoginRateLimit(email);
    } catch (e: any) {
        return { success: false, error: e.message || 'Too many login attempts. Please try again later.' };
    }

    // 1. Check Super Admin
    const superAdmin = await SuperAdminModel.findOne({ email }).lean();
    if (superAdmin) {
        if (superAdmin.password && await comparePassword(password, superAdmin.password)) {
            await resetLoginRateLimit(email);
            await login(superAdmin.id, 'superadmin');
            return { success: true, redirectTo: '/super-admin' };
        }
    }

    // 2. Check Users
    const matchedUsers = await UserModel.find({ email }).lean();
    if (matchedUsers.length > 1) {
        return { success: false, error: "Multiple accounts found for this email. Please contact support." };
    }
    const user = matchedUsers[0];
    if (user) {
        if ((user as any).archived) {
            return { success: false, error: 'This account has been deactivated. Please contact your agency.' };
        }
        if (user.password && await comparePassword(password, user.password)) {
            await resetLoginRateLimit(email);
            await login(user.id, user.role, user.agencyId);
            return { success: true, redirectTo: '/dashboard' };
        }
    }

    // 3. Check Clients
    const matchedClients = await ClientModel.find({ email }).lean();
    if (matchedClients.length > 1) {
        return { success: false, error: "Multiple accounts found for this email. Please contact support." };
    }
    const client = matchedClients[0];
    if (client) {
        if ((client as any).archived) {
            return { success: false, error: 'This account has been deactivated. Please contact your agency.' };
        }
        if (client.password && await comparePassword(password, client.password)) {
            await resetLoginRateLimit(email);
            await login(client.id, 'client', client.agencyId);
            return { success: true, redirectTo: '/dashboard' };
        }
    }

    return { success: false, error: "Invalid email or password" };
}

export async function updatePassword(currentPassword: string, newPassword: string): Promise<{ success: boolean; error?: string }> {
    const session = await getSessionUser();

    if (!session) return { success: false, error: "Unauthorized" };

    // Validate new password against system policy
    try {
        await connectDB();
        const sys = await SystemSettingsModel.findOne(
            { key: 'global' },
            { 'security.enforceStrongPasswords': 1 }
        ).lean() as any;
        const enforceStrong = sys?.security?.enforceStrongPasswords ?? true;
        if (enforceStrong) {
            validateStrongPassword(newPassword);
        } else {
            validatePassword(newPassword);
        }
    } catch (e: any) {
        return { success: false, error: e.message || 'Invalid password' };
    }

    // 1. Fetch User Document
    let user: any;
    let model: any;

    if (session.role === 'superadmin') {
        user = await SuperAdminModel.findOne({ id: session.userId });
        model = SuperAdminModel;
    } else if (session.role === 'client') {
        user = await ClientModel.findOne({ id: session.userId });
        model = ClientModel;
    } else {
        user = await UserModel.findOne({ id: session.userId });
        model = UserModel;
    }

    if (!user) {
        return { success: false, error: "User not found" };
    }

    // 2. Verify Current Password
    if (user.password) {
        const isMatch = await comparePassword(currentPassword, user.password);
        if (!isMatch) {
            return { success: false, error: "Incorrect current password" };
        }
    } else {
        // No password in DB — reject update, require admin reset
        return { success: false, error: "No password configured. Contact an administrator." };
    }

    // 3. Hash & Update
    const hashedPassword = await hashPassword(newPassword);

    await model.findOneAndUpdate({ id: session.userId }, { password: hashedPassword });

    return { success: true };
}

/**
 * Brevo Email Service
 * Handles all email notifications for the agency-os application
 */

import { EMAIL_TEMPLATES, TEMPLATE_TO_CATEGORY, DEFAULT_EMAIL_CATEGORIES } from "./email-constants";
import type { EmailCategory } from "./email-constants";
import { getCurrentAgency } from "./agency-context";
import { formatCurrency } from "./currency";
import { getDefaultCurrency } from "./actions/super-admin";

interface EmailParams {
  to: string | string[];
  templateId: number;
  params: Record<string, any>;
  subject?: string;
}

/**
 * Send email using Brevo API
 */
export async function sendEmail({ to, templateId, params, subject }: EmailParams): Promise<boolean> {
  try {
    const BREVO_API_KEY = process.env.BREVO_API_KEY;
    const BREVO_SENDER_EMAIL = process.env.BREVO_SENDER_EMAIL;
    const BREVO_SENDER_NAME = process.env.BREVO_SENDER_NAME;

    // Skip if Brevo is not configured
    if (!BREVO_API_KEY || !BREVO_SENDER_EMAIL || !BREVO_SENDER_NAME) {
      console.warn('[Brevo] Email service not configured. Skipping email send.');
      return false;
    }

    // CHECK: Global Kill Switch
    const agency = await getCurrentAgency();
    if (agency?.settings?.emailNotificationsEnabled === false) {
      console.warn('[Brevo] Email sending is globally disabled via settings.');
      return true;
    }

    // CHECK: Per-category toggle
    const category = TEMPLATE_TO_CATEGORY[templateId];
    if (category) {
      const categories = agency?.settings?.emailCategories || {};
      const isEnabled = (categories as any)[category] ?? DEFAULT_EMAIL_CATEGORIES[category];
      if (!isEnabled) {
        console.log(`[Brevo] Email category "${category}" is disabled. Skipping template ${templateId}.`);
        return true;
      }
    }

    const recipients = Array.isArray(to) ? to.map(email => ({ email })) : [{ email: to }];

    const response = await fetch('https://api.brevo.com/v3/smtp/email', {
      method: 'POST',
      headers: {
        'Accept': 'application/json',
        'Content-Type': 'application/json',
        'api-key': BREVO_API_KEY,
      },
      body: JSON.stringify({
        sender: {
          name: BREVO_SENDER_NAME,
          email: BREVO_SENDER_EMAIL,
        },
        to: recipients,
        templateId,
        params,
        ...(subject && { subject }),
      }),
    });

    if (!response.ok) {
      const error = await response.text();
      console.error('[Brevo] Email send failed:', error);
      return false;
    }

    const result = await response.json();
    console.log('[Brevo] Email sent successfully:', result.messageId);
    return true;
  } catch (error) {
    console.error('[Brevo] Email send error:', error);
    return false;
  }
}

