/**
 * Build a rich system instruction for Singularity Agent Mode.
 * Fetches live agency data so the AI knows about projects, clients, team,
 * finance, services (categories), and per-employee task assignments.
 */
export async function buildSingularityContext(userId: string): Promise<string> {
    try {
        // Fetch all data in parallel
        const [projects, clients, users, financeStats, recentActivity, services, _currency] = await Promise.all([
            getProjects().catch(() => []),
            getClients().catch(() => []),
            getUsers().catch(() => []),
            getFinanceStats().catch(() => ({
                totalRevenue: 0,
                totalExpenses: 0,
                netProfit: 0,
                pendingInvoicesAmount: 0,
                pendingInvoicesCount: 0,
            })),
            getRecentActivity(0, 10).catch(() => []),
            getServices().catch(() => []),
            getDefaultCurrency().catch(() => "USD"),
        ]);

        // Find the current user
        const currentUser = await getCurrentUser().catch(() => null);
        const userName = currentUser?.name || "User";
        const userRole = currentUser?.role || "unknown";

        // Build a user lookup map for assignee names
        const userMap = new Map<string, any>();
        for (const u of users) {
            userMap.set(u.id, u);
        }

        // Build quick lookup table (name ? ID) for easy matching
        let lookupSection = "";
        const teamMembers = users.filter((u: any) => u.role !== "client");
        if (teamMembers.length > 0) {
            lookupSection += "TEAM NAME ? ID:\n";
            for (const u of teamMembers) {
                lookupSection += `  "${u.name}" ? assigneeId: "${u.id}"\n`;
            }
        }
        if (projects.length > 0) {
            lookupSection += "\nPROJECT NAME ? ID:\n";
            for (const p of projects.slice(0, 20)) {
                lookupSection += `  "${(p as any).name}" ? projectId: "${(p as any).id}"\n`;
            }
        }
        if (clients.length > 0) {
            lookupSection += "\nCLIENT NAME ? ID:\n";
            for (const c of (clients as any[]).slice(0, 20)) {
                lookupSection += `  "${c.name}" (${c.companyName || ""}) ? clientId: "${c.id}"\n`;
            }
        }

        // Build service/category list
        let categorySection = "";
        if (services.length > 0) {
            categorySection = services
                .map((s: any) => `- "${s.name}"${s.employees?.length ? ` (Employees: ${s.employees.join(", ")})` : ""}`)
                .join("\n");
        } else {
            categorySection = "(No services/categories configured)";
        }

        // Build project summaries with task details
        let projectSection = "";
        if (projects.length > 0) {
            const projectLines = await Promise.all(
                projects.slice(0, 20).map(async (p: any) => {
                    const tasks = await getTasks(p.id).catch(() => []);
                    const todo = tasks.filter((t: any) => t.status === "Todo");
                    const inProgress = tasks.filter((t: any) => t.status === "In Progress");
                    const review = tasks.filter((t: any) => t.status === "Review");
                    const done = tasks.filter((t: any) => t.status === "Done");
                    const clientName = p.client || "No Client";

                    let line = `\n### Project: "${p.name}" (ID: "${p.id}")`;
                    line += `\n  Status: ${p.status} | Client: ${clientName}`;
                    line += `\n  Tasks: ${tasks.length} total — ${todo.length} Todo, ${inProgress.length} In Progress, ${review.length} Review, ${done.length} Done`;

                    // List active tasks with assignee info
                    const activeTasks = [...todo, ...inProgress, ...review].slice(0, 15);
                    if (activeTasks.length > 0) {
                        line += `\n  Active tasks:`;
                        for (const t of activeTasks) {
                            const assignee = userMap.get(t.assigneeId);
                            const assigneeName = assignee ? assignee.name : "Unassigned";
                            line += `\n    - "${t.title}" (ID: "${t.id}") | ${t.status} | Priority: ${t.priority || "Medium"} | Assigned: ${assigneeName} | Category: ${t.category || "None"} | Due: ${t.dueDate || "No date"}`;
                        }
                    }

                    return line;
                })
            );
            projectSection = projectLines.join("\n");
        } else {
            projectSection = "(No projects yet)";
        }

        // Build client list
        let clientSection = "";
        if (clients.length > 0) {
            clientSection = clients
                .slice(0, 20)
                .map((c: any) => `- ID: "${c.id}" | ${c.name} | Company: ${c.companyName} | Email: ${c.email || "N/A"}`)
                .join("\n");
        } else {
            clientSection = "(No clients yet)";
        }

        // Build team member list WITH their current task assignments
        let teamSection = "";
        if (users.length > 0) {
            const teamLines = await Promise.all(
                users.filter((u: any) => u.role !== "client").slice(0, 20).map(async (u: any) => {
                    const tasks = await getUserTasks(u.id).catch(() => []);
                    const todo = tasks.filter((t: any) => t.status === "Todo").length;
                    const inProgress = tasks.filter((t: any) => t.status === "In Progress").length;
                    const review = tasks.filter((t: any) => t.status === "Review").length;
                    const done = tasks.filter((t: any) => t.status === "Done").length;

                    let line = `- ID: "${u.id}" | ${u.name} (${u.role}) | ${u.jobTitle || "No title"} | Email: ${u.email}`;
                    line += `\n    Tasks: ${tasks.length} total — ${todo} Todo, ${inProgress} In Progress, ${review} Review, ${done} Done`;

                    // Show their active tasks
                    const activeTasks = tasks.filter((t: any) => t.status !== "Done").slice(0, 5);
                    if (activeTasks.length > 0) {
                        line += `\n    Currently working on:`;
                        for (const t of activeTasks) {
                            line += `\n      ? "${t.title}" (${t.status}) | Priority: ${t.priority || "Medium"}`;
                        }
                    }

                    return line;
                })
            );
            teamSection = teamLines.join("\n");
        } else {
            teamSection = "(No team members yet)";
        }

        // Finance snapshot
        const finance = financeStats as any;
        const financeSection = `Revenue: ${formatCurrency(finance.totalRevenue || 0, _currency)} | Expenses: ${formatCurrency(finance.totalExpenses || 0, _currency)} | Net Profit: ${formatCurrency(finance.netProfit || 0, _currency)}
Pending Invoices: ${finance.pendingInvoicesCount || 0} (${formatCurrency(finance.pendingInvoicesAmount || 0, _currency)})`;

        // Recent activity
        let activitySection = "";
        if (recentActivity.length > 0) {
            activitySection = recentActivity
                .slice(0, 8)
                .map((a: any) => `- ${a.user}: ${a.action} ? ${a.target} (${fmtDate(a.timestamp, 'UTC', 'en-US')})`)
                .join("\n");
        } else {
            activitySection = "(No recent activity)";
        }

        // Compose the system instruction
        return `You are Singularity Agent — an AI-powered agency management assistant.
You are talking to ${userName} (role: ${userRole}, ID: "${currentUser?.id || userId}").

You have full awareness of this agency's data and can perform actions using the tools available to you.

?? CRITICAL: Always use EXACT IDs from the lookup table below. NEVER guess or fabricate IDs.

--- QUICK LOOKUP TABLE ---
${lookupSection}

--- TASK CATEGORIES (from Services) ---
When creating tasks, use one of these exact category names:
${categorySection}

--- PROJECTS ---
${projectSection}

--- CLIENTS ---
${clientSection}

--- TEAM MEMBERS & WORKLOAD ---
${teamSection}

--- FINANCE SNAPSHOT ---
${financeSection}

--- RECENT ACTIVITY ---
${activitySection}

--- INSTRUCTIONS ---
- When asked about agency data, answer using the information above.
- When asked to perform an action (create task, update status, etc.), use the appropriate tool.

?? ASSIGNING TASKS — SMART AUTO-ASSIGN:
- If the user says "assign to [name]", look up that person's exact assigneeId from the QUICK LOOKUP TABLE.
- If the user does NOT specify who to assign to, you MUST auto-assign to the team member with the FEWEST active tasks (Todo + In Progress + Review). Check the TEAM MEMBERS & WORKLOAD section to find who has the least work. NEVER default to the admin or the current user — always pick the least busy developer/employee.
- After assigning, ALWAYS confirm by name who it was assigned to and why (e.g. "Assigned to Rahul — he currently has the fewest active tasks").

?? DUE DATE — SMART ESTIMATION:
- If the user does NOT specify a due date, estimate one based on the task:
  - Simple/small tasks (bug fix, text change, minor update): 2 days from now
  - Medium tasks (new feature section, design update, integration): 5 days from now
  - Large/complex tasks (full page build, major refactor, new system): 10 days from now
- Factor in the task priority: High priority tasks should have shorter deadlines.
- Use YYYY-MM-DD format. Today's date is ${new Date().toISOString().split("T")[0]}.

?? AI PROJECT PLANNER — BULK TASK GENERATION:
When the user provides a project brief or asks you to "plan a project" or "break down tasks":
- Use the bulk_create_tasks tool to create ALL tasks at once.
- Generate a COMPREHENSIVE breakdown — aim for 15-100+ tasks covering the FULL project scope.
- Organize tasks into phases: Planning ? Design ? Development ? Testing ? Deployment.
- For EACH task, provide: a clear title, detailed description with acceptance criteria, the right category (from services), appropriate priority, and estimatedDays.
- DISTRIBUTE assignees evenly across the team based on their role/expertise and current workload. Match task categories to team members' skills.
- Set estimatedDays realistically (1-14 per task). The system auto-calculates sequential due dates per assignee.
- After creating, present a summary table showing phases, task distribution, and project timeline.

?? RESPONSE FORMATTING — CRITICAL:
- NEVER show raw IDs (like "euumyvv5t" or "3g4x23wyr") to the user. These are internal system IDs.
- ALWAYS refer to people by their NAME (e.g. "Rahul", "Priya"), not their ID.
- ALWAYS refer to projects by their NAME (e.g. "Web Redesign"), not their ID.
- IDs are ONLY for tool calls (assigneeId, projectId, taskId parameters). In your text responses, ONLY use human-readable names.
- ALWAYS end every response with proper sentence-ending punctuation (. ! or ?).

GENERAL:
- When creating a task, ALWAYS set: assigneeId, category (from services list), priority, and dueDate.
- If the user doesn't specify a category, pick the most appropriate one from the services list.
- If the user refers to a project/person by name, match it to the correct ID from the QUICK LOOKUP TABLE.
- Be professional, concise, and helpful. Use markdown formatting.
- If you cannot find a matching project or person, ask the user to clarify. NEVER fabricate IDs.

?? PROJECT SERVICES/CATEGORIES — CRITICAL:
- When creating a project with create_project, ALWAYS populate the services array with relevant category names from the SERVICES list.
- Example: for a mobile app project ? services: ["Mobile Development", "UI Design", "QA Testing"]
- If a project already exists without categories, use update_project to add the services array.
- NEVER create a project with an empty services array if the agency has services configured.

?? STRICT TOOL USAGE CONSTRAINTS — NEVER VIOLATE THESE:
- You can ONLY perform actions by calling the appropriate tool. If no tool exists for an action, tell the user it is not possible.
- NEVER claim to have completed an action unless you ACTUALLY called a tool and received a successful response.
- If a tool call is not shown in the Actions panel, you did NOT perform that action. Do not pretend otherwise.
- To move many tasks to Done at once, use bulk_update_task_status (with autoBackdate=true for per-task dates). Do NOT use update_task_status in a loop.
- If you cannot complete a request in one turn, tell the user honestly and suggest breaking it into smaller steps.`;

    } catch (error) {
        console.error("[Singularity Context] Error building context:", error);
        return `You are Singularity Agent — an AI assistant.
Could not load full agency data. Answer questions generally and inform the user that agency data is temporarily unavailable.`;
    }
}

"use server";

import { connectDB, SingularityChatSessionModel, SingularityCheckpointModel, TaskModel, ProjectModel, ClientModel, InvoiceModel, TransactionModel, ServiceModel, LeaveRequestModel } from "./mongodb";
import { getCurrentAgency } from "./agency-context";
import { generateId } from "./utils-server";
import { getSessionUser } from "./auth";

// ============================================================================
// TYPES
// ============================================================================

export interface ChatSessionSummary {
    id: string;
    title: string;
    mode: 'chat' | 'agent';
    updatedAt: string;
    messageCount: number;
}

export interface ChatMessage {
    role: 'user' | 'model';
    content: string;
    thinking?: string;
    images?: string[];
    toolActions?: {
        name: string;
        displayName: string;
        status: 'calling' | 'done' | 'error';
        summary?: string;
        success?: boolean;
    }[];
    timestamp: string;
}

export interface CheckpointAction {
    toolName: string;
    actionType: 'create' | 'update' | 'delete';
    entityType: 'task' | 'project' | 'client' | 'invoice' | 'transaction' | 'service' | 'leaveRequest' | 'comment';
    entityId: string;
    beforeSnapshot?: any;
    createdEntityIds?: string[];
    executedAt: string;
}

export interface ConflictInfo {
    entityType: string;
    entityId: string;
    entityName: string;
    reason: string; // e.g. "Modified after creation", "Has new child tasks", "Comments added"
}

export interface RollbackAnalysis {
    checkpointId: string;
    label: string;
    totalActions: number;
    safeActions: CheckpointAction[];
    conflictedActions: { action: CheckpointAction; conflict: ConflictInfo }[];
}

// ============================================================================
// CHAT SESSION CRUD
// ============================================================================

export async function getSingularitySessions(_userId?: string): Promise<ChatSessionSummary[]> {
    const session = await getSessionUser();
    if (!session) throw new Error('Unauthorized');
    const userId = session.userId;

    await connectDB();
    const agency = await getCurrentAgency();
    const agencyId = agency?.id || 'default-agency';

    const sessions = await SingularityChatSessionModel
        .find({ userId, agencyId })
        .sort({ updatedAt: -1 })
        .lean();

    return sessions.map((s: any) => ({
        id: s.id,
        title: s.title || 'New Chat',
        mode: s.mode,
        updatedAt: s.updatedAt,
        messageCount: s.messages?.length || 0,
    }));
}

export async function getSingularitySession(sessionId: string) {
    const session = await getSessionUser();
    if (!session) throw new Error('Unauthorized');

    await connectDB();
    const chatSession = await SingularityChatSessionModel.findOne({ id: sessionId, userId: session.userId }).lean();
    if (!chatSession) return null;
    return {
        id: (chatSession as any).id,
        userId: (chatSession as any).userId,
        title: (chatSession as any).title,
        mode: (chatSession as any).mode,
        messages: (chatSession as any).messages || [],
        createdAt: (chatSession as any).createdAt,
        updatedAt: (chatSession as any).updatedAt,
    };
}

export async function createSingularitySession(_userId: string, mode: 'chat' | 'agent'): Promise<string> {
    const session = await getSessionUser();
    if (!session) throw new Error('Unauthorized');
    const userId = session.userId;

    await connectDB();
    const agency = await getCurrentAgency();
    const agencyId = agency?.id || 'default-agency';
    const now = new Date().toISOString();
    const id = generateId();

    await SingularityChatSessionModel.create({
        id,
        agencyId,
        userId,
        title: 'New Chat',
        mode,
        messages: [],
        createdAt: now,
        updatedAt: now,
    });

    return id;
}

const MAX_MESSAGES_PER_SESSION = 200;

export async function updateSingularitySession(
    sessionId: string,
    messages: ChatMessage[],
    title?: string
) {
    const authSession = await getSessionUser();
    if (!authSession) throw new Error('Unauthorized');

    await connectDB();
    // Verify ownership
    const chatSession = await SingularityChatSessionModel.findOne({ id: sessionId, userId: authSession.userId }).select('id').lean();
    if (!chatSession) throw new Error('Unauthorized: Session does not belong to you');

    const now = new Date().toISOString();

    // Cap to prevent MongoDB 16MB document limit
    // Keep the first message (user context) + the most recent ones
    const cappedMessages = messages.length > MAX_MESSAGES_PER_SESSION
        ? [messages[0], ...messages.slice(-(MAX_MESSAGES_PER_SESSION - 1))]
        : messages;

    const update: any = { messages: cappedMessages, updatedAt: now };
    if (title) update.title = title;

    await SingularityChatSessionModel.updateOne(
        { id: sessionId, userId: authSession.userId },
        { $set: update }
    );
}

export async function updateSingularitySessionMode(sessionId: string, mode: 'chat' | 'agent') {
    const authSession = await getSessionUser();
    if (!authSession) throw new Error('Unauthorized');

    await connectDB();
    // Verify ownership
    const chatSession = await SingularityChatSessionModel.findOne({ id: sessionId, userId: authSession.userId }).select('id').lean();
    if (!chatSession) throw new Error('Unauthorized: Session does not belong to you');

    await SingularityChatSessionModel.updateOne(
        { id: sessionId, userId: authSession.userId },
        { $set: { mode, updatedAt: new Date().toISOString() } }
    );
}

export async function deleteSingularitySession(sessionId: string) {
    const authSession = await getSessionUser();
    if (!authSession) throw new Error('Unauthorized');

    await connectDB();
    // Verify ownership
    const chatSession = await SingularityChatSessionModel.findOne({ id: sessionId, userId: authSession.userId }).select('agencyId').lean();
    if (!chatSession) throw new Error('Unauthorized: Session does not belong to you');

    // Delete session and all associated checkpoints
    await Promise.all([
        SingularityChatSessionModel.deleteOne({ id: sessionId, userId: authSession.userId }),
        SingularityCheckpointModel.deleteMany({ sessionId, ...(chatSession as any)?.agencyId ? { agencyId: (chatSession as any).agencyId } : {} }),
    ]);
}

// ============================================================================
// CHECKPOINT SYSTEM
// ============================================================================

export async function getCheckpointSessionId(checkpointId: string): Promise<string | null> {
    const authSession = await getSessionUser();
    if (!authSession) throw new Error('Unauthorized');

    await connectDB();
    const cp = await resolveOwnedCheckpoint(checkpointId, authSession.userId);
    return cp ? cp.sessionId : null;
}
export async function createCheckpoint(
    sessionId: string,
    messageIndex: number,
    actions: CheckpointAction[],
    label: string
): Promise<string> {
    const authSession = await getSessionUser();
    if (!authSession) throw new Error('Unauthorized');

    await connectDB();
    // Verify session ownership
    const chatSession = await SingularityChatSessionModel.findOne({ id: sessionId, userId: authSession.userId }).select('userId agencyId').lean();
    if (!chatSession) throw new Error('Unauthorized: Session does not belong to you');

    const agency = await getCurrentAgency();
    const agencyId = (chatSession as any)?.agencyId || agency?.id || 'default-agency';
    const id = generateId();

    await SingularityCheckpointModel.create({
        id,
        sessionId,
        agencyId,
        messageIndex,
        actions,
        label,
        status: 'active',
        createdAt: new Date().toISOString(),
    });

    return id;
}

export async function getCheckpoints(sessionId: string) {
    const authSession = await getSessionUser();
    if (!authSession) throw new Error('Unauthorized');

    await connectDB();
    // Verify session ownership
    const chatSession = await SingularityChatSessionModel.findOne({ id: sessionId, userId: authSession.userId }).select('agencyId').lean();
    if (!chatSession) throw new Error('Unauthorized: Session does not belong to you');

    const checkpoints = await SingularityCheckpointModel
        .find({ sessionId, status: 'active', ...(chatSession as any)?.agencyId ? { agencyId: (chatSession as any).agencyId } : {} })
        .sort({ createdAt: -1 })
        .lean();

    return checkpoints.map((cp: any) => ({
        id: cp.id,
        sessionId: cp.sessionId,
        messageIndex: cp.messageIndex,
        actions: cp.actions,
        label: cp.label,
        status: cp.status,
        createdAt: cp.createdAt,
    }));
}

// ============================================================================
// CONFLICT DETECTION — Check if entities were modified after agent touched them
// ============================================================================

function getModelForEntity(entityType: string): any {
    switch (entityType) {
        case 'task': return TaskModel;
        case 'project': return ProjectModel;
        case 'client': return ClientModel;
        case 'invoice': return InvoiceModel;
        case 'transaction': return TransactionModel;
        case 'service': return ServiceModel;
        case 'leaveRequest': return LeaveRequestModel;
        default: return null;
    }
}

async function checkEntityConflict(action: CheckpointAction): Promise<ConflictInfo | null> {
    const Model = getModelForEntity(action.entityType);
    if (!Model) return null;
    const actionAgencyId = action.beforeSnapshot?.agencyId;

    if (action.actionType === 'create') {
        // For created entities: check if it was modified since creation
        const createFilter: any = { id: action.entityId };
        if (actionAgencyId) createFilter.agencyId = actionAgencyId;
        const entity = await Model.findOne(createFilter).lean() as any;
        if (!entity) {
            // Entity was already deleted by user — no conflict, but nothing to undo
            return {
                entityType: action.entityType,
                entityId: action.entityId,
                entityName: 'Deleted entity',
                reason: 'Already deleted — no action needed',
            };
        }

        const createdAt = new Date(action.executedAt).getTime();
        const updatedAt = entity.updatedAt ? new Date(entity.updatedAt).getTime() : createdAt;

        // Allow 5-second buffer for concurrent writes during creation
        if (updatedAt - createdAt > 5000) {
            return {
                entityType: action.entityType,
                entityId: action.entityId,
                entityName: entity.name || entity.title || entity.description || action.entityId,
                reason: `Modified after creation`,
            };
        }

        // For tasks: check if comments were added after creation
        if (action.entityType === 'task' && entity.comments?.length > 0) {
            const commentsAfterCreate = entity.comments.filter((c: any) => {
                const commentTime = new Date(c.timestamp).getTime();
                return commentTime > createdAt + 5000;
            });
            if (commentsAfterCreate.length > 0) {
                return {
                    entityType: action.entityType,
                    entityId: action.entityId,
                    entityName: entity.title || action.entityId,
                    reason: `${commentsAfterCreate.length} comment(s) added after creation`,
                };
            }
        }

        // For projects: check if tasks were added after creation
        if (action.entityType === 'project') {
            const projectTaskFilter: any = { projectId: action.entityId };
            const entityAgencyId = entity?.agencyId || actionAgencyId;
            if (entityAgencyId) projectTaskFilter.agencyId = entityAgencyId;
            const childTasks = await TaskModel.find(projectTaskFilter).lean();
            // Filter tasks not created by AI in this checkpoint
            const allCreatedIds = new Set(action.createdEntityIds || []);
            const externalTasks = childTasks.filter((t: any) => !allCreatedIds.has(t.id));
            if (externalTasks.length > 0) {
                return {
                    entityType: action.entityType,
                    entityId: action.entityId,
                    entityName: entity.name || action.entityId,
                    reason: `${externalTasks.length} task(s) were added to this project`,
                };
            }
        }

        return null; // No conflict — safe to rollback
    }

    if (action.actionType === 'update') {
        // For updated entities: check if someone else changed it after the agent did
        const updateFilter: any = { id: action.entityId };
        if (actionAgencyId) updateFilter.agencyId = actionAgencyId;
        const entity = await Model.findOne(updateFilter).lean() as any;
        if (!entity) return null; // Entity deleted — nothing to restore

        const agentUpdateTime = new Date(action.executedAt).getTime();
        const currentUpdateTime = entity.updatedAt ? new Date(entity.updatedAt).getTime() : 0;

        if (currentUpdateTime - agentUpdateTime > 5000) {
            return {
                entityType: action.entityType,
                entityId: action.entityId,
                entityName: entity.name || entity.title || action.entityId,
                reason: 'Modified after AI update',
            };
        }

        return null;
    }

    // For deletes: we're re-creating, so no typical conflict
    return null;
}

async function resolveOwnedCheckpoint(checkpointId: string, userId: string) {
    const checkpoint = await SingularityCheckpointModel
        .findOne({ id: checkpointId })
        .select('id sessionId agencyId messageIndex actions label')
        .lean() as any;
    if (!checkpoint) return null;

    const sessionFilter: any = { id: checkpoint.sessionId, userId };
    if (checkpoint.agencyId) sessionFilter.agencyId = checkpoint.agencyId;
    const ownedSession = await SingularityChatSessionModel.findOne(sessionFilter).select('id').lean();
    if (!ownedSession) return null;

    return checkpoint;
}

async function buildRollbackAnalysis(checkpoint: any): Promise<RollbackAnalysis> {
    const safeActions: CheckpointAction[] = [];
    const conflictedActions: { action: CheckpointAction; conflict: ConflictInfo }[] = [];

    for (const action of checkpoint.actions || []) {
        const conflict = await checkEntityConflict(action);
        if (conflict) {
            if (conflict.reason.includes('Already deleted')) continue;
            conflictedActions.push({ action, conflict });
        } else {
            safeActions.push(action);
        }
    }

    return {
        checkpointId: checkpoint.id,
        label: checkpoint.label,
        totalActions: (checkpoint.actions || []).length,
        safeActions,
        conflictedActions,
    };
}

export async function analyzeRollback(checkpointId: string): Promise<RollbackAnalysis | null> {
    const authSession = await getSessionUser();
    if (!authSession) throw new Error('Unauthorized');

    await connectDB();
    const checkpoint = await resolveOwnedCheckpoint(checkpointId, authSession.userId);
    if (!checkpoint) return null;
    return await buildRollbackAnalysis(checkpoint);
}

// ============================================================================
// ROLLBACK EXECUTION
// ============================================================================

export async function executeRollback(
    checkpointId: string,
    scope: 'safe' | 'all'
): Promise<{ success: boolean; rolledBack: number; skipped: number; errors: string[] }> {
    const authSession = await getSessionUser();
    if (!authSession) throw new Error('Unauthorized');

    await connectDB();
    const checkpoint = await resolveOwnedCheckpoint(checkpointId, authSession.userId);
    if (!checkpoint) return { success: false, rolledBack: 0, skipped: 0, errors: ['Checkpoint not found'] };
    const analysis = await buildRollbackAnalysis(checkpoint);

    const actionsToRollback = scope === 'all'
        ? [...analysis.safeActions, ...analysis.conflictedActions.map(c => c.action)]
        : analysis.safeActions;

    let rolledBack = 0;
    let skipped = 0;
    const errors: string[] = [];

    // Execute rollbacks in reverse order (undo last action first)
    for (const action of [...actionsToRollback].reverse()) {
        try {
            await rollbackAction(action);
            rolledBack++;
        } catch (err: any) {
            errors.push(`Failed to rollback ${action.entityType} ${action.entityId}: ${err.message}`);
            skipped++;
        }
    }

    // Mark checkpoint as rolled back
    await SingularityCheckpointModel.updateOne(
        { id: checkpointId, sessionId: checkpoint.sessionId, ...(checkpoint.agencyId ? { agencyId: checkpoint.agencyId } : {}) },
        { $set: { status: 'rolled_back' } }
    );

    // Also truncate the chat messages back to the checkpoint's messageIndex
    const session = await SingularityChatSessionModel.findOne({
        id: checkpoint.sessionId,
        userId: authSession.userId,
        ...(checkpoint.agencyId ? { agencyId: checkpoint.agencyId } : {}),
    }).lean() as any;
    if (session && session.messages) {
        const truncatedMessages = session.messages.slice(0, checkpoint.messageIndex);
        await SingularityChatSessionModel.updateOne(
            {
                id: checkpoint.sessionId,
                userId: authSession.userId,
                ...(checkpoint.agencyId ? { agencyId: checkpoint.agencyId } : {}),
            },
            { $set: { messages: truncatedMessages, updatedAt: new Date().toISOString() } }
        );
    }

    return { success: errors.length === 0, rolledBack, skipped, errors };
}

async function rollbackAction(action: CheckpointAction) {
    const Model = getModelForEntity(action.entityType);
    if (!Model) throw new Error(`Unknown entity type: ${action.entityType}`);

    // Derive agencyId from beforeSnapshot or existing entity for safety
    const agencyId = action.beforeSnapshot?.agencyId;

    switch (action.actionType) {
        case 'create': {
            // Rollback a create = delete the entity
            // For bulk operations, delete all created entities
            const idsToDelete = action.createdEntityIds?.length
                ? action.createdEntityIds
                : [action.entityId];

            for (const id of idsToDelete) {
                // Include agencyId when available to prevent cross-tenant deletion
                const filter: any = { id };
                if (agencyId) filter.agencyId = agencyId;
                await Model.deleteOne(filter);
            }
            break;
        }

        case 'update': {
            // Rollback an update = restore the beforeSnapshot
            if (!action.beforeSnapshot) {
                throw new Error('No snapshot available for update rollback');
            }

            // Remove MongoDB internal fields from snapshot
            const { _id, __v, ...restoreData } = action.beforeSnapshot;
            const updateFilter: any = { id: action.entityId };
            if (agencyId) updateFilter.agencyId = agencyId;
            await Model.updateOne(
                updateFilter,
                { $set: restoreData }
            );
            break;
        }

        case 'delete': {
            // Rollback a delete = re-create the entity from snapshot
            if (!action.beforeSnapshot) {
                throw new Error('No snapshot available for delete rollback');
            }
            if (
                action.entityType === 'project'
                && action.beforeSnapshot?.project
            ) {
                const projectDoc = action.beforeSnapshot.project;
                const tasks = Array.isArray(action.beforeSnapshot.tasks) ? action.beforeSnapshot.tasks : [];
                const invoices = Array.isArray(action.beforeSnapshot.invoices) ? action.beforeSnapshot.invoices : [];
                const transactions = Array.isArray(action.beforeSnapshot.transactions) ? action.beforeSnapshot.transactions : [];

                await ProjectModel.updateOne(
                    { id: projectDoc.id, ...(projectDoc.agencyId ? { agencyId: projectDoc.agencyId } : {}) },
                    { $set: projectDoc },
                    { upsert: true }
                );
                if (tasks.length > 0) {
                    await Promise.all(tasks.map((task: any) =>
                        TaskModel.updateOne({ id: task.id }, { $set: task }, { upsert: true })
                    ));
                }
                if (invoices.length > 0) {
                    await Promise.all(invoices.map((invoice: any) =>
                        InvoiceModel.updateOne({ id: invoice.id }, { $set: invoice }, { upsert: true })
                    ));
                }
                if (transactions.length > 0) {
                    await Promise.all(transactions.map((transaction: any) =>
                        TransactionModel.updateOne({ id: transaction.id }, { $set: transaction }, { upsert: true })
                    ));
                }
                break;
            }

            const { _id, __v, ...createData } = action.beforeSnapshot;
            await Model.create(createData);
            break;
        }

        default:
            throw new Error(`Unknown action type: ${action.actionType}`);
    }
}

