                const txn = await TransactionModel.findOne({ id: args.transactionId, agencyId: agency?.id }).lean();
                if (!txn) return { success: false, data: null, summary: 'Transaction not found' };

                await TransactionModel.deleteOne({ id: args.transactionId, agencyId: agency?.id });
                // C3 fix: Revalidate cache
                const { revalidatePath: revalFinance } = await import('next/cache');
                revalFinance('/dashboard/finance');
                return {
                    success: true,
                    data: { transactionId: args.transactionId },
                    summary: `Transaction deleted: ${fmtCur((txn as any).amount)} (${(txn as any).category})`,
                    rollbackData: txnSnapshot ? [{
                        toolName: 'delete_transaction', actionType: 'delete', entityType: 'transaction',
                        entityId: args.transactionId, beforeSnapshot: txnSnapshot, executedAt: new Date().toISOString(),
                    }] : undefined,
                };
            }

            case "delete_service": {
                const aiPerms = await getAIPermissions();
                if (!aiPerms.canDelete) return { success: false, data: null, summary: '? AI Delete permission is disabled. Enable it in Settings ? AI Settings.' };

                const svcDelSnapshot = await snapshotEntity('service', args.serviceId);
                try {
                    await deleteService(args.serviceId);
                } catch (err: any) {
                    return { success: false, data: null, summary: err.message };
                }
                return {
                    success: true,
                    data: { serviceId: args.serviceId },
                    summary: `Service deleted`,
                    rollbackData: svcDelSnapshot ? [{
                        toolName: 'delete_service', actionType: 'delete', entityType: 'service',
                        entityId: args.serviceId, beforeSnapshot: svcDelSnapshot, executedAt: new Date().toISOString(),
                    }] : undefined,
                };
            }

            default:
                return {
                    success: false,
                    data: null,
                    summary: `Unknown tool: ${name}`,
                };
        }
    } catch (error: any) {
        console.error(`[Tool Executor] ${name} failed:`, error.message);
        return {
            success: false,
            data: null,
            summary: `Error: ${error.message || "Tool execution failed"}`,
        };
    }
}

import { put, del, list } from '@vercel/blob';
import { uploadToAzure, deleteFromAzure, isAzureBlobUrl } from './azure-storage';

/**
 * Hybrid Storage Module
 * 
 * Primary: Vercel Blob (free 1GB across all agencies)
 * Overflow: Azure Blob Storage (when Vercel Blob exceeds 950MB)
 * 
 * Both providers return self-contained URLs:
 * - Vercel Blob: https://xxx.public.blob.vercel-storage.com/filename
 * - Azure Blob:  https://account.blob.core.windows.net/container/filename?sas=...
 */

const VERCEL_BLOB_THRESHOLD = 950 * 1024 * 1024; // 950MB — switch to Azure after this

// In-memory cache for Vercel Blob usage to avoid frequent list() calls
let _cachedVercelUsage: { bytes: number; fetchedAt: number } | null = null;
const CACHE_TTL = 5 * 60 * 1000; // 5 minutes

/**
 * Get the Vercel Blob token. Returns undefined if not configured.
 */
function getVercelBlobToken(): string | undefined {
  return process.env.BLOB_READ_WRITE_TOKEN;
}

/**
 * Check if BLOB_READ_WRITE_TOKEN is configured (Vercel Blob available)
 */
function isVercelBlobConfigured(): boolean {
  return !!getVercelBlobToken();
}

/**
 * Check if a URL is a Vercel Blob URL
 */
export function isVercelBlobUrl(url: string): boolean {
  return url.includes('.public.blob.vercel-storage.com') || url.includes('.blob.vercel-storage.com');
}

/**
 * Get current Vercel Blob usage in bytes.
 * Uses list() API with cursor pagination to sum up all blob sizes.
 * Results are cached for 5 minutes to avoid excessive API calls.
 */
async function getVercelBlobUsage(): Promise<number> {
  // Return cache if fresh
  if (_cachedVercelUsage && (Date.now() - _cachedVercelUsage.fetchedAt) < CACHE_TTL) {
    return _cachedVercelUsage.bytes;
  }

  const token = getVercelBlobToken();
  if (!token) return Infinity;

  try {
    let totalBytes = 0;
    let cursor: string | undefined;
    let hasMore = true;

    while (hasMore) {
      const result = await list({ cursor, limit: 1000, token });
      for (const blob of result.blobs) {
        totalBytes += blob.size;
      }
      cursor = result.cursor;
      hasMore = result.hasMore;
    }

    _cachedVercelUsage = { bytes: totalBytes, fetchedAt: Date.now() };
    return totalBytes;
  } catch (error) {
    console.error('[Storage] Failed to get Vercel Blob usage:', error);
    // If we can't check usage, fall back to Azure to be safe
    return Infinity;
  }
}

/**
 * Invalidate the usage cache (call after upload/delete)
 */
function invalidateUsageCache() {
  _cachedVercelUsage = null;
}

/**
 * Upload a file — routes to Vercel Blob or Azure based on current usage.
 * 
 * @param buffer - File buffer
 * @param fileName - Sanitized filename (already timestamped by caller)
 * @param contentType - MIME type
 * @returns Public URL of the uploaded file
 */
export async function uploadFile(
  buffer: Buffer,
  fileName: string,
  contentType?: string
): Promise<string> {
  const token = getVercelBlobToken();

  // Check if Vercel Blob is available and under threshold
  if (token) {
    try {
      const currentUsage = await getVercelBlobUsage();
      console.log(`[Storage] Vercel Blob configured. Usage: ${(currentUsage / (1024 * 1024)).toFixed(1)}MB / ${(VERCEL_BLOB_THRESHOLD / (1024 * 1024)).toFixed(0)}MB`);

      if (currentUsage + buffer.length <= VERCEL_BLOB_THRESHOLD) {
        // Upload to Vercel Blob
        const blob = await put(fileName, buffer, {
          access: 'public',
          contentType: contentType || 'application/octet-stream',
          token,
        });

        // Update cache optimistically
        if (_cachedVercelUsage) {
          _cachedVercelUsage.bytes += buffer.length;
        }

        console.log(`[Storage] ? Uploaded to Vercel Blob: ${blob.url}`);
        return blob.url;
      } else {
        console.log(`[Storage] Vercel Blob at ${(currentUsage / (1024 * 1024)).toFixed(1)}MB — over threshold, routing to Azure`);
      }
    } catch (error: any) {
      console.error(`[Storage] ? Vercel Blob failed (${error?.message || error}), falling back to Azure`);
    }
  } else {
    console.log('[Storage] BLOB_READ_WRITE_TOKEN not set — using Azure');
  }

  // Fallback: Upload to Azure
  const url = await uploadToAzure(buffer, fileName, contentType);
  console.log('[Storage] Uploaded to Azure Blob Storage');
  return url;
}

/**
 * Delete a file from whichever provider hosts it.
 * Detects provider from the URL.
 */
export async function deleteFile(url: string): Promise<void> {
  const token = getVercelBlobToken();
  try {
    if (isVercelBlobUrl(url)) {
      await del(url, { token });
      invalidateUsageCache();
      console.log('[Storage] Deleted from Vercel Blob');
    } else if (isAzureBlobUrl(url)) {
      await deleteFromAzure(url);
      console.log('[Storage] Deleted from Azure');
    } else {
      console.warn('[Storage] Unknown storage provider for URL:', url);
    }
  } catch (error) {
    console.error('[Storage] Failed to delete file:', error);
    // Don't throw — DB operations should still succeed
  }
}

/**
 * Get storage stats for monitoring (optional, for super-admin dashboard)
 */
export async function getStorageStats() {
  const vercelUsage = isVercelBlobConfigured() ? await getVercelBlobUsage() : 0;
  return {
    vercelBlob: {
      usedBytes: vercelUsage,
      usedMB: Math.round(vercelUsage / (1024 * 1024) * 100) / 100,
      thresholdMB: VERCEL_BLOB_THRESHOLD / (1024 * 1024),
      isOverThreshold: vercelUsage >= VERCEL_BLOB_THRESHOLD,
      configured: isVercelBlobConfigured(),
    },
    activeProvider: vercelUsage < VERCEL_BLOB_THRESHOLD && isVercelBlobConfigured()
      ? 'vercel-blob' : 'azure',
  };
}

import { connectDB, UserModel, ClientModel, SuperAdminModel, decryptApiKey } from "./mongodb";
import { User, AIConfig } from "./types";
import { randomUUID } from "crypto";
import { getCurrentAgency } from "./agency-context";

export function generateId(): string {
    return randomUUID();
}

/**
 * Resolves a User or Client by ID or Username.
 * If found as a Client, adapts it to the User type.
 * @param agencyId - Optional agency scope. When provided, User/Client queries are
 *                   restricted to that agency to prevent cross-tenant data access.
 */
export async function resolveUserOrClient(identifier: string, agencyId?: string): Promise<User | undefined> {
    await connectDB();

    // Build agency-scoped filter for multi-tenancy safety
    const agencyScope = agencyId ? { agencyId } : {};

    // Parallel lookup for maximum performance
    const [user, client, superAdmin] = await Promise.all([
        UserModel.findOne({ $or: [{ id: identifier }, { username: identifier }], ...agencyScope }).select('-password').lean(),
        ClientModel.findOne({ $or: [{ id: identifier }, { username: identifier }], ...agencyScope }).select('-password').lean(),
        SuperAdminModel.findOne({ id: identifier }).select('-password').lean() // SuperAdmin is global, not tenant-scoped
    ]);

    // 1. Check User
    if (user) {
        return {
            ...user,
            id: user.id || user._id.toString(), // Ensure ID is string
            agencyId: user.agencyId || 'default-agency' // Fallback
        } as any as User;
    }

    // 2. Check Super Admin
    if (superAdmin) {
        return {
            id: superAdmin.id,
            name: superAdmin.name,
            email: superAdmin.email,
            role: 'superadmin' as any, // Cast to any to bypass strict User role enum if needed
            avatar: superAdmin.avatar,
            createdAt: superAdmin.createdAt,
            agencyId: 'super-admin'
        } as any as User;
    }

    // 3. Check Client
    if (client) {
        return {
            id: client.id,
            name: client.name,
            email: client.email,
            role: 'client' as any,
            jobTitle: client.companyName,
            avatar: client.logo || `https://api.dicebear.com/7.x/initials/svg?seed=${client.companyName}`,
            lastActiveAt: client.lastActiveAt,
            username: client.username || client.id,
